-- Poems batch 319
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('9974da08-4d1a-4856-b803-5c66eb309005','蘇學十題 泮池','朱長文','宋','宋诗','song-poetry','','[]','怪石鋪幽麓，芳塘倚茂林。',48,'全唐诗/poet.song.47000.json','["怪石鋪幽麓，芳塘倚茂林。", "冷光開玉鏡，清影滌人心。", "芹藻無傷性，龜魚各就深。", "泉源應不涸，何必傅巖霖。"]'),
('485c327c-1ce1-42ff-811d-6cfd6419efa8','蘇學十題 玲瓏石','朱長文','宋','宋诗','song-poetry','','[]','巨浪洗蒼玉，一峰飛我前。',48,'全唐诗/poet.song.47000.json','["巨浪洗蒼玉，一峰飛我前。", "鑿開混沌竅，窺見滄浪天。", "洞敞延華月，巖虛生翠煙。", "幽軒相對久，古意日翛然。"]'),
('2f208cba-4d2b-4471-ad52-5e27984c2a6d','蘇學十題 百幹黄楊','朱長文','宋','宋诗','song-poetry','','[]','寶幹多材美，孤根一氣同。',48,'全唐诗/poet.song.47000.json','["寶幹多材美，孤根一氣同。", "春餘花淡薄，雪裏葉青葱。", "蕃衍非人力，堅剛稟化工。", "寸枝裁玉軫，可助舜南風。"]'),
('90382390-ac48-4c00-8eb7-296f87cd7b5b','蘇學十題 公堂槐','朱長文','宋','宋诗','song-poetry','','[]','五紀栽培後，三春長育中。',48,'全唐诗/poet.song.47000.json','["五紀栽培後，三春長育中。", "靈根蟠故國，密葉蔭儒宮。", "患與般斤遠，歌宜魯藻同。", "先儒垂意遠，期此出三公。"]'),
('74bda4b4-4570-4bf7-87ca-9007a84c7d84','蘇學十題 辛夷','朱長文','宋','宋诗','song-poetry','','[]','楚客曾流詠，吳都獨擅奇。',48,'全唐诗/poet.song.47000.json','["楚客曾流詠，吳都獨擅奇。", "風霆存老幹，桃李避芳時。", "名入文房夢，功資妙手醫。", "紫微顔色好，先占鳳凰池。"]'),
('be686ba5-d6af-4d95-a776-71ddde561f2d','蘇學十題 石楠','朱長文','宋','宋诗','song-poetry','','[]','昔年曾賞玩，移自碧山遥。',48,'全唐诗/poet.song.47000.json','["昔年曾賞玩，移自碧山遥。", "古幹磨文石，寒枝熨翠綃。", "雖殊楩梓用，終免雪霜凋。", "來者宜珍護，毋令困採樵。"]'),
('8a6355c7-7de6-4d12-a2ff-8e672f599c28','蘇學十題 多幹柏','朱長文','宋','宋诗','song-poetry','','[]','古柏列重門，連枝若弟昆。',48,'全唐诗/poet.song.47000.json','["古柏列重門，連枝若弟昆。", "參天分直幹，得地共靈根。", "月照龍蛇影，風摧鐵石痕。", "鸞凰期可宿，香葉向春繁。"]'),
('668ae635-6b69-4b1a-9bf9-91b3e38615ae','蘇學十題 並秀檜','朱長文','宋','宋诗','song-poetry','','[]','槃根幾百齡，合幹倚冥冥。',48,'全唐诗/poet.song.47000.json','["槃根幾百齡，合幹倚冥冥。", "偃蹇雙虬聳，聯翩兩蓋青。", "紫鱗霜外躍，紺葉雨餘馨。", "左紐憑仙宇，何如拱泮亭。"]'),
('c459bdf6-9b18-43ef-9607-98061b377683','蘇學十題 新杉','朱長文','宋','宋诗','song-poetry','','[]','弱植還生意，凌冬見後凋。',48,'全唐诗/poet.song.47000.json','["弱植還生意，凌冬見後凋。", "尚低霑雨露，更長拂雲霄。", "庭月摇疏影，檐風舞細條。", "他年逢匠石，寶構壯天朝。"]'),
('351f6615-7f3f-4899-8743-67ede21a17f0','蘇學十題 泮山','朱長文','宋','宋诗','song-poetry','','[]','山形拱泮宮，林壑意無窮。',48,'全唐诗/poet.song.47000.json','["山形拱泮宮，林壑意無窮。", "自得千巖秀，無虧九仞功。", "光延東嶺月，清轉碧潭風。", "官冷真相稱，婆娑一釣翁。"]'),
('571ae6dc-f1a7-4058-a4e7-b3cf96f65584','送曹縣丞入京','朱長文','宋','宋诗','song-poetry','','[]','忠義家聲久，夫君更美才。',48,'全唐诗/poet.song.47000.json','["忠義家聲久，夫君更美才。", "吏民愁既去，交友約重來。", "別岫浮雲遠，征帆曉月開。", "棣華同郡府，眷戀共銜杯。"]'),
('f779d52b-3da8-488f-8a62-399db57adb4b','次韵司封使君和推官早梅山茶二首  其一','朱長文','宋','宋诗','song-poetry','','[]','嫩跗黏絳蠟，輕朵插珠鈿。',48,'全唐诗/poet.song.47000.json','["嫩跗黏絳蠟，輕朵插珠鈿。", "雪裏心偏苦，花中達最先。", "玉階香馥郁，煙野蕊聯娟。", "託植雖然別，黄金子並圓。"]'),
('2d2b66b7-ae88-4f1a-acd0-80485b3961ee','次韵司封使君和推官早梅山茶二首  其二','朱長文','宋','宋诗','song-poetry','','[]','柏葉元同翠，桃顔未比紅。',48,'全唐诗/poet.song.47000.json','["柏葉元同翠，桃顔未比紅。", "留芳占春月，弄蕊耐秋風。", "自稱階庭玩，休煩帟幕籠。", "佳篇補韋白，流品重吳中。"]'),
('c0c6571b-587c-438b-8507-ea68518ce06e','梅評事携詩過訪欲求屬和因次其韵','朱長文','宋','宋诗','song-poetry','','[]','築室尋幽處，唯求水竹鄰。',48,'全唐诗/poet.song.47000.json','["築室尋幽處，唯求水竹鄰。", "心安何必貴，累少莫如貧。", "石裏求奇古，花中悟道新。", "不須多轍迹，猿鶴自爲賓。"]'),
('dcc25d5b-4dda-4d40-9314-3adc2e380d6b','次韵司封使君和練推官再詠山茶','朱長文','宋','宋诗','song-poetry','','[]','珍木何年種，繁英滿舊枝。',48,'全唐诗/poet.song.47000.json','["珍木何年種，繁英滿舊枝。", "開從殘雪裏，盛過牡丹時。", "對日心全展，凌風幹不欹。", "藥階如賦詠，欠此尚相思。"]'),
('33415bec-a022-45d5-b89e-fff61c016517','次韵練定公權垂訪樂圃之什','朱長文','宋','宋诗','song-poetry','','[]','隠圃甚蕭條，驅車豈憚勞。',48,'全唐诗/poet.song.47000.json','["隠圃甚蕭條，驅車豈憚勞。", "境從前代勝，岡對遠山高。", "林曉猿抽臂，池秋鶴浴毛。", "興來頻就醉，奇句僕離騷。"]'),
('5d7e6875-d600-4fcb-9dad-f634551e6e77','賀林承務還吳門','朱長文','宋','宋诗','song-poetry','','[]','朱顔充賦早，蒼鬢拜恩歸。',48,'全唐诗/poet.song.47000.json','["朱顔充賦早，蒼鬢拜恩歸。", "煙水鶺鴒聚，霜穹鴻雁飛。", "傳經金恥富，下筆玉藏輝。", "貴仕毋嫌晚，天門受賜衣。"]'),
('d8f5f487-871a-4c1f-8c0a-b6e3dcb8eba5','寄和晏守','朱長文','宋','宋诗','song-poetry','','[]','二年懷郡印，八度到柴扉。',48,'全唐诗/poet.song.47000.json','["二年懷郡印，八度到柴扉。", "曾未陪珠履，頻煩友布衣。", "水邊孤鶴睡，天際片雲歸。", "拜德知何日，煙霞戀翠微。"]'),
('b956f875-2536-490c-8210-b14440c05efe','和公權秋暑奉懷','朱長文','宋','宋诗','song-poetry','','[]','誰謂雲中句，能移江上峰。',48,'全唐诗/poet.song.47000.json','["誰謂雲中句，能移江上峰。", "清飆隨玉楮，爽氣襲塵容。", "劇暑嬰多病，嘉招恨未從。", "眷言相與意，深荷故情濃。"]'),
('eacd194a-0a80-435f-88d6-bae54cd1ffa5','再和','朱長文','宋','宋诗','song-poetry','','[]','鄉校叨微祿，家林傍舊峰。',48,'全唐诗/poet.song.47000.json','["鄉校叨微祿，家林傍舊峰。", "散人那適用，逋客拙爲容。", "良友幸不棄，華軒時肯從。", "早秋須命駕，荷葉露華濃。"]'),
('cea06fb0-9e5c-4f6b-b123-e868be1fcf44','光祿生日','朱長文','宋','宋诗','song-poetry','','[]','舜庭新遣牧，漢寺舊名卿。',48,'全唐诗/poet.song.47000.json','["舜庭新遣牧，漢寺舊名卿。", "致主丹心在，憂民素髮生。", "鷲峰仙桂老，猿澗古松清。", "金簡傳真理，期頤體更輕。"]'),
('03e017e7-5beb-4645-a5d5-2ef79a1c782f','蒙使君召預池光之會','朱長文','宋','宋诗','song-poetry','','[]','韋公池閣尚依然，賓主于今不乏賢。',64,'全唐诗/poet.song.47000.json','["韋公池閣尚依然，賓主于今不乏賢。", "郡內欣逢兩耆俊，樽前喜會四同年。", "清談自可成珠玉，真賞何須聽管絃。", "宴罷旌旗摇暮靄，蔡經寂寞別羣仙。"]'),
('5dda71f6-6619-4b4a-9a04-008b6ae3e11e','遊虎丘借前韵','朱長文','宋','宋诗','song-poetry','','[]','一丘雖小勢巉然，自古登臨歷幾賢。',64,'全唐诗/poet.song.47000.json','["一丘雖小勢巉然，自古登臨歷幾賢。", "門惹白雲常盡日，地藏靈劍不知年。", "清歡相與隨雙旆，幽趣誰能解七絃。", "每月來遊存故事，郡中依舊有詩仙。"]'),
('d4ddb267-76a7-496b-97f3-cdbdd2777271','次韵蒲左丞宗孟遊虎丘二首  其一','朱長文','宋','宋诗','song-poetry','','[]','命相將乘傅說舟，愛山尋遍樂天遊。',64,'全唐诗/poet.song.47000.json','["命相將乘傅說舟，愛山尋遍樂天遊。", "先聲汶北安千里，選勝吳西賁一丘。", "靜見隴雲生峭壁，寒知海氣入危樓。", "鏘金佳句留蕭寺，剡紙朝來貴此州。"]'),
('eeb40b76-710f-41ed-8605-edc1201d3735','次韵蒲左丞宗孟遊虎丘二首  其二','朱長文','宋','宋诗','song-poetry','','[]','蓬島奇峰水四環，何年涌出向人間。',64,'全唐诗/poet.song.47000.json','["蓬島奇峰水四環，何年涌出向人間。", "清池不測通滄海，寶玉長存潤碧山。", "曾致神仙留歡詠，可令軒冕樂蕭閒。", "謝公方爲蒼生起，戀戀煙蘿日暮還。"]'),
('5d922cc4-4d5d-41ce-80cf-15d46b3b15bf','次韵朱牧樂圃宴有感','朱長文','宋','宋诗','song-poetry','','[]','竊祿都無簿領迷，得錢邀客手頻携。',64,'全唐诗/poet.song.47000.json','["竊祿都無簿領迷，得錢邀客手頻携。", "春來佳景迴三徑，雪後晴波滿一溪。", "歲月易凋青鬢色，塵埃難上白雲梯。", "煩君枉駕慚荒索，空種梧桐待鳳棲。"]'),
('9857ee93-54eb-45ea-b141-1c739558f3e8','次韵彥舒席上有作','朱長文','宋','宋诗','song-poetry','','[]','蒼煙寒水滿方塘，插架排籤典籍場。',64,'全唐诗/poet.song.47000.json','["蒼煙寒水滿方塘，插架排籤典籍場。", "喜對七賢閑把手，希逢四皓醉飛觴。", "林深迥出千齡幹，詩就俄成萬丈光。", "逸興欲尋丁氏宅，雲間老鶴共昂昂。"]'),
('7ce721d1-6158-4149-9a4d-f0a2b5cfaa33','奉謝司封使君晏公臨顧園居  其一','朱長文','宋','宋诗','song-poetry','','[]','閑卧林泉與世疏，使君三度枉旌旟。',64,'全唐诗/poet.song.47000.json','["閑卧林泉與世疏，使君三度枉旌旟。", "未陪徐孺升賓榻，敢屈文侯式敝閭。", "暫擲魚竿絲半卷，旋開松徑草新鋤。", "愧無美酒拈巾漉，難得金波款緒餘。"]'),
('293e53d0-fda5-4fcb-b492-4bd7b26e2adf','奉謝司封使君晏公臨顧園居  其二','朱長文','宋','宋诗','song-poetry','','[]','未入柴扉即下車，茅齋揮麈緩論書。',64,'全唐诗/poet.song.47000.json','["未入柴扉即下車，茅齋揮麈緩論書。", "不知銅虎威權重，豈責荷衣禮貌疏。", "此日狂歌希魯望，昔年能賦擬相如。", "篋中殘藁如傳後，雖枉朱轓亦不虛。"]'),
('037dcd88-9052-4d5c-9844-10ca275d16ff','奉謝司封使君晏公臨顧園居  其三','朱長文','宋','宋诗','song-poetry','','[]','甘盤德業滿天區，博學承家行有餘。',64,'全唐诗/poet.song.47000.json','["甘盤德業滿天區，博學承家行有餘。", "鳳翥頻觀先帝詔，牙籤新補相君書。", "晨羊不飲康衢靜，夜犬無聲獄犴虛。", "風績已應推第一，鼇峰深處列仙居。"]'),
('a42aa6ca-a0c2-4889-b262-1febb64c9d96','次韵虎丘祖印大師秋日懷寄','朱長文','宋','宋诗','song-poetry','','[]','不愛紛華愛寂寥，松風竹月共蕭蕭。',64,'全唐诗/poet.song.47000.json','["不愛紛華愛寂寥，松風竹月共蕭蕭。", "因隨野鶴過三徑，每對江鷗洗一瓢。", "無復塵埃沾短褐，尚思煙水泛歸橈。", "道人肯與羲之友，飛錫重來莫待招。"]'),
('6df7bfad-bd8d-4d0c-abcb-3482f26fac62','重九與子通遊虎丘謁祖印大師三首  其一','朱長文','宋','宋诗','song-poetry','','[]','絕境良辰少兩全，搘筇莫倦到山巔。',64,'全唐诗/poet.song.47000.json','["絕境良辰少兩全，搘筇莫倦到山巔。", "清談已可忘樽俎，真樂何勞聽管絃。", "才子就題黄絹語，高僧多諷碧雲篇。", "孤舟欲去更回首，天半樓臺生晚煙。"]'),
('faa9c05e-26b1-4794-97b7-615ad9342d47','重九與子通遊虎丘謁祖印大師三首  其二','朱長文','宋','宋诗','song-poetry','','[]','秋山寥曠景無涯，執手凭欄到日斜。',64,'全唐诗/poet.song.47000.json','["秋山寥曠景無涯，執手凭欄到日斜。", "地竦一丘容澗谷，天低四面納雲霞。", "凌風劇飲從吹帽，多病忘情懶插花。", "深羨二難兄弟好，共將巖壑占爲家。"]'),
('f3b12c5d-2015-45e1-8316-1c0cb54ed333','重九與子通遊虎丘謁祖印大師三首  其三','朱長文','宋','宋诗','song-poetry','','[]','浮世誰如金石堅，吟鬚俄頃見皤然。',64,'全唐诗/poet.song.47000.json','["浮世誰如金石堅，吟鬚俄頃見皤然。", "登山未免懷千古，泛菊相期保百年。", "方外逸民猶有傳，人間高爵豈如仙。", "良辰盛宴多遺迹，何似江南五柳賢。"]'),
('f14ba587-0eb3-42d6-ac85-568721d99b38','彥和善談性理子文繼成偈句見要屬和謹次韵','朱長文','宋','宋诗','song-poetry','','[]','萬法都明一瞬中，可憐情膜久相蒙。',64,'全唐诗/poet.song.47000.json','["萬法都明一瞬中，可憐情膜久相蒙。", "浮雲映月元非暗，病眼生花本是空。", "斷想求真猶未悟，將心覓佛轉相攻。", "誰能吸盡曹溪水，莫負當年祖道東。"]'),
('522e7244-23fc-408d-9a92-7468e71c6461','彥和與子文相期卜鄰子文作詩以遺謹次韵','朱長文','宋','宋诗','song-poetry','','[]','仙才宜在道家山，却學幽人欲閉關。',64,'全唐诗/poet.song.47000.json','["仙才宜在道家山，却學幽人欲閉關。", "清燕曾陪明主問，羣言已助相君刪。", "談圍莫敵書盈腹，詩社相過酒滿顔。", "聞道卜鄰同喜慰，亦開荒徑待餘閑。"]'),
('a77537ef-334a-45a8-8eea-13924c38395e','次韵子文抱病幽居之作二首  其一','朱長文','宋','宋诗','song-poetry','','[]','幾年彩筆擅辭場，鬢髮相饒色更蒼。',64,'全唐诗/poet.song.47000.json','["幾年彩筆擅辭場，鬢髮相饒色更蒼。", "千里舊聞稱驥騄，九霄安得接鸞凰。", "醉凭浄几拋烏帽，閑捲新詩置錦囊。", "治世莫將公幹比，松陵風物勝清漳。"]'),
('e5dcd680-486a-4391-9530-6a1a063b565a','次韵子文抱病幽居之作二首  其二','朱長文','宋','宋诗','song-poetry','','[]','好閑不復愛輕肥，病起神清與道宜。',64,'全唐诗/poet.song.47000.json','["好閑不復愛輕肥，病起神清與道宜。", "藥竈夜寒薪焰歇，書窗晝寂竹陰移。", "坦懷莫學途窮哭，行己應無屋漏欺。", "里巷遊從須勉强，相逢猶記是童兒。"]'),
('fc24aa47-f5bd-4c9e-97d0-fa843587bd49','佳雪應時呈司封使君三首  其一','朱長文','宋','宋诗','song-poetry','','[]','蘇臺風雨久如期，太守精誠不待祈。',64,'全唐诗/poet.song.47000.json','["蘇臺風雨久如期，太守精誠不待祈。", "萬廩更爲來歲計，六花故就臘晨飛。", "靜裝松桂仙枝老，深壅芝蘭土脈肥。", "衡泌棲遲牆仞遠，爲公何日賦緇衣。"]'),
('922c03d1-6ed6-43bb-a371-f49bc8f06567','佳雪應時呈司封使君三首  其二','朱長文','宋','宋诗','song-poetry','','[]','炫晃天花著物新，壺中萬景浄無塵。',64,'全唐诗/poet.song.47000.json','["炫晃天花著物新，壺中萬景浄無塵。", "光輝只欲饒寒士，清潔尤宜比古人。", "韋白吟時飄入硯，鄒枚燕處舞迴茵。", "明年霄漢橫飛去，應踏繁霙拜玉宸。"]'),
('de134790-6a49-48a3-98fc-ba5847fcf824','佳雪應時呈司封使君三首  其三','朱長文','宋','宋诗','song-poetry','','[]','千里江山入郡樓，凭欄乍喜密雲浮。',64,'全唐诗/poet.song.47000.json','["千里江山入郡樓，凭欄乍喜密雲浮。", "冷光交映天峰色，餘潤遥隨笠澤流。", "民疊袴襦看不厭，客叢簪履賞應留。", "野人乘興狂吟外，引鶴披蓑上釣舟。"]'),
('a7e8cb43-46f6-4370-8d09-4ea5653d653a','次韵司封使君新歲喜雪','朱長文','宋','宋诗','song-poetry','','[]','玉燭均調應改元，賢侯喜雪望堯天。',64,'全唐诗/poet.song.47000.json','["玉燭均調應改元，賢侯喜雪望堯天。", "暗聲撒竹高齋夜，瑞彩連雲畫戟前。", "千里湖山成洞府，萬家觴詠展賓筵。", "應憐陋巷袁安卧，擁褐孤吟又過年。"]'),
('f5901adc-8047-43a3-8fe5-23bcffff8d1a','次韵司封使君立春紀事','朱長文','宋','宋诗','song-poetry','','[]','碧瓦猶藏臘雪寒，東杓初向斗旁觀。',64,'全唐诗/poet.song.47000.json','["碧瓦猶藏臘雪寒，東杓初向斗旁觀。", "雪垂華旦天京遠，雉舞條風野老歡。", "官柳嫩黄迎皂蓋，園蔬新綠委金盤。", "詩才例作姑蘇守，一曲陽春喜歲端。"]'),
('b1a7a7a4-410f-42a4-bc46-9cb99b1579b2','次梅評事韵','朱長文','宋','宋诗','song-poetry','','[]','滿目紅塵汩沒深，誰能世事總無心。',64,'全唐诗/poet.song.47000.json','["滿目紅塵汩沒深，誰能世事總無心。", "買松野老栽成徑，覓竹山僧種滿林。", "薄酒時斟資道氣，好詩頻諷滌煩襟。", "鳳雛光顯門庭喜，應笑陶潛責子吟。"]'),
('a6c34d46-78c4-4a7c-8902-e16da36096ca','梅公書齋挂簑笠釣綸船楫四物形於詩句余爲和之','朱長文','宋','宋诗','song-poetry','','[]','快楫輕綸笠與衣，閑將四物挂柴扉。',64,'全唐诗/poet.song.47000.json','["快楫輕綸笠與衣，閑將四物挂柴扉。", "江頭夜雪好披去，湖上春光宜棹歸。", "靜處無憂嫌印綬，貧中有味勝輕肥。", "興來願借君毋吝，渺渺煙波一葉飛。"]'),
('cdab9cc2-f7bd-4497-a548-10c15d98a9be','次韵公權子通唱酬詩四首 春晚遣懷','朱長文','宋','宋诗','song-poetry','','[]','春華急似曉天星，誰得年年鬢髮青。',64,'全唐诗/poet.song.47000.json','["春華急似曉天星，誰得年年鬢髮青。", "露濯淺深枝上錦，風吹離合水中萍。", "吟餘金谷香隨步，書罷蘭亭酒欲醒。", "擬把冽泉同一酌，爲君林下洗寒瓶。"]'),
('3ea9cafe-d194-420f-a60a-a9fb7c149cc5','次韵公權子通唱酬詩四首 閶門懷古','朱長文','宋','宋诗','song-poetry','','[]','九曲堙淪茂苑荒，吳人誰復怨吳王。',64,'全唐诗/poet.song.47000.json','["九曲堙淪茂苑荒，吳人誰復怨吳王。", "莫言故國千秋遠，知是仙家幾日長。", "湖上只誇浮海相，里中休笑傚顰娘。", "舊時芳徑今猶在，但屬漁樵自採香。"]'),
('afbc4767-5637-4acb-9760-19a0886934f1','次韵公權子通唱酬詩四首 春日旅懷','朱長文','宋','宋诗','song-poetry','','[]','身在塵勞未免憂，傷春佇立碧江頭。',64,'全唐诗/poet.song.47000.json','["身在塵勞未免憂，傷春佇立碧江頭。", "回腸只殢千鍾飲，方寸那容萬斛愁。", "懶着錦袍凌巨浪，好乘黄犢傍高丘。", "池塘得句頻相示，直把珠璣爲暗投。"]'),
('57f79d6c-0d9b-4b31-8394-d06e3efb4485','次韵公權子通唱酬詩四首 牡丹','朱長文','宋','宋诗','song-poetry','','[]','奇姿須頼接花工，未必妖華限洛中。',64,'全唐诗/poet.song.47000.json','["奇姿須頼接花工，未必妖華限洛中。", "應是春皇偏與色，却教仙女愧乘風。", "朱欄共約他年賞，翠幄休嗟數日空。", "誰就東吳爲品第，清晨子細閱芳叢。"]'),
('31a77314-327c-47e7-b5e1-245bba9f2167','奉和司封使君春日回文之作','朱長文','宋','宋诗','song-poetry','','[]','佳景更同民共樂，俊髦皆集盛飛觴。',64,'全唐诗/poet.song.47000.json','["佳景更同民共樂，俊髦皆集盛飛觴。", "花隨客醉還成句，柳贈人行欲斷腸。", "斜月上時霞散綺，暖風來處寢凝香。", "華年惜過須心賞，富貴叢身逼鬢霜。"]'),
('2338aeef-fb02-4b40-8424-c4a14a343c65','次韵司封使君和程給事','朱長文','宋','宋诗','song-poetry','','[]','通波隄上幾鞦韆，花接遥山柳接天。',64,'全唐诗/poet.song.47000.json','["通波隄上幾鞦韆，花接遥山柳接天。", "故里松楸霑雨露，神都池苑隔雲煙。", "耕桑交勸紅塵外，羅綺分遊畫舫邊。", "暫歇甘棠隨衆望，不禁野岸更聞鵑。"]'),
('dbad766c-703d-4b85-aa67-b04711ddc832','次韵司封使君和給事寒食城外感事','朱長文','宋','宋诗','song-poetry','','[]','花如步障草如茵，萬景繁華在此旬。',64,'全唐诗/poet.song.47000.json','["花如步障草如茵，萬景繁華在此旬。", "金印誰來誇故里，密章燔了賁慈親。", "莫看白髮興千感，好共朱轓醉一春。", "俱是詩人兼富貴，只疑元白是前身。"]'),
('00ebc4ce-1e71-42ca-9cf4-7d46ea059703','吳門比月不雨司封使君深閔而精祈俄有佳應謹吟成七言二首聊代謁賀  其一','朱長文','宋','宋诗','song-poetry','','[]','賢守憂勞鬢欲霜，通宵霢霂滿吳疆。',64,'全唐诗/poet.song.47000.json','["賢守憂勞鬢欲霜，通宵霢霂滿吳疆。", "五湖水闊魚龍喜，九曲塵清檜栢香。", "更入高鄉多䆉稏，雖當淺處泛艅艎。", "爲霖事業傳家世，潤澤應難限一方。"]'),
('6226741b-2f7e-4d3f-846c-d52cbe9067d0','吳門比月不雨司封使君深閔而精祈俄有佳應謹吟成七言二首聊代謁賀  其二','朱長文','宋','宋诗','song-poetry','','[]','一雨歡心幾萬家，預期舂稻博流霞。',64,'全唐诗/poet.song.47000.json','["一雨歡心幾萬家，預期舂稻博流霞。", "低侵滬瀆田交岸，高傍支山水滿車。", "葉幄謾霑桃李實，隄奩暗長芰荷花。", "豐年闔境渾無事，閑把詩毫放兩衙。"]'),
('cdb2e663-0123-4137-bb8b-f96808d90d08','知府司封見和喜雨詩次韵陳謝','朱長文','宋','宋诗','song-poetry','','[]','天意分明應魯雩，高壇晨拜紫袍濡。',64,'全唐诗/poet.song.47000.json','["天意分明應魯雩，高壇晨拜紫袍濡。", "禽窺舊井寒泉長，魚泳新荷涸轍蘇。", "敏政有餘閑利刃，清詩無纇擲靈珠。", "夏畦蒙潤秋皋稔，顔巷銷憂卒歲娛。"]'),
('23d2133f-2a5c-487b-b0e6-c1dbfb8bd95f','送榮子揚齋郎','朱長文','宋','宋诗','song-poetry','','[]','茹蔬酌水度清晨，自是浮生潔靜身。',64,'全唐诗/poet.song.47000.json','["茹蔬酌水度清晨，自是浮生潔靜身。", "好事頻過三徑晚，愛閑惜別五湖春。", "品泉暗識南零味，鑒茗多藏北苑真。", "且著青袍居膝下，少年未羨折腰人。"]'),
('1dc43fd9-e09b-450d-8f3b-bcc67e7a789b','次韵公權燈花','朱長文','宋','宋诗','song-poetry','','[]','蘭膏未耗結花新，花自無情喜在人。',64,'全唐诗/poet.song.47000.json','["蘭膏未耗結花新，花自無情喜在人。", "生向輕籠先得地，開從細焰別裝春。", "飛蛾雖繞光難掩，夢蝶初迴色尚勻。", "更待玉堂清夜直，賜來蓮燭影相鄰。"]'),
('baea3b2d-3412-4e88-a3d1-bcf99625f18c','次韵俞子文南軒雨後','朱長文','宋','宋诗','song-poetry','','[]','農疇已種圃畦青，高卧丘園自放情。',64,'全唐诗/poet.song.47000.json','["農疇已種圃畦青，高卧丘園自放情。", "客少不嫌三徑濕，年豐休嘆一瓢清。", "殘鶑喜向風前囀，病鶴猶能月下鳴。", "千載令名如有得，莫愁軒冕老無成。"]'),
('53053b28-c638-47fd-a55e-dcbf27ae086c','次韵俞子文感事','朱長文','宋','宋诗','song-poetry','','[]','我曾折桂向蟾宮，君有文華似彩虹。',64,'全唐诗/poet.song.47000.json','["我曾折桂向蟾宮，君有文華似彩虹。", "連蹇未酬平日願，笑歌猶得故鄉同。", "不才甘作耕巖叟，有志宜爲結駟翁。", "窮達由來都似夢，幾人曾是黑頭公。"]'),
('512ae59a-d395-4af8-be52-f5dda1f01030','次韵楊彝甫見成甫裝褾舊書之什','朱長文','宋','宋诗','song-poetry','','[]','儒者須看萬卷書，古人精博固難如。',64,'全唐诗/poet.song.47000.json','["儒者須看萬卷書，古人精博固難如。", "殘編莫惜裝褫費，舊迹堪憐繕寫初。", "輕撥蠹蟲文未損，平齊緗帙架無虛。", "白頭更且窮經藝，誰道忘筌便得魚。"]'),
('e995055f-e7ad-4345-843f-052e71d2c44f','次韵公權庾中成詠','朱長文','宋','宋诗','song-poetry','','[]','坐局偷閑步小橋，風隨秋葉過軒蕭。',64,'全唐诗/poet.song.47000.json','["坐局偷閑步小橋，風隨秋葉過軒蕭。", "愁多萬斛量難盡，飲欠千鍾困易銷。", "笠澤狂歌方繼陸，海門高隠莫如焦。", "昔時委吏猶堪處，誰道倉公厭寂寥。"]'),
('8e0768c9-2166-4f2a-8a72-8f4fc43eab7f','喜公權仲逢垂訪','朱長文','宋','宋诗','song-poetry','','[]','高軒相約訪柴關，瀟灑如君會合難。',64,'全唐诗/poet.song.47000.json','["高軒相約訪柴關，瀟灑如君會合難。", "雨徑偕行穿履濕，風亭久佇袷衣寒。", "百忙好向閑中息，萬動宜當靜處看。", "公暇再來應不倦，東籬金蕊未凋殘。"]'),
('616284b0-3cf4-4099-8126-69ce8646d839','曉坐朋雲齋懷公紹','朱長文','宋','宋诗','song-poetry','','[]','曉來乘興步高岡，便就幽齋作醉鄉。',64,'全唐诗/poet.song.47000.json','["曉來乘興步高岡，便就幽齋作醉鄉。", "鄰寺樓臺分兩面，一家池館得中央。", "南坡嫩橘寒傾日，北牖疏筠小带霜。", "更待怪松擎積雪，莫辭訪戴舉瑶觴。"]'),
('11b62bd2-91e0-49be-a7ff-5cce7d7a88de','次韵蘇文饒見貽之什','朱長文','宋','宋诗','song-poetry','','[]','閒釣松陵閱歲多，家林終日對煙蘿。',64,'全唐诗/poet.song.47000.json','["閒釣松陵閱歲多，家林終日對煙蘿。", "茹芝深隠慚商皓，獻璧求知笑卞和。", "靜送征鴻雲外翼，吟看老桂月中柯。", "洛陽年少材驚俗，車馬猶從陋巷過。"]'),
('e6b2ff3e-70cf-4fe2-8ad7-f6957f4e3362','次韵樞言龍圖得請洞霄之作  其一','朱長文','宋','宋诗','song-poetry','','[]','世間如幻此生浮，寧典仙祠不典州。',64,'全唐诗/poet.song.47000.json','["世間如幻此生浮，寧典仙祠不典州。", "决勝金城勳烈茂，宣風玉壘治聲優。", "遠移遁跡無嘶馬，舊得調元問喘牛。", "耆俊如公宜大用，行聞召節趣蘭舟。"]'),
('5590aaa9-815a-47ed-acf0-12d4dc35ab40','次韵樞言龍圖得請洞霄之作  其二','朱長文','宋','宋诗','song-poetry','','[]','平生氣節薄青雲，不任機心只任真。',64,'全唐诗/poet.song.47000.json','["平生氣節薄青雲，不任機心只任真。", "金爲散多虛越橐，衣從洗浄遠京塵。", "吟隨猿鶴滄洲晚，醉賞鶑花茂苑春。", "仰止高賢同里閈，掃門羞未效前人。"]'),
('2b1a3ffa-270a-4cb6-be90-f27e796000f0','次韵公紹賀崇靜之賜金紫  其一','朱長文','宋','宋诗','song-poetry','','[]','北窗二紀傲羲皇，節比淵明事更光。',64,'全唐诗/poet.song.47000.json','["北窗二紀傲羲皇，節比淵明事更光。", "共喜遐齡垂紫綬，莫嫌猛退棄銅章。", "文房句就心常佚，藥鼎功成壽轉長。", "七品官階三品服，滿斟綠醑醉春陽。"]'),
('dd5a6f4f-fc51-404b-85e5-6b6c7d6ad640','次韵公紹賀崇靜之賜金紫  其二','朱長文','宋','宋诗','song-poetry','','[]','久脫朝衣襲野裳，親逢盛旦日重光。',64,'全唐诗/poet.song.47000.json','["久脫朝衣襲野裳，親逢盛旦日重光。", "耕田鑿井堯民事，垂組懷黄漢服章。", "諸老相歡陶聖治，兩宮遥祝與天長。", "謫仙才調今誰是，肯解金龜燕夕陽。"]'),
('4b9ebbde-195d-4a15-8da7-6b69858ab043','次韵徐中散丙寅二月見訪之什','朱長文','宋','宋诗','song-poetry','','[]','數年解紱隠林扉，乘興頻來訪習池。',64,'全唐诗/poet.song.47000.json','["數年解紱隠林扉，乘興頻來訪習池。", "老似樂天兼少病，官如叔夜又能詩。", "身閑幸與耆英接，學淺虛蒙國士知。", "白雪佳章難復繼，策駑追驥自嫌疲。"]'),
('4988e550-0418-4534-9799-3c7470896f8d','祖母生日','朱長文','宋','宋诗','song-poetry','','[]','挺生賢德對耆英，歲物皆新氣淑清。',64,'全唐诗/poet.song.47000.json','["挺生賢德對耆英，歲物皆新氣淑清。", "年至七旬人已少，子爲四品世稱榮。", "紫泥屢捧門多慶，華髮雖稠體益輕。", "欲比遐齡何所似，蟠桃結實老仙京。"]'),
('52256711-0e8b-4d42-9859-a7b6ba957c8b','判府曹宣徽生日  其一','朱長文','宋','宋诗','song-poetry','','[]','星杓指未月增弦，神選良時協半千。',64,'全唐诗/poet.song.47000.json','["星杓指未月增弦，神選良時協半千。", "恭慎動遵長樂意，潔清能紹冀王賢。", "緩垂相印淹公論，堅請州符避劇權。", "四十擁旄非不貴，更看黄髮珥貂蟬。"]'),
('49dc537a-297f-4530-8a78-879227a8aa0d','判府曹宣徽生日  其二','朱長文','宋','宋诗','song-poetry','','[]','盛世高門福兩全，星辰粹氣萃爲賢。',64,'全唐诗/poet.song.47000.json','["盛世高門福兩全，星辰粹氣萃爲賢。", "釣璜韜略傳三葉，齋鉞風稜積十年。", "陰德在人宜壽考，清才脫俗恐神仙。", "寒儒欲繼崧高頌，不獨生申但美宣。"]'),
('bcf13a71-9b4d-4f38-a861-af825177398c','郡牧李侍郎生日  其一','朱長文','宋','宋诗','song-poetry','','[]','柱史仙翁舊指枝，生賢左右太平基。',64,'全唐诗/poet.song.47000.json','["柱史仙翁舊指枝，生賢左右太平基。", "居留成就昭陵後，賜告從容故里時。", "籌策久爲當世重，勳勞方受兩宮知。", "欲祈天錫公眉壽，更過芳蓮葉上龜。"]'),
('80e5dd00-3f4b-492b-8514-8c54590efdfd','郡牧李侍郎生日  其二','朱長文','宋','宋诗','song-poetry','','[]','當年弧矢設門闌，英氣鍾於曲阜間。',64,'全唐诗/poet.song.47000.json','["當年弧矢設門闌，英氣鍾於曲阜間。", "名覆金甌新品地，香盤密印舊家山。", "腰邊龜組光華動，膝下龍駒禮法閑。", "五福俱全誰跂及，流霞爲壽日開顔。"]'),
('4728487a-d50d-4224-9d8d-f08521d77aa6','閏月丙子判府相公被制命升使弼越六月癸卯公誕生之辰謹齋潔爲詩二章拜獻左右雖辭句蕪纇不足奉揚盛德姑以述惓惓之誠  其一','朱長文','宋','宋诗','song-poetry','','[]','武德陰功積在民，既生太姒復生申。',64,'全唐诗/poet.song.47000.json','["武德陰功積在民，既生太姒復生申。", "手提將鉞雖三世，身到台衡始二人。", "膝下龍駒環壽斝，日邊鳳使捧恩綸。", "沙堤築就朱衣引，富有青春尚四旬。"]'),
('2b09dfdc-409b-45f1-84a0-35e031d41f94','閏月丙子判府相公被制命升使弼越六月癸卯公誕生之辰謹齋潔爲詩二章拜獻左右雖辭句蕪纇不足奉揚盛德姑以述惓惓之誠  其二','朱長文','宋','宋诗','song-poetry','','[]','宣制初聞下玉墀，又逢盛事協熊羆。',64,'全唐诗/poet.song.47000.json','["宣制初聞下玉墀，又逢盛事協熊羆。", "青霄靈昴凝祥久，紫府蟠桃結實奇。", "養志增添龜鶴算，避權辭讓鳳凰池。", "從今若校中書考，屈指當如郭子儀。"]'),
('fe49c31e-e7c9-47a9-91a4-181a32ac28cf','元厚之少保生日','朱長文','宋','宋诗','song-poetry','','[]','四紀勳榮動冕旒，倦趨黄閣傍滄洲。',64,'全唐诗/poet.song.47000.json','["四紀勳榮動冕旒，倦趨黄閣傍滄洲。", "名如白傅身尤貴，才繼微之德更優。", "千載神龜巢葉穩，九霄老鳳带雛遊。", "蓬萊水淺公猶健，輝照東南對斗牛。"]'),
('0a7f469d-b601-40e4-9795-265d8041cfc6','答人見慶除博士','朱長文','宋','宋诗','song-poetry','','[]','幅巾短褐對江雲，閑把群經自討論。',64,'全唐诗/poet.song.47000.json','["幅巾短褐對江雲，閑把群經自討論。", "魯泮未能開後學，虞庠豈稱講微言。", "羸駒久絕騰驤望，病木猶霑化育恩。", "蔣徑雖荒陶菊在，徘徊惟恐去吳門。"]'),
('c442a00b-03e5-44e4-9dd9-9b7e617c9c84','元少保生日  其一','朱長文','宋','宋诗','song-poetry','','[]','孟夏堯蓂六葉殘，來從仙府瑞人寰。',64,'全唐诗/poet.song.47000.json','["孟夏堯蓂六葉殘，來從仙府瑞人寰。", "幾年彩鳳池中浴，此日神龜葉上閑。", "七老相歡非將相，二疏高宴欠湖山。", "羨公退自台衡地，長在煙霞縹緲間。"]'),
('3cb0987b-acbc-455f-bf54-24e170991bf1','元少保生日  其二','朱長文','宋','宋诗','song-poetry','','[]','體貌方隆避政樞，歸來衮繡耀東吳。',64,'全唐诗/poet.song.47000.json','["體貌方隆避政樞，歸來衮繡耀東吳。", "騎鯨才格從天稟，化鶴風姿與衆殊。", "經國文章垂睿想，濟民德澤感神扶。", "堂邊三壽高千丈，依舊扁舟泛五湖。"]'),
('b09c6bb2-8297-476b-b749-d115cfd769a9','程給事新第','朱長文','宋','宋诗','song-poetry','','[]','朱門不鎖走朱輪，東省仙材晝錦人。',64,'全唐诗/poet.song.47000.json','["朱門不鎖走朱輪，東省仙材晝錦人。", "石上雲輕林屋曉，花頭露重洛陽春。", "謝公棋戰烏巾靜，裴令吟高綠野新。", "他日南園真可乞，滿池煙水正相鄰。"]'),
('d00bf224-e7c3-4f00-82cd-5bb3e579afc3','判府蒲左丞寵贈佳篇謹次韵','朱長文','宋','宋诗','song-poetry','','[]','高文大冊耀天衢，新句鏘金擲隠居。',64,'全唐诗/poet.song.47000.json','["高文大冊耀天衢，新句鏘金擲隠居。", "廊廟方將歸輔弼，江湖猶復念耕漁。", "百城草木知威望，一代賢能入薦書。", "近日東南興節士，既旌吳子又褒徐。"]'),
('dbedd514-631a-4c5f-a845-598fbc6b97f3','次韵公權喜太守再留','朱長文','宋','宋诗','song-poetry','','[]','不爲機巧不求新，坦坦襟懷任道真。',64,'全唐诗/poet.song.47000.json','["不爲機巧不求新，坦坦襟懷任道真。", "揭節二方陰布德，分符千里別生春。", "兒童共喜重迎伋，父老相歡許借恂。", "池閣逍遥無一事，清風入座轉汀蘋。"]'),
('25c8f9ed-7cd3-4038-94e4-198c3d805519','近承南康朝請使君寵訪林圃小酌至夜公權特惠篇什謹次韵','朱長文','宋','宋诗','song-poetry','','[]','栝柏森森覆小臺，凌風采菊共銜杯。',64,'全唐诗/poet.song.47000.json','["栝柏森森覆小臺，凌風采菊共銜杯。", "東籬寂寞陶翁醉，連騎繽紛衛相來。", "放浪五湖慚釣客，均調玉燭仰璇魁。", "秋河半夜檐前轉，誰泛仙槎去却迴。"]'),
('90beb3fe-ba0f-4d36-b96d-397ca4ab1f0c','奉陪太守及諸公遊虎丘','朱長文','宋','宋诗','song-poetry','','[]','何必襄陽孟浩然，苦吟自可繼前賢。',64,'全唐诗/poet.song.47000.json','["何必襄陽孟浩然，苦吟自可繼前賢。", "虎丘合去十二度，熊軾再遊三百年。", "雲閣爲君追舊額，霓裳從古播朱絃。", "此行不減唐人樂，暢飲惟無八酒仙。"]'),
('f5713c9a-73a8-4b3c-9dac-d65232244e36','次韵司封使君和練推官春望之什','朱長文','宋','宋诗','song-poetry','','[]','目極江湖近，心存象魏遥。',72,'全唐诗/poet.song.47000.json','["目極江湖近，心存象魏遥。", "未調金鼎餗，新泛玉觴椒。", "賦爲凭欄得，憂從散帙消。", "高才方謝守，輕舉羨王喬。", "桃結千年蕊，松抽百尺條。", "天涯舟一葉，風送逸漁樵。"]'),
('4d03d12b-5bab-4233-9858-5134eaeac797','次韵蒲左丞遊虎丘十首  其一','朱長文','宋','宋诗','song-poetry','','[]','玉堂紫閣冠英游，身作三公未白頭。',32,'全唐诗/poet.song.47000.json','["玉堂紫閣冠英游，身作三公未白頭。", "須向鳳凰池上浴，豈容蕭散詠林丘。"]'),
('41f89794-9c5f-4232-b69e-50a071628081','次韵蒲左丞遊虎丘十首  其二','朱長文','宋','宋诗','song-poetry','','[]','掃石捫蘿向上行，門前坐見白雲生。',32,'全唐诗/poet.song.47000.json','["掃石捫蘿向上行，門前坐見白雲生。", "應思夢得多佳趣，獨宿樓中待月明。"]'),
('caee9f23-20b4-4657-9695-b14de5ebed38','次韵蒲左丞遊虎丘十首  其三','朱長文','宋','宋诗','song-poetry','','[]','地近峰低俗慣遊，不知絕景冠吳州。',32,'全唐诗/poet.song.47000.json','["地近峰低俗慣遊，不知絕景冠吳州。", "從今合與名山等，左轄題詩翠嶺頭。"]'),
('04b41fce-c582-410d-a1dc-23f1fdda9ad9','次韵蒲左丞遊虎丘十首  其四','朱長文','宋','宋诗','song-poetry','','[]','羣山處處盡凌空，未若奇峰隠寺中。',32,'全唐诗/poet.song.47000.json','["羣山處處盡凌空，未若奇峰隠寺中。", "一見便知名不棄，爲傳佳句滿江東。"]'),
('a688c4c7-6381-4bbd-8085-794b21af2cf6','次韵蒲左丞遊虎丘十首  其五','朱長文','宋','宋诗','song-poetry','','[]','萬丈澄潭挾兩崖，削成奇壁自天開。',32,'全唐诗/poet.song.47000.json','["萬丈澄潭挾兩崖，削成奇壁自天開。", "龍泉一淬名因得，不待秦皇發塚來。"]'),
('a2c709c1-7992-4f40-a80f-75ce2613433c','次韵蒲左丞遊虎丘十首  其六','朱長文','宋','宋诗','song-poetry','','[]','層巒稍稍暮雲歸，喬木森森衆鳥依。',32,'全唐诗/poet.song.47000.json','["層巒稍稍暮雲歸，喬木森森衆鳥依。", "再踏石花尋去路，畫船十隻带斜暉。"]'),
('b7a19977-93e7-43d6-8e34-7764e01062ad','次韵蒲左丞遊虎丘十首  其七','朱長文','宋','宋诗','song-poetry','','[]','丘如蹲虎占吳西，應得佳名故國時。',32,'全唐诗/poet.song.47000.json','["丘如蹲虎占吳西，應得佳名故國時。", "未必金精能變化，空傳怪說使人疑。"]'),
('6f9ab4ec-22f4-4692-b5ad-a19ff44b3c63','次韵蒲左丞遊虎丘十首  其八','朱長文','宋','宋诗','song-poetry','','[]','海湧當年有舊山，吳王侈葬倚層巒。',32,'全唐诗/poet.song.47000.json','["海湧當年有舊山，吳王侈葬倚層巒。", "誰知國破丘陵在，兄弟幽居屬二難。"]'),
('7d6b4503-976f-4475-9be8-994b62d80ac2','次韵蒲左丞遊虎丘十首  其九','朱長文','宋','宋诗','song-poetry','','[]','西溪風月宜真賞，東嶺煙霞稱苦吟。',32,'全唐诗/poet.song.47000.json','["西溪風月宜真賞，東嶺煙霞稱苦吟。", "他日黄扉勤論道，秋風一夢到山林。"]'),
('dfc1e3ed-29c8-4593-819e-76b08019a390','次韵蒲左丞遊虎丘十首  其一○','朱長文','宋','宋诗','song-poetry','','[]','雲霞咫尺壓吳郊，乘興斯須棹小舠。',32,'全唐诗/poet.song.47000.json','["雲霞咫尺壓吳郊，乘興斯須棹小舠。", "欲往結廬嗟未得，羨他何氏有三高。"]'),
('45615e42-3709-4861-a617-08400ad8ed7a','秋月乘興遊松江至垂虹亭登長橋夜泊南岸旦遊寧境院因成十絕呈君勉且寄子通  其一','朱長文','宋','宋诗','song-poetry','','[]','綵衣幾度醉江濱，今日重來淚滿巾。',32,'全唐诗/poet.song.47000.json','["綵衣幾度醉江濱，今日重來淚滿巾。", "惟有舊詩存屋壁，豈知投老負垂綸。"]'),
('a349589b-b176-4397-8562-31bf7a1bfa1a','秋月乘興遊松江至垂虹亭登長橋夜泊南岸旦遊寧境院因成十絕呈君勉且寄子通  其二','朱長文','宋','宋诗','song-poetry','','[]','前哲臨流猛拂衣，身違憂患是先幾。',32,'全唐诗/poet.song.47000.json','["前哲臨流猛拂衣，身違憂患是先幾。", "非才自合居閑曠，不泛五湖何處歸。"]'),
('acf0e750-8373-432c-8495-c5448a77717e','秋月乘興遊松江至垂虹亭登長橋夜泊南岸旦遊寧境院因成十絕呈君勉且寄子通  其三','朱長文','宋','宋诗','song-poetry','','[]','雲動鑑中雙槳飛，天圍林外片帆歸。',32,'全唐诗/poet.song.47000.json','["雲動鑑中雙槳飛，天圍林外片帆歸。", "欄桿倚遍日云暮，坐看丹霞生翠微。"]'),
('a2a1e84c-39fa-4614-b87e-a6b5a903988b','秋月乘興遊松江至垂虹亭登長橋夜泊南岸旦遊寧境院因成十絕呈君勉且寄子通  其四','朱長文','宋','宋诗','song-poetry','','[]','人爭軒冕安在哉，我愛煙霞歸去來。',32,'全唐诗/poet.song.47000.json','["人爭軒冕安在哉，我愛煙霞歸去來。", "魯望有靈還見笑，更回城郭戀塵埃。"]'),
('5967f593-fe0f-4413-9d4b-b7bf366cb97b','秋月乘興遊松江至垂虹亭登長橋夜泊南岸旦遊寧境院因成十絕呈君勉且寄子通  其五','朱長文','宋','宋诗','song-poetry','','[]','兩山映日磨蒼玉，萬頃涵虛皺碧羅。',32,'全唐诗/poet.song.47000.json','["兩山映日磨蒼玉，萬頃涵虛皺碧羅。", "不會樂天猶近俗，謾將絃管雜煙波。"]'),
('313b3a6a-7c2d-4ed2-b970-04aa92324313','秋月乘興遊松江至垂虹亭登長橋夜泊南岸旦遊寧境院因成十絕呈君勉且寄子通  其六','朱長文','宋','宋诗','song-poetry','','[]','長虹穩卧碧江心，夢寐頻遊覺莫尋。',32,'全唐诗/poet.song.47000.json','["長虹穩卧碧江心，夢寐頻遊覺莫尋。", "歡友相逢清絕處，酣歌一夕抵千金。"]'),
