('4e482384-08b5-4709-8c4a-d4ba97053645','英宗皇帝挽詞五首  其四','朱長文','宋','宋诗','song-poetry','','[]','鳳翣行將遠，龍髯斷莫尋。',48,'全唐诗/poet.song.47000.json','["鳳翣行將遠，龍髯斷莫尋。", "白雲留穆御，黄屋豈堯心。", "雖享天齡淺，終成睿算深。", "垂鴻須萬祀，累葉奉姜任。"]'),
('bf00c8d4-9ed4-4916-a18b-e44753ab8649','英宗皇帝挽詞五首  其五','朱長文','宋','宋诗','song-poetry','','[]','有德三宗後，無憂累聖間。',48,'全唐诗/poet.song.47000.json','["有德三宗後，無憂累聖間。", "鳳當金粟翥，龍隔鼎湖攀。", "玉几言猶在，霓旌去不還。", "園陵饒瑞氣，東接永昭山。"]'),
('0bf3ca4c-8478-481d-bd0f-b929ea45e1e1','邵湘母挽詩','朱長文','宋','宋诗','song-poetry','','[]','華屋辭榮養，佳城合舊封。',48,'全唐诗/poet.song.47000.json','["華屋辭榮養，佳城合舊封。", "浮生無定相，衆善有遺蹤。", "家盛金籝在，山長玉案重。", "浮圖傳勝事，寶殿壯天峰。"]'),
('4ac9b1c4-d1f2-41eb-b4fa-de280f6195b6','張虞卿挽詩','朱長文','宋','宋诗','song-poetry','','[]','一卧東吳七十春，區區南北笑鄉人。',64,'全唐诗/poet.song.47000.json','["一卧東吳七十春，區區南北笑鄉人。", "盛開黌舍招英俊，敞闢華堂待縉紳。", "婉婉重孫勝綵服，煌煌兩婿擁朱輪。", "銘旌已去空回首，通德門前舊是鄰。"]'),
('5df863a7-347b-4b1e-9c1c-f67be6d6eaa0','林少卿挽詩','朱長文','宋','宋诗','song-poetry','','[]','壽考安榮遇聖朝，構成門戶自勤勞。',64,'全唐诗/poet.song.47000.json','["壽考安榮遇聖朝，構成門戶自勤勞。", "閨中萊婦皆華髮，膝下荀龍盡綠袍。", "堂有金籝身更約，案披玉簡道尤高。", "人間厚福終歸盡，漲海難停一夜濤。"]'),
('e8f76571-442f-4606-9497-06011e8b8ddb','黄朝散挽詩  其一','朱長文','宋','宋诗','song-poetry','','[]','持心平厚勝澆浮，仕路徊翔四十秋。',64,'全唐诗/poet.song.47000.json','["持心平厚勝澆浮，仕路徊翔四十秋。", "政事每於談笑辦，交親多向急難收。", "命由真宰隨窮達，身在勞生任去留。", "舊治昔年應畫像，龐眉聞訃淚先流。"]'),
('65bc3068-1be8-439c-8d55-0014e9b14781','黄朝散挽詩  其二','朱長文','宋','宋诗','song-poetry','','[]','江湖嘗佩左符歸，一卧漳濱素願違。',64,'全唐诗/poet.song.47000.json','["江湖嘗佩左符歸，一卧漳濱素願違。", "平日華旌過里巷，此時丹旐下巖扉。", "羣峰拱揖開新穴，萬木森羅長舊圍。", "佇看于門驅駟馬，想應丘隴亦光輝。"]'),
('67377db7-c626-49c5-b9e8-7d674977b0b4','太守召陪諸公遊虎丘','朱長文','宋','宋诗','song-poetry','','[]','海湧一小山，遠視如陵丘。',288,'全唐诗/poet.song.47000.json','["海湧一小山，遠視如陵丘。", "中藏天下奇，巖谷峻且幽。", "石壁老萬古，劍池照千秋。", "蕞爾小吳會，隠然瞰瀛洲。", "能令軒冕客，到此忘沉憂。", "樂天擁千騎，一月常一遊。", "高賢愛絕景，塵事莫可留。", "我公初下車，明斷速如流。", "千里滿和氣，訟庭無繫囚。", "三英皆膚使，金節憩南州。", "同聲約真賞，相應如鳴球。", "半刺富文雅，嘉賓張與劉。", "清晨出西閶，山翠逼蘭舟。", "耕叟迎彩旆，佳禽和鳴騶。", "憑闌共四顧，湖海入危樓。", "雲低未作雨，萬象圍寸眸。", "憲老揮散隸，妙絕與古儔。", "河漢淡輕靄，天門跳驚虯。", "才名三十年，餘事及銀鈎。", "茲遊雖偶然，千載仰芳猷。", "日暮下危磴，玉杯相獻酬。", "一篇間一局，豪放不自休。", "樂哉文字飲，相與喜賢侯。", "短篇春事勝，可與吳兒謳。"]'),
('09dfbdde-815b-4c2f-9091-50d47c8664f5','疊嶂樓有懷吳門','朱長文','宋','宋诗','song-poetry','','[]','虎邱換得敬亭山，句水松陵數舍間。',64,'全唐诗/poet.song.47000.json','["虎邱換得敬亭山，句水松陵數舍間。", "天下難如兩州好，君恩乞與一身閑。", "慚無牒訴煩敲撲，喜有林泉數往還。", "猶想朋雲隠君子，思歸時見鬢毛班。"]'),
('d1b1d16d-84c7-46f4-9bc8-4cbea2191a40','春眺西上岡寄徐員外','朱長文','宋','宋诗','song-poetry','','[]','蕪城西眺極滄流，漠漠春烟暗戍樓。',48,'全唐诗/poet.song.47000.json','["蕪城西眺極滄流，漠漠春烟暗戍樓。", "瓜步早潮吞建業，蒜山晴日照揚州。", "隋家故事不能問，鶴在仙池期我遊。"]'),
('8b7f7af5-2801-41c4-9f6e-bb7647f70fbd','句','朱長文','宋','宋诗','song-poetry','','[]','孤館閉塞水，大江生夜風。',12,'全唐诗/poet.song.47000.json','["孤館閉塞水，大江生夜風。"]'),
('7e1012e9-f08d-4ac5-a6c1-db567342c8a5','郭綸','蘇轍','宋','宋诗','song-poetry','','[]','郭綸本蕃種，騎鬥雄西戎。',288,'全唐诗/poet.song.47000.json','["郭綸本蕃種，騎鬥雄西戎。", "流落初無罪，因循遂龍鍾。", "嘉州已經歲，見我涕無窮。", "自言將家子，少小學彎弓。", "長遇西鄙亂，走馬救邊烽。", "手挑丈八矛，所往如投空。", "平生事苦戰，數與大寇逢。", "昔在定川寨，賊來如羣蜂。", "萬騎擁酋帥，自謂白相公。", "揮兵取其元，模糊腥血紅。", "戰勝士氣振，赴敵如旋風。", "蚩蚩氈裘將，不信勇且忠。", "遥語相勸誘，一矢摧厥胸。", "短兵接死地，日落沙塵蒙。", "馳歸不敢息，馬口銜折鋒。", "誰知八尺軀，脫命萬死中。", "忽聞南蠻叛，羽檄行匆匆。", "將兵赴危難，瘴霧不辭衝。", "行經賀州城，寂寞無人蹤。", "攀堞莽不見，入據爲築墉。", "一旦賊兵下，百計燒且攻。", "三日不能陷，救至遂得通。", "崎嶇有成績，元帥多異同。", "有功不見賞，憔悴落巴賨。"]'),
('9f55d8f0-7316-4789-bb8b-8a3716ed91b8','初發嘉州','蘇轍','宋','宋诗','song-poetry','','[]','放舟沫江濱，往意念荆楚。',216,'全唐诗/poet.song.47000.json','["放舟沫江濱，往意念荆楚。", "擊鼓樹兩旗，勢如遠征戍。", "紛紛上船人，艣急不容語。", "余生雖江陽，未省至嘉樹。", "巉巉九頂峰，可愛不可住。", "飛舟過山足，佛脚見江滸。", "舟人盡斂容，競欲揖其拇。", "俄頃已不見，烏牛在中渚。", "移舟近山陰，壁峭上無路。", "云有古郭生，此地苦箋注。", "區區辨蟲魚，爾雅細分縷。", "洗硯去殘墨，遍水如黑霧。", "至今江上魚，頂有遺墨處。", "覽物悲古人，嗟此空自苦。", "余今方南行，朝夕事鳴艣。", "至楚不復留，上馬千里去。", "誰能居深山，永與禽獸伍。", "此事誰是非，行行重回顧。"]'),
('0d0a414c-b175-48b4-9333-e6db1af27f6c','過宜賓見夷中亂山','蘇轍','宋','宋诗','song-poetry','','[]','江流日益深，民語漸已變。',72,'全唐诗/poet.song.47000.json','["江流日益深，民語漸已變。", "岸闊山盡平，連峰遠非漢。", "慘慘瘴氣青，薄薄寒日暖。", "峰巒若崖石，草木條幹短。", "遥想彼居人，狀類麏鹿竄。", "何時遂平定，戍卒從此返。"]'),
('e4d46503-988e-4f88-b3a6-300ccd6f3c46','夜泊牛口','蘇轍','宋','宋诗','song-poetry','','[]','行過石壁盡，夜泊牛口渚。',96,'全唐诗/poet.song.47000.json','["行過石壁盡，夜泊牛口渚。", "野老三四家，寒燈照疏樹。", "見我各無言，倚石但箕踞。", "水寒雙脛長，壞袴不蔽股。", "日莫江上歸，潛魚遠難捕。", "稻飯不滿盂，饑卧冷徹曙。", "安知城市歡，守此田野趣。", "祇應長凍饑，寒暑不能苦。"]'),
('5e9ea072-7526-4c6b-bf71-8acba5d76cbd','戎州','蘇轍','宋','宋诗','song-poetry','','[]','江水通三峽，州城控百蠻。',72,'全唐诗/poet.song.47000.json','["江水通三峽，州城控百蠻。", "沙昏行旅倦，邊靜禁軍閑。", "漢虜更成市，羅紈靳不還。", "投氈揀精密，換馬瘦孱顔。", "兀兀頭垂髻，團團耳带環。", "夷聲不可會，爭利苦間關。"]'),
('f423b7ea-fcdf-4903-9d69-02ccd76c9177','舟中聽琴','蘇轍','宋','宋诗','song-poetry','','[]','江流浩浩羣動息，琴聲琅琅中夜鳴。',144,'全唐诗/poet.song.47000.json','["江流浩浩羣動息，琴聲琅琅中夜鳴。", "水深天闊音響遠，仰視牛斗皆從橫。", "昔有至人愛奇曲，學之三歲終無成。", "一朝隨師過滄海，留置絕島不復迎。", "終年見怪心自感，海水震掉魚龍驚。", "翻回蕩潏有遺韵，琴意忽忽從此生。", "師來迎笑問所得，撫手無言心已明。", "世人囂囂好絲竹，撞鐘擊鼓浪謂榮。", "安知江琴韵超絕，擺耳大笑不肯聽。"]'),
('54bdc11a-470f-4ec1-bee1-8377eb814b10','泊南井口期任遵聖','蘇轍','宋','宋诗','song-poetry','','[]','期君荒江濆，未至望已極。',60,'全唐诗/poet.song.47000.json','["期君荒江濆，未至望已極。", "朔風吹烏裘，隠隠沙上立。", "愧余後期至，先到犯寒色。", "既泊問所如，歸去已無及。", "繫舟重相邀，雨冷塗路濕。"]'),
('fd234aec-a5f3-4cfd-9cb0-a82f3dc0ee1e','江上早起','蘇轍','宋','宋诗','song-poetry','','[]','晨興孤舟上，盥濯夜氣清。',144,'全唐诗/poet.song.47000.json','["晨興孤舟上，盥濯夜氣清。", "整巾未皇坐，雙艣軋已鳴。", "日出江霧散，江上山從橫。", "區區茅舍翁，曉出露氣腥。", "收筒得大鯉，愛惜不忍烹。", "持之易斗粟，朝飯厭魚羹。", "蕭蕭遠風起，泛泛野雁驚。", "忽過百餘里，山水互變更。", "逢舟問所如，彼此不知名。", "超超江湖間，殊勝地上行。", "旦游市井喧，莫宿無人聲。", "江上誠足樂，無怪陶朱生。"]'),
('83806a63-d266-4663-bc47-e6870063f71b','江上看山','蘇轍','宋','宋诗','song-poetry','','[]','朝看江上枯崖山，憔悴荒榛赤如赭。',64,'全唐诗/poet.song.47000.json','["朝看江上枯崖山，憔悴荒榛赤如赭。", "莫行百里一回頭，落日孤雲靄新畫。", "前山更遠色更深，誰知可愛信如今。", "唯有巫山最穠秀，依然不負遠來心。"]'),
('3d273358-26d6-4b65-ad6b-7d3aecf0080d','山胡','蘇轍','宋','宋诗','song-poetry','','[]','山胡擁蒼毳，兩耳白茸茸。',48,'全唐诗/poet.song.47000.json','["山胡擁蒼毳，兩耳白茸茸。", "野樹啼終日，黔山深幾重。", "啄溪探細石，噪虎上孤峰。", "被執應多恨，筠籠僅不容。"]'),
('e5fc1929-ee03-4939-90c6-f0cf736ce7eb','白鷴','蘇轍','宋','宋诗','song-poetry','','[]','白鷴形似鴿，摇曳尾能長。',48,'全唐诗/poet.song.47000.json','["白鷴形似鴿，摇曳尾能長。", "寂寞懷溪水，低回愛稻粱。", "田家比鷄鶩，野食薦杯觴。", "肯信朱門裏，徘徊占玉塘。"]'),
('04195836-1e2f-42d9-8c57-d3583c2d03c8','屈原塔','蘇轍','宋','宋诗','song-poetry','','[]','屈原遺宅秭歸山，南賓古者巴子國。',80,'全唐诗/poet.song.47000.json','["屈原遺宅秭歸山，南賓古者巴子國。", "山中遺塔知幾年，過者遲疑不能識。", "浮圖高絕誰所爲，原死豈復待汝力。", "臨江慷慨心自明，南訪重華訟孤直。", "世人不知徒悲傷，强爲築土高岌岌。"]'),
('73d1f4cc-14e2-4587-8c68-5459f1d02a19','嚴顔碑','蘇轍','宋','宋诗','song-poetry','','[]','古碑殘缺不可讀，遠人愛惜未忍磨。',128,'全唐诗/poet.song.47000.json','["古碑殘缺不可讀，遠人愛惜未忍磨。", "相傳昔者嚴太守，刻石千歲字已訛。", "嚴顔平生吾不記，獨憶城破節最高。", "被擒不辱古亦有，吾愛善折張飛豪。", "軍中生死何足怪，乘勝使氣可若何。", "斫頭徐死子無怒，我豈畏死如兒曹。", "匹夫受戮或不避，所重壯氣吞黄河。", "臨危閑暇有如此，覽碑慷慨思橫戈。"]'),
('0aa6aed6-b323-4680-845d-53040e49f253','竹枝歌','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','舟行千里不至楚，忽聞竹枝皆楚語。',288,'全唐诗/poet.song.47000.json','["舟行千里不至楚，忽聞竹枝皆楚語。", "楚言啁哳安可分，江中明月多風露。", "扁舟日落駐平沙，茅屋竹籬三四家。", "連舂並汲各無語，齊唱竹枝如有嗟。", "可憐楚人足悲訴，歲樂年豐爾何苦。", "釣魚長江江水深，耕田種麥畏狼虎。", "俚人風俗非中原，處子不嫁如等閑。", "雙鬟垂頂髮已白，負水採薪長苦艱。", "上山採薪多荆棘，負水入溪波浪黑。", "天寒斫木手如龜，水重還家足無力。", "山深瘴暖霜露乾，夜長無衣猶苦寒。", "平生有似麋與鹿，一旦白髮已百年。", "江上乘舟何處客，列肆喧譁占平磧。", "遠來忽去不記州，罷市歸船不相識。", "去家千里未能歸，忽聽長歌皆慘悽。", "空船獨宿無與語，月滿長江歸路迷。", "路迷鄉思渺何極，長怨歌聲苦凄急。", "不知歌者樂與悲，遠客乍聞皆掩泣。"]'),
('aac10c18-4746-4232-940b-0a3d7a85c50f','望夫臺','蘇轍','宋','宋诗','song-poetry','','[]','江上孤峰石爲骨，望夫不來空獨立。',64,'全唐诗/poet.song.47000.json','["江上孤峰石爲骨，望夫不來空獨立。", "去時江水拍山流，去後江移水成磧。", "江移岸改安可知，獨與高山化爲石。", "山高身在心不移，慰爾行人遠行役。"]'),
('88df3e01-b4f3-4de7-a30e-4281dd7afea2','八陣磧','蘇轍','宋','宋诗','song-poetry','','[]','漲江吹八陣，江落陣如故。',132,'全唐诗/poet.song.47000.json','["漲江吹八陣，江落陣如故。", "我來苦寒後，平沙如匹素。", "乘高望遺迹，磊磊六十四。", "遥指如布棋，就視不知處。", "世稱諸葛公，用衆有法度。", "區區落褒斜，軍旅無闊步。", "中原竟不到，置陣狹無所。", "茫茫平沙中，積石排隊伍。", "獨使後世人，知我非莽鹵。", "奈何長蛇形，千古竟不悟。", "惟餘桓元子，久視不能去。"]'),
('d09f4bd4-8309-441e-bf8a-c86c7c33d8c1','灧澦堆','蘇轍','宋','宋诗','song-poetry','','[]','江中石屏灧澦堆，鱉靈夏禹不能摧。',80,'全唐诗/poet.song.47000.json','["江中石屏灧澦堆，鱉靈夏禹不能摧。", "深根百丈無敢近，落日紛紛鳬雁來。", "何人磊落不畏死，爲我赤脚登崔嵬。", "上有古碑刻奇篆，當使盡讀磨蒼苔。", "此碑若見必有怪，恐至絕頂遭風雷。"]'),
('cebb646d-4588-433a-ac78-1aed1ad27b09','入峽','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','舟行瞿唐口，兩耳風鳴號。',228,'全唐诗/poet.song.47000.json','["舟行瞿唐口，兩耳風鳴號。", "渺然長江水，千里投一瓢。", "峽門石爲戶，鬰怒水力驕。", "扁舟落中流，浩如一葉飄。", "呼吸信奔浪，不復由長篙。", "捩柁破濆旋，畏與亂石遭。", "兩山蹙相值，望之不容舠。", "漸近乃可入，白鹽最雄高。", "草木皆倒生，哀叫悲玄猱。", "白雲繚長袖，零落如飛毛。", "緬懷洚水年，慘蹙病有堯。", "禹益决岷水，屢與山鬼鏖。", "摧岡轉大石，破地疏洪濤。", "巉巉當道山，斬截肩尾銷。", "峭壁下無趾，連峰斷脩腰。", "破處不生草，上不掛鳥巢。", "水怪不盡戮，下有龍與鰲。", "遼哉千萬年，禹死遺迹牢。", "豈必見河洛，開峽斯已勞。"]'),
('4cb45ac5-f923-43b0-a29a-a824bfb2e101','巫山廟','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山中廟堂古神女，楚巫婆娑奏歌舞。',376,'全唐诗/poet.song.47000.json','["山中廟堂古神女，楚巫婆娑奏歌舞。", "空山日落悲風吹，舉手睢盱道神語。", "神仙潔清非世人，瓦盎傾醪薦麋脯。", "子知神君竟何自，西方真人古王母。", "飄然乘風遊九州，朅渡西海薄中土。", "白雲爲車駕蒼虬，驂乘湘君宓妃御。", "天孫織綃素非素，衣裳飄颻薄烟霧。", "泊然沖虛眇無營，朝餐屑玉嚥瓊乳。", "下視人世安可據，超江乘山去無所。", "巫山之下江流清，偶然愛之不能去。", "湍崖激作相喧豗，白花翻翻龍正怒。", "堯使大禹導九州，石隕山隊幾折股。", "山前恐懼久無措，稽首山下苦求助。", "丹書玉笈世莫窺，指示文字相爾汝。", "擘山洩江幸無苦，庚辰虞余實相禹。", "功成事定世莫知，空山俄頃千萬古。", "廟中擊鼓吹長簫，採蘭爲飧蕙爲肴，玉缶薦芰香飄蕭。", "龍勺取酒注白茅，神來享之風飄飄。", "荒山長江何所有，豈有瓊玉薦泬寥。", "神君聰明無我責，爲我驅獸攘龍蛟。", "乘船入楚泝巴蜀，濆旋深惡秋水高。", "歸來無恙無以報，山上麥熟可作醪。", "神君尊貴豈待我，再拜長跪神所勞。"]'),
('982e9206-5b14-4c5c-acf3-0a7b09707048','巫山廟烏','蘇轍','宋','宋诗','song-poetry','','[]','巫廟真人古列仙，高心獨愛玉爐烟。',32,'全唐诗/poet.song.47000.json','["巫廟真人古列仙，高心獨愛玉爐烟。", "饑烏巧會行人意，來去紛紛噪客船。"]'),
('5f70d18d-5f2a-4a3d-9474-ce81d15a2827','昭君村','蘇轍','宋','宋诗','song-poetry','','[]','峽女王嬙繼屈須，入宮曾不愧秦姝。',96,'全唐诗/poet.song.47000.json','["峽女王嬙繼屈須，入宮曾不愧秦姝。", "一朝遠逐呼韓去，遥憶江頭捕鯉魚。", "江上大魚安敢釣，轉柁橫江筋力小。", "深邊積雪厚埋牛，兩處辛勤何處好。", "去家離俗慕榮華，富貴終身獨可嗟。", "不及故鄉山上女，夜從東舍嫁西家。"]'),
('d1a485a0-3064-4bbb-9ab1-4cf5562a5557','三遊洞','蘇轍','宋','宋诗','song-poetry','','[]','洞前危徑不容足，洞中明曠坐百人。',128,'全唐诗/poet.song.47000.json','["洞前危徑不容足，洞中明曠坐百人。", "蒼崖硉兀起成柱，亂石散列如驚麇。", "清溪百丈下無路，水滿沙土如魚鱗。", "夜深明月出山頂，下照洞口纔及唇。", "沉沉深黑若大屋，野老構火青如燐。", "平明欲出迷上下，洞氣飄亂爲橫雲。", "深山大澤亦有是，野鳥鳴噪孤熊蹲。", "三人一去無復見，至今冠蓋長滿門。"]'),
('40d94e0d-da07-43e7-bad1-dba49e92936d','寄題清溪寺','蘇轍','宋','宋诗','song-poetry','','[]','清溪鬼谷子，雄辯傾六國。',144,'全唐诗/poet.song.47000.json','["清溪鬼谷子，雄辯傾六國。", "視世無足言，自閉長默默。", "蘇張何爲者，欲竊長短術。", "學成果無頼，遂爲世所惑。", "顛倒賣諸侯，傾轉莫可執。", "後世何不明，疑我不汝及。", "誰知居深山，玩世可終日。", "君觀二弟子，死處竟莫得。", "客齊自披裂，投魏求寄食。", "悠悠清溪中，石亂流水急。", "溪魚爲朝餐，老死得安穴。", "居亂獨無言，其辯吾不測。"]'),
('f066e5d5-5ab9-4bd2-ae94-284a2434e254','息壤','蘇轍','宋','宋诗','song-poetry','','[]','江上寒沙薄如席，一夕墳起成高丘。',320,'全唐诗/poet.song.47000.json','["江上寒沙薄如席，一夕墳起成高丘。", "江流傾轉力不勝，左齧右吐非自由。", "南郡城南獨何者，平地生長殊不休。", "當中屋背不盈尺，深入百丈皆石樓。", "古人不知下有怪，發破不掩水漲浮。", "傳言夏鯀塞洚水，上帝愛此無敢偷。", "竊持大畚負長鎛，刺取不已帝使流。", "禹知水怒非塞止，網捕百怪雜蜃鰍。", "掘壕入土不計丈，投擲填壓聲鳴啾。", "一時既定憂後世，恐此竊出壞九州。", "神人已死無復制，故以此土封其頭。", "發之輒滿不可既，意使靈物長幽囚。", "前年大旱千里赤，取土盈掬雨不收。", "誰言咫尺舊黄壤，中有千歲龍與虬。", "高山萬仞猶可削，嗟此何獨生如疣。", "天長地遠莽無極，雖有缺壞誰能賙。", "我疑天意固有在，患世多事窮鎸鎪。", "埏陶鼓鑄地力困，久不自補無爲憂。", "世無女媧空白石，磊磊滿地如浮漚。", "耕田鑿井自無已，息壤無幾安能酬。"]'),
('2f493206-b8c1-45ce-8bb2-100ff9d2ac9d','荆門惠泉','蘇轍','宋','宋诗','song-poetry','','[]','泉源何從來，山下長溪發。',120,'全唐诗/poet.song.47000.json','["泉源何從來，山下長溪發。", "油然本無營，誰使自激冽。", "茫茫九地底，大水浮一葉。", "使水皆爲泉，地已不勝洩。", "應是衆水中，獨不容至潔。", "涓涓自傾瀉，奕奕見清澈。", "石泓浄無塵，中有三尺雪。", "下爲百丈溪，冷不受魚鱉。", "脫衣浣中流，解我雙足熱。", "樂哉泉上翁，大旱不知渴。"]'),
('a8aa3a72-4731-456a-94f8-78dee02ffe99','答荆門張都官維見和惠泉','蘇轍','宋','宋诗','song-poetry','','[]','荒凉荆門西，泉水誰爲洩。',120,'全唐诗/poet.song.47000.json','["荒凉荆門西，泉水誰爲洩。", "發源雖甚微，來意不可折。", "平鋪清池滿，皎皎自明澈。", "甘凉最宜茶，羊炙可用雪。", "炎風五月交，中夜吐明月。", "太守燕已遠，青嶂空嵲嵲。", "泉上白髮翁，來飲杯饌闕。", "酌水自獻酬，箕踞無禮節。", "區區游泉人，常值午日烈。", "回首憂重城，賞玩安能徹。"]'),
('a55aa2b6-b94f-4a2a-8e9d-bf1f5411cf4e','浰陽早發','蘇轍','宋','宋诗','song-poetry','','[]','春氣入楚澤，原上草猶枯。',96,'全唐诗/poet.song.47000.json','["春氣入楚澤，原上草猶枯。", "北風吹栗林，梅蕊颯已無。", "我行亦何事，驅馬無疾徐。", "楚人信稀少，田畝任蓁蕪。", "空有道路人，擾擾不留車。", "悲傷彼何懶，嘆息此亦愚。", "今我何爲爾，豈亦愚者徒。", "行行楚山曉，霜露滿陂湖。"]'),
('fbeeacf4-27d6-43a7-973d-476ee5bbd9e0','襄陽古樂府二首 野鷹來','蘇轍','宋','宋诗','song-poetry','','[]','野鷹來，雄雉走。',160,'全唐诗/poet.song.47000.json','["野鷹來，雄雉走。", "蒼茫荒榛下，毰毸大如斗。", "鷹來蕭蕭風雨寒，壯士臺中一揮肘。", "臺高百尺臨平川，山中放火秋草乾。", "雉肥兔飽走不去，野鷹飛下風蕭然。", "嵯峨呼鷹臺，人去臺已圮。", "高臺不可見，况復呼鷹子。", "長歌野鷹來，當年落誰耳。", "父生已不武，子立又不强。", "北兵果南下，擾擾如驅羊。", "鷹來野雉何暇走，束縛籠中安得翔。", "可憐野雉亦有爪，兩手捽鷹猶可傷。"]'),
('5a69c5e5-fcbc-4188-9099-76b0c268e059','襄陽古樂府二首 襄陽樂','蘇轍','宋','宋诗','song-poetry','','[]','誰言襄陽苦，歌者樂襄陽。',120,'全唐诗/poet.song.47000.json','["誰言襄陽苦，歌者樂襄陽。", "太守劉公子，千年未可忘。", "劉公一去歲時改，惟有州南漢水長。", "漢水南流峴山碧，種稻耕田泥沒尺。", "里人種麥滿高原，長使越人耕大澤。", "澤中多水原上乾，越人爲種楚人食。", "火耕水耨古常然，漢水魚多去滿船。", "長有行人知此樂，來買槎頭縮項鯿。"]'),
('ef097a05-f26c-488d-ad38-0d03ad61884f','雙鳬觀','蘇轍','宋','宋诗','song-poetry','','[]','王喬西飛朝洛陽，飄飄千里雙鳬翔。',64,'全唐诗/poet.song.47000.json','["王喬西飛朝洛陽，飄飄千里雙鳬翔。", "鳬飛遭網不能去，惟有空屨鳬已亡。", "誰知野鳥不能化，豈必雙屨能飛揚。", "鳬神屨怪當有在，搔首野廟春風長。"]'),
('9c3dd67e-63f6-44a2-8ed3-7de60911ce67','懷黽池寄子瞻兄','蘇轍','宋','宋诗','song-poetry','','[]','相携話別鄭原上，共道長途怕雪泥。',64,'全唐诗/poet.song.47000.json','["相携話別鄭原上，共道長途怕雪泥。", "歸騎還尋大梁陌，行人已渡古崤西。", "曾爲縣吏民知否，舊宿僧房壁共題。", "遥想獨遊佳味少，無言騅馬但鳴嘶。"]'),
('3b039007-eadf-4924-89e9-c6f8f2cd7df6','辛丑除日寄子瞻','蘇轍','宋','宋诗','song-poetry','','[]','一歲不復居，一日安足惜。',264,'全唐诗/poet.song.47000.json','["一歲不復居，一日安足惜。", "人心畏增年，對酒語終夕。", "夜長書室幽，燈燭明照席。", "盤飧雜梁楚，羊炙錯魚腊。", "庖人饌雞兔，家味宛如昔。", "有懷岐山下，展轉不能釋。", "念同去閭里，此節三已失。", "初來寄荆渚，魚雁賤宜客。", "楚人重歲時，爆竹鳴磔磔。", "新春始涉五，田凍未生麥。", "相携歷唐許，花柳漸牙拆。", "居梁不耐貧，投杞避糠覈。", "城南庠齋靜，終歲守墳籍。", "酒酸未嘗飲，牛美每共炙。", "謂言從明年，此會可懸射。", "同爲洛中吏，相去不盈尺。", "濁醪幸分季，新筍可餉伯。", "巑巑嵩山美，漾漾洛水碧。", "官閑得相從，春野玩朝日。", "安知書閤下，羣子並遭馘。", "偶成一朝榮，遂使千里隔。", "何年相會歡，逢節勿輕擲。"]'),
('265370d1-59c2-472a-9eac-279d6e22189d','次韵子瞻減降諸縣囚徒事畢登覽','蘇轍','宋','宋诗','song-poetry','','[]','山川足清曠，闤闠巧拘囚。',288,'全唐诗/poet.song.47000.json','["山川足清曠，闤闠巧拘囚。", "安得孅阿御，同爲穆滿遊。", "遥知因渙汗，遠出散幽憂。", "原隰繁分繡，村墟盡小侯。", "春深秦樹綠，野闊渭河流。", "四顧神蕭瑟，前探意漲浮。", "勝觀殊未已，往足詎能收。", "下坂如浮舸，登崖劇上樓。", "强行腰傴僂，困坐氣噓咻。", "鳥語林巒靜，花明澗谷幽。", "濯溪驚野老，伐路駭他州。", "中散探深去，文淵到處留。", "聽琴峰下寺，弄石水中洲。", "溪冷泉冰脚，山高霧繞頭。", "石潭清照骨，瀑水濺成鈎。", "仙廟鳴鐘磬，神官秉鉞劉。", "養生聞帝女，服氣絕彭讎。", "故宅猶傳尹，先師不喜丘。", "居人那識道，過客謾停騶。", "巖谷誠深絕，神仙信有不。", "雲居無几杖，霞珮棄鎸鎪。", "豹隠連山霧，龍潛百尺湫。", "門開誰與叩，桃熟浪傳偷。", "紺髮清無比，方瞳凜不侔。"]'),
('7f8afb89-fbd1-4b4a-adc5-240a97b2c7bf','次韵子瞻太白山下早行題崇壽院','蘇轍','宋','宋诗','song-poetry','','[]','山下晨光晚，林梢露滴昇。',48,'全唐诗/poet.song.47000.json','["山下晨光晚，林梢露滴昇。", "峰頭斜見月，野市早明燈。", "樹暗猶藏鵲，堂開已饌僧。", "據鞍應夢我，聯騎昔嘗曾。"]'),
('98038728-820e-4b10-a34d-b435d642b40e','次韵子瞻延生觀後山上小堂','蘇轍','宋','宋诗','song-poetry','','[]','謝公遊意未能厭，踏盡登山屐齒尖。',64,'全唐诗/poet.song.47000.json','["謝公遊意未能厭，踏盡登山屐齒尖。", "古殿神仙深杳杳，香爐烟翠起纖纖。", "巖花寂歷飄瓊片，庭檜蕭疏漏玉蟾。", "帝子莫歸人不見，微風細雨自開簾。"]'),
('7e7a50fa-a054-40c5-bce9-f30a5d31a26d','次韵子瞻題仙遊潭中興寺','蘇轍','宋','宋诗','song-poetry','','[]','潭邊沙水不成泥，潭上孤禽挂嶮啼。',64,'全唐诗/poet.song.47000.json','["潭邊沙水不成泥，潭上孤禽挂嶮啼。", "繚繞飛橋能試客，蒙茸翠蔓巧藏溪。", "雲爲絳帳馬融室，石作屏風玉女閨。", "仙果知君今未足，臨潭脚戰怕長梯。"]'),
('799b82c3-9b30-42ee-81da-c150fc5999f1','石鼻城','蘇轍','宋','宋诗','song-poetry','','[]','千山欲盡垂爲鼻，百戰皆空但有城。',64,'全唐诗/poet.song.47000.json','["千山欲盡垂爲鼻，百戰皆空但有城。", "虎闖穴中秦地恐，龍飛渭上漢江傾。", "雍人未有章邯怨，魏將猶存仲達精。", "睥睨陵遲春草滿，白羊無數向風鳴。"]'),
('c3782b97-a1fb-419d-8ab3-f7d326263fef','磻溪石','蘇轍','宋','宋诗','song-poetry','','[]','呂公年已莫，擇主渭河邊。',48,'全唐诗/poet.song.47000.json','["呂公年已莫，擇主渭河邊。", "跪餌留雙膝，臨溪不計年。", "神專能陷石，心大豈營鱣。", "不到磻溪上，安知自守堅。"]'),
('c1f28168-cba7-4a38-ac96-258025f04592','郿塢','蘇轍','宋','宋诗','song-poetry','','[]','董公平昔甚縱橫，晚歲藏金欲避兵。',32,'全唐诗/poet.song.47000.json','["董公平昔甚縱橫，晚歲藏金欲避兵。", "當日英雄智相似，燕南趙北亦爲京。"]'),
('4d45b8c1-330b-484d-ad89-4a7f7e302f12','樓觀','蘇轍','宋','宋诗','song-poetry','','[]','老聃厭世入流沙，飄蕩如雲不可遮。',64,'全唐诗/poet.song.47000.json','["老聃厭世入流沙，飄蕩如雲不可遮。", "弟子憐師將去國，關門望氣載還家。", "高臺尚有傳經處，畫壁空留駕犢車。", "一授遺書無復老，不知何苦服胡麻。"]'),
('28cccd28-ca69-4b42-889e-24038dba2754','次韵子瞻秋雪見寄二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','秋氣蕭騷仍見雪，客愁繚繞動縈心。',64,'全唐诗/poet.song.47000.json','["秋氣蕭騷仍見雪，客愁繚繞動縈心。", "幽吟北戶窗聲細，歸夢函關馬迹深。", "疏樹飛花輕䔩䔩，衰荷留柄亂簪簪。", "遥聞詩酒皆推勝，社客何人近納賝。"]'),
('b6ad6207-cbcc-4a2e-8e41-f8b35d3e75ba','次韵子瞻秋雪見寄二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','平時出處常聯袂，文翰叨陪舊服膺。',64,'全唐诗/poet.song.47000.json','["平時出處常聯袂，文翰叨陪舊服膺。", "自信老兄憐弱弟，豈關天下少良朋。", "何時杯酒看浮白，清夜肴蔬粗滿登。", "離思隔年詩不盡，秦梁雖遠速須譍。"]'),
('ec6f85c0-ae2c-48da-a74d-0a0e093d7f1b','次韵子瞻聞不赴商幕三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','怪我辭官免入商，才疏深畏忝周行。',64,'全唐诗/poet.song.47000.json','["怪我辭官免入商，才疏深畏忝周行。", "學從社稷非源本，近讀詩書識短長。", "東舍久居如舊宅，春蔬新種似吾鄉。", "閉門已學龜頭縮，避謗仍兼雉尾藏。"]'),
('7b999225-1ade-463d-8fce-3548ae7d9f1f','次韵子瞻聞不赴商幕三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','南商西洛曾虛署，長吏居民怪不來。',64,'全唐诗/poet.song.47000.json','["南商西洛曾虛署，長吏居民怪不來。", "妄語自知當見棄，遠人未信本非才。", "厭從貧李嘲東閣，懶學諛張緩兩腮。", "知有四翁遺迹在，山中豈信少人哉。"]'),
('8aa173bc-7c6b-478b-8e97-4728b4e9794c','次韵子瞻聞不赴商幕三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','塤動篪鳴只自知，憂輕責少幸官卑。',64,'全唐诗/poet.song.47000.json','["塤動篪鳴只自知，憂輕責少幸官卑。", "聲名謾作耳中瑱，科第空收頷底髭。", "西鄙猖狂猶將將，中朝閑暇自師師。", "近成新論無人語，仰羨飛鴻兩翅差。"]'),
('990bb197-a798-4bf7-9e61-3237d1a2e780','次韵子瞻病中大雪','蘇轍','宋','宋诗','song-poetry','','[]','吾兄筆鋒雄，詩俊不可和。',192,'全唐诗/poet.song.47000.json','["吾兄筆鋒雄，詩俊不可和。", "雪中思清絕，韵惡愈難奈。", "殷勤賦黄竹，自勸飲白墮。", "言隨飛花落，意與長風簸。", "餘力遠見撩，千里寄璀瑳。", "嗟予學久廢，有類轉空磨。", "研磨久無得，安可待充貨。", "空記乘峽船，行意被摧剉。", "溟濛覆洲渚，泠冽光照坐。", "我唱君實酬，馳騁不遑卧。", "譬如逐獸盧，豈覺山徑坷。", "酒肴助喧熱，筆硯盡霑涴。", "詩詞禁推類，令肅安敢破。", "亦有同行人，牽挽赴程課。", "爾來隔秦魏，渴望等饑餓。", "徒然遇佳雪，有酒誰與賀。"]'),
('bff5d400-7c59-4543-81a6-a03ebf68f474','次韵子瞻記歲莫鄉俗三首 餽歲','蘇轍','宋','宋诗','song-poetry','','[]','周公制鄉禮，無有相通佐。',96,'全唐诗/poet.song.47000.json','["周公制鄉禮，無有相通佐。", "鼎肉送子思，烝豚出陽貨。", "交親隨高低，豈問小與大。", "自從此禮衰，伏臘有饑卧。", "鄉人慕古俗，酬酢等四坐。", "東鄰遺西舍，迭出如蟻磨。", "寧我不飲食，無爾相咎過。", "相從慶新春，顔色買愉和。"]'),
('ebc1093d-58ee-4dda-94fd-dcba96fc1b6e','次韵子瞻記歲莫鄉俗三首 別歲','蘇轍','宋','宋诗','song-poetry','','[]','富貴日月速，貧賤覺歲遲。',96,'全唐诗/poet.song.47000.json','["富貴日月速，貧賤覺歲遲。", "遲速不須問，俱作不可追。", "親舊且酣飲，送爾天北涯。", "歲歲雖無情，從我歷四時。", "酌爾一杯酒，留我壯且肥。", "長作今歲歡，勿起異日悲。", "掉頭不肯顧，曾莫與我辭。", "酒闌氣方橫，豈信從爾衰。"]'),
('fdd53008-ea90-4c40-abc9-3be622ae277c','次韵子瞻記歲莫鄉俗三首 守歲','蘇轍','宋','宋诗','song-poetry','','[]','於菟絕繩去，顧兔追龍蛇。',96,'全唐诗/poet.song.47000.json','["於菟絕繩去，顧兔追龍蛇。", "奔走十二蟲，羅網不及遮。", "嗟我地上人，豈復奈爾何。", "未去不自閑，將去乃喧嘩。", "天上驅獸官，爲君肯停檛。", "魯陽揮長戈，日車果再斜。", "釃酒勸爾醉，期爾蹔蹉跎。", "偕醉遣爾去，壽考自足誇。"]'),
('6714dbce-9763-45fb-ab3b-98e409f73714','記歲首鄉俗寄子瞻二首 踏青','蘇轍','宋','宋诗','song-poetry','','[]','江上冰消岸草青，三三五五踏青行。',128,'全唐诗/poet.song.47000.json','["江上冰消岸草青，三三五五踏青行。", "浮橋沒水不勝重，野店壓糟無復清。", "松下寒花初破萼，谷中幽鳥漸嚶鳴。", "洞門泉脈龍睛動，觀裏丹池鴨舌生。", "山下瓶罌霑稚孺，峰頭鼓樂聚簪纓。", "縞裙紅袂臨江影，青蓋驊騮踏石聲。", "曉去爭先心蕩漾，莫歸誇後醉從橫。", "最憐人散西軒靜，曖曖斜陽著樹明。"]'),
('264c4f57-68ef-44e4-a2ec-9a97eae0a1b1','記歲首鄉俗寄子瞻二首 蠶市','蘇轍','宋','宋诗','song-poetry','','[]','枯桑舒牙葉漸青，新蠶可浴日晴明。',128,'全唐诗/poet.song.47000.json','["枯桑舒牙葉漸青，新蠶可浴日晴明。", "前年器用隨手敗，今冬衣着及春營。", "傾囷計口賣餘粟，買箔還家待種生。", "不惟箱篚供婦女，亦有鉏鎛資男耕。", "空巷無人鬥容冶，六親相見爭邀迎。", "酒肴勸屬坊市滿，鼓笛繁亂倡優獰。", "蠶叢在時已如此，古人雖沒誰敢更。", "異方不見古風俗，但向陌上聞吹笙。"]'),
('bc0dfb1d-f72f-4c5d-90f6-b0cba789c293','子瞻寄示岐陽十五碑','蘇轍','宋','宋诗','song-poetry','','[]','堂上岐陽碑，吾兄所與我。',180,'全唐诗/poet.song.47000.json','["堂上岐陽碑，吾兄所與我。", "吾兄自善書，所取無不可。", "歐陽弱而立，商隠瘦且橢。", "小篆妙詰曲，波字美婀娜。", "譚藩居顔前，何類學顔頗。", "魏華自磨淬，峻秀不包裹。", "九成刻賢俊，磊落雜幺麽。", "英公與褒鄂，戈戟聞自荷。", "何年學操筆，終歲惟箭笴。", "書成亦可愛，藝業嗟獨夥。", "余雖謬學文，書字每慵墮。", "車前駕騏驥，車後繫羸跛。", "逾年學舉足，漸亦行駊騀。", "古人有遺迹，䈕短不及鏁。", "願從兄發之，洗硯處兄左。"]'),
('e489da73-a61f-4bd5-bd21-e78f7f3a01eb','畫文殊普賢','蘇轍','宋','宋诗','song-poetry','','[]','誰人畫此二菩薩，趺坐花心乘象狻。',176,'全唐诗/poet.song.47000.json','["誰人畫此二菩薩，趺坐花心乘象狻。", "弟子先後執盂缶，老僧槎牙森比肩。", "山林修道幾世劫，顔貌偉麗如開蓮。", "重崖宛轉带林樹，野水荒蕩浮雲天。", "峨眉高處不可上，下有絕澗錮九泉。", "朝陽未出白霧起，有光升天如月圓。", "靈仙居中粗可識，有類白兔依清躔。", "遊人禮拜千萬萬，迤邐漸遠如飛烟。", "五臺不到想亦爾，今之畫圖誰所傳。", "吾兄子瞻苦好異，敗繒破紙收明鮮。", "自從西行止得此，試與記錄代一觀。"]'),
('84c9f02f-9ec1-45bc-b1d6-dc3758763e59','聞子瞻重遊南山','蘇轍','宋','宋诗','song-poetry','','[]','終南重到已春回，山木緣崖綠似苔。',64,'全唐诗/poet.song.47000.json','["終南重到已春回，山木緣崖綠似苔。", "谷鳥鳴呼嘲獨往，野人笑語記曾來。", "定邀道士彈鳴鹿，誰與溪堂共酒杯。", "應有新詩還寄我，與君和取當遊陪。"]'),
('6a70ba7c-d157-48c7-9ae6-abf2dc5f314c','子瞻見許驪山澄泥硯','蘇轍','宋','宋诗','song-poetry','','[]','長安新硯石同堅，不待書求遂許頒。',64,'全唐诗/poet.song.47000.json','["長安新硯石同堅，不待書求遂許頒。", "豈必魏人勝近世，强推銅雀沒驪山。", "寒煤舒卷開雲葉，清露霑流發涕潸。", "早與封題寄書案，報君湘竹筆身班。"]'),
('8924469b-f647-4aaf-9e3b-04ab0d8f3c5a','寒食前一日寄子瞻','蘇轍','宋','宋诗','song-poetry','','[]','寒食明朝一百五，誰家冉冉尚厨烟。',64,'全唐诗/poet.song.47000.json','["寒食明朝一百五，誰家冉冉尚厨烟。", "桃花開盡葉初綠，燕子飛來體自便。", "愛客漸能陪痛飲，讀書無思懶開編。", "秦川雪盡南山出，思共肩輿看麥田。"]'),
('34db4373-4557-4be1-9eee-f7c87ba78092','大人久廢彈琴比借人雷琴以記舊曲十得三四率爾拜呈','蘇轍','宋','宋诗','song-poetry','','[]','久厭凡桐不復彈，偶然尋繹尚能存。',64,'全唐诗/poet.song.47000.json','["久厭凡桐不復彈，偶然尋繹尚能存。", "倉庚鳴樹思前歲，春水生波滿舊痕。", "泉落空巖虛谷應，珮敲清殿百官寒。", "終宵竊聽不能學，庭樹無風月滿軒。"]'),
('68b00282-aa54-4add-a6ae-fdd904289bf3','聞子瞻習射','蘇轍','宋','宋诗','song-poetry','','[]','舊讀兵書氣已振，近傳能射喜征鼖。',64,'全唐诗/poet.song.47000.json','["舊讀兵書氣已振，近傳能射喜征鼖。", "手隨樂節寧論中，箭作鴟聲不害文。", "力薄僅能勝五斗，才高應自敵三軍。", "良家六郡傳真法，馬上今誰最出羣。"]'),
('5cf03132-bc67-477c-9781-7d68c11f4807','種菜','蘇轍','宋','宋诗','song-poetry','','[]','久種春蔬旱不生，園中汲水亂瓶甖。',64,'全唐诗/poet.song.47000.json','["久種春蔬旱不生，園中汲水亂瓶甖。", "菘葵經火未出土，僮僕何朝飽食羹。", "强有人功趨節令，悵無甘雨困耘耕。", "家居閑暇厭長日，欲看年華上菜莖。"]'),
('30b58d76-a96d-40e7-b887-e0dd1c15af21','次韵子瞻題薛周逸老亭','蘇轍','宋','宋诗','song-poetry','','[]','飛鳥不知穴，山鹿不知流。',144,'全唐诗/poet.song.47000.json','["飛鳥不知穴，山鹿不知流。", "薛子善飲酒，口如汲水虬。", "吾觀腸胃間，何異族黨州。", "人滿地已盡，一介不可留。", "謂子試飲水，一酌不再求。", "謂子飲醇酒，百釂豈待酬。", "酒可水不可，其說亦已悠。", "以我視夫子，胸腹百丈幽。", "譬如田中人，視彼公與侯。", "未省破顔飲，何况裸露頭。", "鴟夷謂大瓠，皆飽安用浮。", "多少苟自適，豈害爲朋遊。"]'),
('5c93df27-4329-4b91-9164-e2a569de0e45','次韵子瞻題長安王氏中隠堂五首  其一','蘇轍','宋','宋诗','song-poetry','','[]','秦中勝岷蜀，故國不須歸。',48,'全唐诗/poet.song.47000.json','["秦中勝岷蜀，故國不須歸。", "甲第春風滿，巴山晝夢非。", "竹深啼鳥亂，花落晚蜂飛。", "我欲西還去，敲門慎勿違。"]'),
('10c9a7de-96ae-4821-bbff-a509ff42958c','次韵子瞻題長安王氏中隠堂五首  其二','蘇轍','宋','宋诗','song-poetry','','[]','唐朝卿相宅，此外更應無。',48,'全唐诗/poet.song.47000.json','["唐朝卿相宅，此外更應無。", "請看庭前樹，曾攀屋裏姝。", "流傳漸失實，遺老不禁徂。", "試問歸登物，林間翠石孤。"]'),
('e2feee80-e3c2-4f33-b0fc-ce704313cb5f','次韵子瞻題長安王氏中隠堂五首  其三','蘇轍','宋','宋诗','song-poetry','','[]','愛君高堂上，有似蜀江壖。',48,'全唐诗/poet.song.47000.json','["愛君高堂上，有似蜀江壖。", "牆外終南近，檐西太白偏。", "晚梅晴自媚，老竹暗相遷。", "未到遥聞說，吾廬安得然。"]'),
('52f10541-99a8-40d4-8d32-3bf8a11618f4','次韵子瞻題長安王氏中隠堂五首  其四','蘇轍','宋','宋诗','song-poetry','','[]','官去空留鶴，山浮不見鼇。',48,'全唐诗/poet.song.47000.json','["官去空留鶴，山浮不見鼇。", "竹林迎日凈，槐木擁亭高。", "烏噪知人至，蟬鳴覺口勞。", "誰能飲堂上，解带不穿袍。"]'),
('891d16b1-fd7f-4c23-bcf8-e07622e71a22','次韵子瞻題長安王氏中隠堂五首  其五','蘇轍','宋','宋诗','song-poetry','','[]','君看原上墓，墳盡但餘碑。',48,'全唐诗/poet.song.47000.json','["君看原上墓，墳盡但餘碑。", "誰見生前貴，塵生带下龜。", "高堂幸有酒，一飲豈論貲。", "勉强行樂耳，古人良可悲。"]'),
('36fe1bdb-0031-41c0-94c8-78363e2bb0a1','和子瞻鳳翔八觀八首 石鼓','蘇轍','宋','宋诗','song-poetry','','[]','岐山之陽石爲鼓，叩之不鳴懸無虡。',384,'全唐诗/poet.song.47000.json','["岐山之陽石爲鼓，叩之不鳴懸無虡。", "以爲無用百無直，以爲有用萬物祖。", "置身無用有用間，自託周宣誰敢侮。", "宣王沒後墳壠平，秦野蒼茫不知處。", "周人舊物惟存山，文武遺民盡囚虜。", "鼎鍾無在鑄戈戟，宮殿已倒生禾黍。", "厲宣子孫竄四方，昭穆錯亂不存譜。", "時有過客悲先王，綢繆牖戶徹桑土。", "思宣不見幸鼓存，由鼓求宣近爲愈。", "彼皆有用世所好，天地能生不能主。", "君看項籍猛如狼，身死未冷割爲脯。", "馬童楊喜豈不仁，待汝封侯非怨汝。", "何况外物固已輕，毛擒翡翠尾執麈。", "惟有蒼石於此時，獨以無用不見數。", "形骸偃蹇任苔蘚，文字皴剝困風雨。", "遭亂既以無用全，有用還爲太平取。", "古人不見見遺物，如見方召與申甫。", "文非科斗可窮詰，簡編不載無訓詁。", "字形漫汗隨石缺，蒼蛇生角龍折股。", "亦如老人遭暴橫，頤下髭禿口齒齬。", "形雖不具意可知，有云楊柳貫魴鱮。", "魴鱮豈厭居溪谷，自投網罟入君俎。", "柳條柔弱長百尺，挽之不斷細如縷。", "以柳貫魚魚不傷，貫不傷魚魚樂死。"]'),
('ad06b3f9-2162-4a3b-b60b-2ab62a073794','和子瞻鳳翔八觀八首 詛楚文','蘇轍','宋','宋诗','song-poetry','','[]','詛楚楚如桀，詛秦秦則紂。',144,'全唐诗/poet.song.47000.json','["詛楚楚如桀，詛秦秦則紂。", "桀罪使信然，紂語安足受。", "牲肥酒醪潔，夸誕鬼不祐。", "鬼非東諸侯，豈信辯士口。", "碑埋祈年下，意繞章華走。", "得楚不付孫，但爲劉季取。", "吾聞秦穆公，與晉實甥舅。", "盟鄭絕晉歡，結楚將自救。", "使秦詛楚人，晉亦議其後。", "諸侯迭相詛，禍福果誰有。", "世人不知道，好古無可否。", "何當投涇流，渾濁蓋鄙醜。"]'),
('f4f076e6-7fd8-40d7-99ca-9bb617061f6d','和子瞻鳳翔八觀八首 王維吳道子畫','蘇轍','宋','宋诗','song-poetry','','[]','吾觀天地間，萬事同一理。',228,'全唐诗/poet.song.47000.json','["吾觀天地間，萬事同一理。", "扁也工斫輪，乃知讀文字。", "我非畫中師，偶亦識畫旨。", "勇怯不必同，要以各善耳。", "壯馬脫銜放平陸，步驟風雨百夫靡。", "美人婉娩守閑獨，不出庭戶修容止。", "女能嫣然笑傾國，馬能一蹴致千里。", "優柔自好勇自强，各自勝絕無彼此。", "誰言王摩詰，乃過吳道子。", "試謂道子來，置女所挾從軟美。", "道子掉頭不肯應，剛傑我已足自恃。", "雄奔不失馳，精妙實無比。", "老僧寂滅生慮微，侍女閑潔非復婢。", "丁寧勿相違，幸使二子齒。", "二子遺迹今豈多，岐陽可貴能獨備。", "但使古壁常堅完，塵土雖積光艷長不毀。"]'),
('c103398b-2109-4e17-ae1d-ab1756a93b57','和子瞻鳳翔八觀八首 楊惠之塑維摩像','蘇轍','宋','宋诗','song-poetry','','[]','金粟如來瘦如腊，坐上文殊秋月圓。',160,'全唐诗/poet.song.47000.json','["金粟如來瘦如腊，坐上文殊秋月圓。", "法門論極兩相可，言語不復相通傳。", "至人養心遺四體，瘦不爲病肥非妍。", "誰人好道塑遺像，鮐皮束骨筋扶咽。", "兀然隠几心已滅，形如病鶴竦兩肩。", "骨節支離體疏緩，兩目視物猶烱然。", "長嗟靈運不知道，强翦美鬚插兩顴。", "彼人視身若枯木，割去右臂非所患。", "何况塑畫已身外，豈必奪爾庸自全。", "真人遺意世莫識，時有遊僧施鉢錢。"]'),
('dd7cb95a-fbaa-43ff-8695-86968139fa0b','和子瞻鳳翔八觀八首 東湖','蘇轍','宋','宋诗','song-poetry','','[]','不到東湖上，但聞東湖吟。',288,'全唐诗/poet.song.47000.json','["不到東湖上，但聞東湖吟。", "詩詞已清絕，佳境亦可尋。", "蜿蜒蒼石螭，蟠拏據湖心。", "倒腹吐流水，奔注爲重深。", "清風蕩微波，渺渺平無音。", "有鼈行在沙，有魚躍在潯。", "鼈圓如新荷，魚細如蠹蟫。", "梧桐生兩涯，蕭蕭自成林。", "孫枝復生孫，已中瑟與琴。", "秋蟲噪蜩蚻，春鳥鳴鴂鵀。", "有客來無時，濯足蔭清陰。", "自忘府中官，取酒石上斟。", "醉倒卧石上，野蟲上其襟。", "醒來不知莫，湖月翻黄金。", "油然上馬去，縱意不自箴。", "作詩招路人，行樂宜及今。", "人生不滿百，一瞬何所任。", "路人掉頭笑，去馬何駸駸。", "子有不肖弟，有冠未嘗簪。", "願身化爲線，使子爲之鍼。", "子欲烹鯉魚，爲子溉釜鬵。", "子欲枕山石，爲子求布衾。", "異鄉雖云樂，不如反故岑。", "瘦田可鑿耕，桑柘可織紝。"]'),
('4141a4fd-6977-4c8e-983a-9630c8a5775e','和子瞻鳳翔八觀八首 真興寺閣','蘇轍','宋','宋诗','song-poetry','','[]','秦川不爲廣，南山不爲高。',120,'全唐诗/poet.song.47000.json','["秦川不爲廣，南山不爲高。", "嵯峨真興閣，傑立陵風飆。", "危檻俯翔鳥，跳檐落飛猱。", "上有傲世人，身衣白鶴毛。", "下視市井喧，奔走何嗷嗷。", "蕭然倚楹嘯，遺響入雲霄。", "清風吹其裾，冉冉不可操。", "不知何所爲，豈即非盧敖。", "遊目萬里間，遠山如伏羔。", "遺語謝世俗，釣魚當釣鼇。"]'),
('767250e7-814f-474e-b941-dfcf03bfdc9d','和子瞻鳳翔八觀八首 李氏園','蘇轍','宋','宋诗','song-poetry','','[]','有客騎白駒，揚鞭入青草。',288,'全唐诗/poet.song.47000.json','["有客騎白駒，揚鞭入青草。", "悠悠無遠近，但擇林亭好。", "蕭條北城下，園號李家媼。", "繫馬古車門，隨意無灑掃。", "鳴禽驚上屋，飛蝶紛入抱。", "竹林凈如濯，流水清可澡。", "閑花不着行，香梨獨依島。", "松枝貫今昔，林影變昏早。", "草木皆蒼顔，亭宇已新造。", "臨風置酒樽，庭下取栗棗。", "今人强歡笑，古人已枯槁。", "欲求百年事，不見白鬚老。", "秦中古云樂，文武在豐鎬。", "置囿通樵蘇，養獸讓麀䴠。", "池魚躍金碧，白鳥飛紵縞。", "牛羊感仁恕，行葦亦自保。", "當年歌靈臺，後世詠魚藻。", "古詩宛猶在，遺處不可考。", "悲哉李氏末，王霸出奴皂。", "城中開芳園，城外羅戰堡。", "擊鼓鳴巨鐘，百姓皆懊惱。", "及夫聖人出，戰國卷秋潦。", "園田賦貧民，耕破園前道。", "高原種菽粟，陂澤滿粳稻。"]'),
('2bee9025-16cc-46e3-a3f1-957eea2737b3','和子瞻鳳翔八觀八首 秦穆公墓','蘇轍','宋','宋诗','song-poetry','','[]','泉上秦伯墳，下埋三良士。',124,'全唐诗/poet.song.47000.json','["泉上秦伯墳，下埋三良士。", "三良百夫特，豈爲無益死。", "當年不幸見迫脅，詩人尚記臨穴惴。", "豈如田橫海中客，中原皆漢無報所。", "秦國吞西周，康公穆公子。", "盡力事康公，穆公不爲負。", "豈必殺身從之遊，夫子乃以侯嬴所爲疑三子。", "王澤既未竭，君子不爲詭。", "三良狥秦穆，要自不得已。"]'),
('7af4d98a-7c4a-4b41-b3ba-e3ad3f1b69c3','聞子瞻將如終南太平宮谿堂讀書','蘇轍','宋','宋诗','song-poetry','','[]','爲吏豈厭事，厭事日墮媮。',240,'全唐诗/poet.song.47000.json','["爲吏豈厭事，厭事日墮媮。", "著書雖不急，實與百世謀。", "問吏所事何，過客及繫囚。", "客實虛攪人，囚有不自由。", "辦之何益增，不辦亦足憂。", "嗟此誰不能，脫去使自收。", "幽幽南山麓，下有溪水流。", "溪上亦有堂，其水可濯漱。", "終日不見人，惟有山鹿呦。", "是時夏之初，溪冷如孟秋。", "山椹黄笠展，林筍紫角抽。", "朝取筍爲羹，莫以椹爲羞。", "溪魚鯉與魴，山鳥鴬與鳩。", "食之飽且平，偃仰自佚休。", "試探篋中書，把卷揖前修。", "恍如反故鄉，親朋自相求。", "蔚如甕中糟，久熟待一篘。", "爲文若江河，豈復有刻鎪。", "尚何憶我爲，欲與我同遊。", "我雖不能往，寄詩以解愁。"]'),
('51327c55-ce95-4d9e-9f34-4fa71e8a1ecc','次韵子瞻麻田青峰寺下院翠麓亭','蘇轍','宋','宋诗','song-poetry','','[]','走馬紅塵合，開懷野寺存。',96,'全唐诗/poet.song.47000.json','["走馬紅塵合，開懷野寺存。", "南山抱村轉，渭水带沙渾。", "亭峻朱欄繞，堂虛白佛尊。", "煩襟喜修竹，倦馬樂芳蓀。", "白㲲柔隨手，清泉滿照盆。", "塵顔洗濯浄，髀肉再三捫。", "饋食青蔬軟，流匙細粟翻。", "老僧勿施敬，對客說山門。"]'),
('5562252d-e6d3-4902-be85-f6a91ce63a46','次韵子瞻宿南山蟠龍寺','蘇轍','宋','宋诗','song-poetry','','[]','谷中夜行不見月，上下不辨山與谷。',160,'全唐诗/poet.song.47000.json','["谷中夜行不見月，上下不辨山與谷。", "前呼後應行相從，山頭誰家有遺燭。", "跫跫深徑馬蹄響，落落稀星著疏木。", "行投野寺僧已眠，叩門無人狗出縮。", "號呼從者久嗔駡，老僧下牀揉兩目。", "問知官吏冒夜來，掃牀延客卧華屋。", "釜中無羹甑實盡，愧客滿盎惟脫粟。", "客來已遠睡忘覺，僧起開堂勸晨粥。", "自嗟奔走閔僧閑，偶然來過何年復。", "留詩滿壁待重遊，但恐塵埃難再讀。"]'),
('044bf315-8355-4b9f-b98a-6d88fdaad256','賦園中所有十首  其一','蘇轍','宋','宋诗','song-poetry','','[]','萱草朝始開，呀然黄鵠觜。',72,'全唐诗/poet.song.47000.json','["萱草朝始開，呀然黄鵠觜。", "仰吸日出光，口中爛如綺。", "纖纖吐鬚鬣，冉冉隨風哆。", "朝陽未上軒，粲粲幽閑女。", "美女生山谷，不解歌與舞。", "君看野草花，可以解憂悴。"]'),
('b603d149-401e-4379-955d-ad0d83ab8fa3','賦園中所有十首  其二','蘇轍','宋','宋诗','song-poetry','','[]','寒地竹不生，雖生常若病。',72,'全唐诗/poet.song.47000.json','["寒地竹不生，雖生常若病。", "斸根種幽砌，開葉何已猛。", "嬋娟冰雪姿，散亂風日影。", "繁華見孤淡，一個敵千頃。", "令人憶江上，森聳緣崖勁。", "無風籜自飄，策策鳴荒徑。"]'),
('effa566d-483c-43f4-8634-7b4660a7c1c9','賦園中所有十首  其三','蘇轍','宋','宋诗','song-poetry','','[]','蘆生井欄上，蕭騷大如竹。',72,'全唐诗/poet.song.47000.json','["蘆生井欄上，蕭騷大如竹。", "移來種堂下，何爾短局促。", "莖青甲未解，枯葉已可束。", "蘆根愛溪水，餘潤長鮮綠。", "强移性不遂，灌水惱僮僕。", "晡日下西山，汲者汗盈掬。"]'),
('c04e374d-b16b-4cf3-acc1-d6c267766d86','賦園中所有十首  其四','蘇轍','宋','宋诗','song-poetry','','[]','堂後病石榴，及時亦開花。',72,'全唐诗/poet.song.47000.json','["堂後病石榴，及時亦開花。", "身病花不齊，火候漸已差。", "芳心竟未已，新萼綴枯槎。", "誰言石榴病，乃久占年華。", "鄰家花最盛，早發豈容遮。", "殘紅已零落，婀娜子如瓜。"]'),
('04efa126-afbe-44ee-906c-0821d8faf3df','賦園中所有十首  其五','蘇轍','宋','宋诗','song-poetry','','[]','蒲桃不禁冬，屈盤似無氣。',72,'全唐诗/poet.song.47000.json','["蒲桃不禁冬，屈盤似無氣。", "春來乘盛陽，覆架青綾被。", "龍髯亂無數，馬乳垂至地。", "初如早梅酸，晚作醲酪味。", "誰能釀爲酒，爲爾架前醉。", "滿斗不與人，凉州幾時致。"]'),
('2fddee40-02e9-481e-9dd0-3021ed961a7b','賦園中所有十首  其六','蘇轍','宋','宋诗','song-poetry','','[]','室幽來客稀，塵土積不掃。',72,'全唐诗/poet.song.47000.json','["室幽來客稀，塵土積不掃。", "鄰翁笑我拙，教我種藂草。", "經霜斫爲篲，不讓秋竹好。", "始生如一毛，張王忽侵道。", "鉏耰禁芟斸，愛惜待枯槁。", "有用皆勿輕，吾師灌園老。"]'),
('5b40c623-8786-42be-a5fe-b13f61e1c7b4','賦園中所有十首  其七','蘇轍','宋','宋诗','song-poetry','','[]','吾兄客關中，果臝施吾宇。',72,'全唐诗/poet.song.47000.json','["吾兄客關中，果臝施吾宇。", "兄雖未得還，我豈如婦女。", "呦呦感微物，涕泗若零雨。", "但愛果臝莖，屈曲上牆堵。", "朝見緣牆頭，莫已過牆去。", "物生隨年華，還日何足數。"]'),
('fbb0d4fb-ddfe-4bea-97ad-61921c889f97','賦園中所有十首  其八','蘇轍','宋','宋诗','song-poetry','','[]','牽牛非佳花，走蔓入荒榛。',72,'全唐诗/poet.song.47000.json','["牽牛非佳花，走蔓入荒榛。", "開花荒榛上，不見細蔓身。", "誰翦薄素紗，浸之青藍盆。", "水淺浸不盡，下餘一寸銀。", "嗟爾脆弱草，豈能凌霜晨。", "物性有稟受，安問秋與春。"]'),
('65a0e539-167c-48d2-bcb5-313896b02bf1','賦園中所有十首  其九','蘇轍','宋','宋诗','song-poetry','','[]','南園地性惡，雙柏不得長。',72,'全唐诗/poet.song.47000.json','["南園地性惡，雙柏不得長。", "蓬麻春始生，今已滿一丈。", "柏生嗟幾年，失意自悽愴。", "有子壓枝低，已老非少壯。", "尤柏柏已冤，尤地亦恐妄。", "兩既無所尤，高枝幾時放。"]'),
('3ab8036d-5c15-465c-a074-16546929ecd9','賦園中所有十首  其一○','蘇轍','宋','宋诗','song-poetry','','[]','葵花開已闌，結子壓枝重。',72,'全唐诗/poet.song.47000.json','["葵花開已闌，結子壓枝重。", "長條困風雨，倒卧枕丘壟。", "憶初始放花，岌岌旌節聳。", "得時能幾時，狼籍成荒冗。", "浮根不任雪，採剝收遺種。", "未忍焚枯莖，積疊牆角擁。"]'),
('0e7e2e29-4083-41fe-986e-dde91e3e7791','和子瞻記夢二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','兄從南山來，夢我南山下。',108,'全唐诗/poet.song.47000.json','["兄從南山來，夢我南山下。", "探懷出詩卷，卷卷盈君把。", "詩詞古人似，弟則吾弟也。", "相與千里隔，安得千里馬。", "携手上南山，不知今乃夜。", "晨鷄隔牆唱，欹枕窗月亞。", "百語記一詞，秋菊悲蛩吒。", "此語鮑謝流，平日我不暇。", "我本無此詩，嗟此誰所借。"]'),
('c40159b0-1601-475e-a5e3-114b9c1b5283','和子瞻記夢二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','蟋蟀感秋氣，夜吟抱菊根。',72,'全唐诗/poet.song.47000.json','["蟋蟀感秋氣，夜吟抱菊根。", "霜降菊叢折，寸根安可存。", "耿耿荒苗下，唧唧空自論。", "不敢學蝴蝶，菊盡兩翅翻。", "蟲凍不絕口，菊死不絕芬。", "志士豈棄友，列女無兩婚。"]'),
('02ec5885-4585-458d-b300-72ec61b8652e','次韵子瞻題岐山周公廟','蘇轍','宋','宋诗','song-poetry','','[]','周人尚記有周公，禾黍離離下有宮。',64,'全唐诗/poet.song.47000.json','["周人尚記有周公，禾黍離離下有宮。", "破豆烝豚非以報，野巫長跪若爲通。", "山圍棟宇泉流近，鳳去梧桐落葉濛。", "有客賦詩題屋壁，二南猶自有遺風。"]'),
('f028a816-d22a-4699-a08a-b92d2c1073b2','次韵子瞻題扶風道中天花寺小亭','蘇轍','宋','宋诗','song-poetry','','[]','客車來不息，轍迹知成溝。',48,'全唐诗/poet.song.47000.json','["客車來不息，轍迹知成溝。", "莫怪慵登寺，猶宜賞舉頭。", "獨遊知憶弟，望遠勝登樓。", "處處題詩遍，篇篇誰爲收。"]'),
('02167c95-530e-4651-8264-6f968d37a2d1','次韵子瞻南溪避世堂','蘇轍','宋','宋诗','song-poetry','','[]','柱杖行窮徑，圍堂尚有林。',96,'全唐诗/poet.song.47000.json','["柱杖行窮徑，圍堂尚有林。", "飛禽不驚處，萬竹正當心。", "虎嘯風吹籟，霜多蟬病瘖。", "獸驕從不避，人到記由今。", "未暇終身住，聊爲半日吟。", "青松可絕食，黄葉不須衾。", "偶到初迷路，將還始覺深。", "堂中有幽士，插髻尚餘簪。"]'),
('c8464006-59e7-4836-b270-811db448ef15','和子瞻三遊南山九首 樓觀','蘇轍','宋','宋诗','song-poetry','','[]','神仙避世守關門，一世沉埋百世尊。',64,'全唐诗/poet.song.47000.json','["神仙避世守關門，一世沉埋百世尊。", "舊宅居人無姓尹，深山道士即爲孫。", "天寒遊客常逢雪，日暮歸鴉自識村。", "君欲留身記幽寂，直將山外比羌渾。"]'),
('d1026bf8-d8c3-4882-975f-8e0eda9d37b0','和子瞻三遊南山九首 五郡','蘇轍','宋','宋诗','song-poetry','','[]','蜀人不信秦川好，食蔗從梢未及甘。',64,'全唐诗/poet.song.47000.json','["蜀人不信秦川好，食蔗從梢未及甘。", "當道沙塵類河北，依山水竹似江南。", "觀形隨阜飲溪鹿，雲氣侵山食葉蠶。", "猶有道人迎客笑，白鬚黄袖豈非聃。"]'),
('5ca714b3-c498-4953-9f77-d9ece5e38f91','和子瞻三遊南山九首 傳經臺','蘇轍','宋','宋诗','song-poetry','','[]','輪扁不能令子巧，老聃雖智若爲傳。',32,'全唐诗/poet.song.47000.json','["輪扁不能令子巧，老聃雖智若爲傳。", "遺經尚在臺如故，弟子今無似喜賢。"]'),
('9b6b8ba4-983a-492c-8147-6d6aa9b3467a','和子瞻三遊南山九首 大秦寺','蘇轍','宋','宋诗','song-poetry','','[]','大秦遥可說，高處見秦川。',48,'全唐诗/poet.song.47000.json','["大秦遥可說，高處見秦川。", "草木埋深谷，牛羊散晚田。", "山平堪種麥，僧魯不求禪。", "北望長安市，高城遠似烟。"]'),
('fcbbd314-7a61-4e71-8343-105fc5eba4ed','和子瞻三遊南山九首 仙遊潭五首 其一','蘇轍','宋','宋诗','song-poetry','','[]','潭深不可涉，潭小不通船。',48,'全唐诗/poet.song.47000.json','["潭深不可涉，潭小不通船。", "路斷遊人止，龍藏白沫旋。", "翦藤量水短，插石置橋堅。", "橋外居民少，躬耕不用錢。"]'),
('21d6cbdf-bd4f-4439-b863-5dea019e0f28','和子瞻三遊南山九首 仙遊潭五首 其二','蘇轍','宋','宋诗','song-poetry','','[]','澄潭下無底，將渡又安能。',48,'全唐诗/poet.song.47000.json','["澄潭下無底，將渡又安能。", "慣上橫空木，輕生此寺僧。", "曉魚聞考考，石塔見層層。", "不到殊非惡，他年記未曾。"]'),
('a299b9b0-5c43-4028-94d2-62e3735283c1','和子瞻三遊南山九首 仙遊潭五首 其三','蘇轍','宋','宋诗','song-poetry','','[]','君看潭北寺，何用減潭南。',48,'全唐诗/poet.song.47000.json','["君看潭北寺，何用減潭南。", "不到還能止，重來獨未厭。", "荒凉增客思，貧病覺僧慚。", "飲水寒難忍，誰言栢子甘。"]'),
('5280c8b5-19b5-47a9-8201-07ac79e1b970','和子瞻三遊南山九首 仙遊潭五首 其四','蘇轍','宋','宋诗','song-poetry','','[]','扶風貴公子，早歲伴山家。',48,'全唐诗/poet.song.47000.json','["扶風貴公子，早歲伴山家。", "吹笛墮秋葉，讀書隨曉鴉。", "業成心自叛，學苦我長嗟。", "石室非人住，窮山雪似沙。"]'),
('75b2a2aa-8f43-4f19-a8dd-8bea32517b33','和子瞻三遊南山九首 仙遊潭五首 其五','蘇轍','宋','宋诗','song-poetry','','[]','洞門蒼蘚合，逼仄不容身。',48,'全唐诗/poet.song.47000.json','["洞門蒼蘚合，逼仄不容身。", "傳有虛明處，中藏窈窕人。", "吹笙橋上月，拾翠洞南春。", "往往來山下，蕭然雨灑塵。"]'),
('d536ffbb-e517-48fc-83a2-a8f0c699d2e2','和子瞻調水符','蘇轍','宋','宋诗','song-poetry','','[]','多防出多欲，欲少防自簡。',72,'全唐诗/poet.song.47000.json','["多防出多欲，欲少防自簡。", "君看山中人，老死竟誰謾。", "渴飲吾井泉，饑食甑中飯。", "何用費卒徒，取水負瓢罐。", "置符未免欺，反覆慮多變。", "授君無憂符，階下泉可嚥。"]'),
('5c5bd58d-83d5-4268-8e3a-08b4a6b95c7f','次韵子瞻招隠亭','蘇轍','宋','宋诗','song-poetry','','[]','隠居吾未暇，何暇勸夫人。',96,'全唐诗/poet.song.47000.json','["隠居吾未暇，何暇勸夫人。", "試飲此亭酒，自慚纓上塵。", "林深開翠帟，岸斷峻嚴闉。", "送雪村酤釅，迎陽鳥哢新。", "竹風吹斷籟，湖月轉車輪。", "霜葉飛投坐，山梅重壓巾。", "欲居常有待，已失嘆無因。", "古語君看取，聲名本實賓。"]'),
('79708961-e3f9-4c10-87a1-7468cda5a367','次韵子瞻凌虛臺','蘇轍','宋','宋诗','song-poetry','','[]','棄我謂我遠，求我謂我還。',120,'全唐诗/poet.song.47000.json','["棄我謂我遠，求我謂我還。", "我一爾則二，視此臺上山。", "山高上干天，獨不照我顔。", "無乃我自蔽，誰謂山則慳。", "遠望不見趾，近視不得鬟。", "山實未始變，任子自擇刪。", "北風吹南崖，山上秋葉斑。", "道遠又寒苦，皴裂辭難攀。", "晴空卷朝雲，照夜霜月彎。", "强爾登此臺，免爾超闠闤。"]'),
('0ef0491e-a357-47df-92e0-20ae877b6719','次韵子瞻竹𪕋','蘇轍','宋','宋诗','song-poetry','','[]','野食不穿囷，溪飲不盜盎。',96,'全唐诗/poet.song.47000.json','["野食不穿囷，溪飲不盜盎。", "嗟𪕋獨何罪，膏血自爲罔。", "陰陽造百物，偏此愚不爽。", "肥癡與瘦黠，稟受不相髣。", "王孫處深谷，小若兒在襁。", "超騰避彈射，將中還復枉。", "一朝受羈緤，冠带相賓饗。", "愚死智亦擒，臨食抵吾掌。"]'),
('8c212c36-8a7f-470d-ac24-181bb61a74cf','次韵子瞻渼陂魚','蘇轍','宋','宋诗','song-poetry','','[]','渼陂霜落魚可掩，枯芡破盤蒲折劍。',160,'全唐诗/poet.song.47000.json','["渼陂霜落魚可掩，枯芡破盤蒲折劍。", "巨斧敲冰已暗知，長叉刺浪那容閃。", "鯨孫蛟子誰復惜，朱鬣金鱗漫如染。", "邂逅相遭已失津，偶然一掉猶思塹。", "嗟君遊宦久羊炙，有似遠行安野店。", "得魚未熟口流涎，豈有哀矜自欺僭。", "人生飽足百事已，美味那令一朝欠。", "少年勿笑貪匕筯，老病行看費針砭。", "羊生懸骨空自饑，伯夷食菜有不贍。", "清名驚世不益身，何異飲醯徒酷釅。"]'),
('9a3f1feb-7069-41eb-bc92-8457c6835ea7','和子瞻讀道藏','蘇轍','宋','宋诗','song-poetry','','[]','道書世多有，吾讀老與莊。',120,'全唐诗/poet.song.47000.json','["道書世多有，吾讀老與莊。", "老莊已云多，何况其駢傍。", "所讀嗟甚少，所得半已强。", "有言至無言，既得旋自忘。", "譬如飲醇酒，已醉安用漿。", "昔者惠子死，莊子哭自傷。", "微言不復知，言之使誰聽。", "哭已輒復笑，不如斂此藏。", "脂牛雜肥羜，烹熟有不嘗。", "安得西飛鴻，送弟以與兄。"]'),
('7eff3778-33ad-4510-81eb-078052defc3d','次韵子瞻南溪微雪','蘇轍','宋','宋诗','song-poetry','','[]','南溪夜雪曉來霽，有客晨遊酒未消。',64,'全唐诗/poet.song.47000.json','["南溪夜雪曉來霽，有客晨遊酒未消。", "風泛餘花來逐馬，光浮斷澗不知橋。", "山寒凍合行人息，醉熟賓歡舞意囂。", "歸騎相將踏瑶玉，嗅林閑認早梅條。"]'),
('4da12618-c01a-4f38-8213-b0e7d44842b1','和子瞻司竹監燒葦園因獵園下','蘇轍','宋','宋诗','song-poetry','','[]','駿馬七尺行馮馮，曉出射獸霜爲冰。',320,'全唐诗/poet.song.47000.json','["駿馬七尺行馮馮，曉出射獸霜爲冰。", "荻園斫盡有枯枿，束茅吹火初如燈。", "乍分乍合勢開展，蒼烟被野風騰騰。", "黄狐驚顧嘯儔侶，飛鳥先起如蒼蠅。", "須臾立旆布行伍，有似修蟒橫岡陵。", "蒼鷹猛獸出前後，缺處已挂黄麻罾。", "回風忽作火力怒，平地一卷無疆塍。", "商辛不出抱寶死，曹瞞逸去燋其肱。", "投身誤喜脫灰燼，闖首旋已遭侵凌。", "何人上馬氣吞虎，狐帽壓耳皮蒙膺。", "開弓徐射疊雙兔，擁馬歡叫驚未曾。", "舉鞭一麾百夫進，擊鼓再發箭舉掤。", "去如飛虻中如電，獲若雨獸膏流澠。", "肉分麾下飽壯士，皮與公子留縑繒。", "縱橫分裂惠村塢，尚有磊落載後乘。", "吾兄善射久無敵，是日斂手稱不能。", "憑鞍縱馬聊自適，酒後醉語誰能譍。", "健兒擊搏信可樂，主將雄猛今誰勝。", "胸中森列萬貔虎，嗟世但以文儒稱。", "安得强弓傅長箭，使射蔽日垂天鵬。"]'),
('f321521c-28b6-4815-8422-0d4bf9533cc9','木山引水二首  其一','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','引水穿牆接竹梢，谷藏峰底大容瓢。',64,'全唐诗/poet.song.47000.json','["引水穿牆接竹梢，谷藏峰底大容瓢。", "將流旋滴廬山瀑，已盡還來海上潮。", "亂點落池驚睡覺，半山含潤沃心焦。", "瓦盆一斛何勝滿，溢去猶能浸菊苗。"]'),
('3457b649-7c84-47f0-8ec7-f2dd86979c77','木山引水二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','檐下枯槎拂荻梢，山川迤邐費公瓢。',64,'全唐诗/poet.song.47000.json','["檐下枯槎拂荻梢，山川迤邐費公瓢。", "幽泉細細流巖鼻，盆水瀰瀰漲海潮。", "但愛堅如湖上石，誰憐收自竈中焦。", "蒼崖寒溜須佳蔭，尚少冬青石繭苗。"]'),
('5cf83e0e-12cd-4ccc-989f-cca8078b5e0a','興州新開古東池','蘇轍','宋','宋诗','song-poetry','','[]','山繞興州萬疊青，池開近郭百泉并。',64,'全唐诗/poet.song.47000.json','["山繞興州萬疊青，池開近郭百泉并。", "昔年種柳人安在，累歲開花藕自生。", "波暖跳魚聞樂喜，人來野鴨望船鳴。", "西還過此須終日，爲問使君行未行。"]'),
('1350d4d7-486f-494f-a9d7-e19028c33004','子瞻喜雨亭北隋仁壽宮中怪石','蘇轍','宋','宋诗','song-poetry','','["\u592a\u6e56"]','仁壽宮中穭穀生，太湖蒼石草間橫。',64,'全唐诗/poet.song.47000.json','["仁壽宮中穭穀生，太湖蒼石草間橫。", "興衰換世身猶在，南北從人事已輕。", "累石作臺秋蘚上，鑿汧通水細渠清。", "三年此亦非公有，空使他年記姓名。"]'),
('dc397d7f-5927-41e3-a170-e6901c450d27','用林侄韵賦雪','蘇轍','宋','宋诗','song-poetry','','[]','密雪來何晚，窮冬候欲差。',240,'全唐诗/poet.song.47000.json','["密雪來何晚，窮冬候欲差。", "投空落細米，布地凈平沙。", "繚繞飛相著，重仍積暗加。", "雨微花破碎，風細脚傾斜。", "次第來如摻，冥濛墮不嘩。", "燖鵝吹勁鞴，秀葦拂輕淚。", "畫字飄還沒，團毬暖旋窊。", "出鹽東海若，鍊石古皇媧。", "翻簸騰歸騎，紛飄集晚鴉。", "庭梅辨紅萼，壠麥覆黄芽。", "撥砌求新藥，尋蹤射伏䴥。", "埋樓平盡脊，集樹短留槎。", "亂下曾何擇，平鋪欲盡遮。", "欺貧寒入褐，惱客重添車。", "積素聊成燭，烹甘强試茶。", "病僧添曉鉢，老令放晨衙。", "融液曾何有，鮮明竟不奢。", "積多還避井，化早發從畬。", "溜滴檐垂箸，行觀逕轉蛇。", "誰能相就醉，都市酒容賒。"]'),
('5b896cef-a662-416e-a6a0-d4479253799b','送張唐英監閬州稅','蘇轍','宋','宋诗','song-poetry','','[]','閬中雖近蜀，監稅本閑官。',48,'全唐诗/poet.song.47000.json','["閬中雖近蜀，監稅本閑官。", "豈足淹賢俊，聊應長羽翰。", "讀書心健否，答策意何闌。", "未可厭畋獵，田中有走貆。"]'),
('e6d78056-6d44-4ba6-833a-2ef36449ce03','送張師道楊壽祺二同年','蘇轍','宋','宋诗','song-poetry','','[]','故國多賢俊，登科並弟兄。',72,'全唐诗/poet.song.47000.json','["故國多賢俊，登科並弟兄。", "重來舊游處，兩見近題名。", "冉冉須堪把，駸駸歲可驚。", "孤轅已南向，疋馬復西征。", "入峽猿應苦，還荆雁已鳴。", "喜從元帥幕，官職漸崢嶸。"]'),
('e356e77a-ab83-4d75-8907-742bf686f28c','送家定國同年赴永康掾','蘇轍','宋','宋诗','song-poetry','','[]','清慎岷山掾，登科已七年。',48,'全唐诗/poet.song.47000.json','["清慎岷山掾，登科已七年。", "迎親就魚稻，爲吏擇林泉。", "去騎關中熱，歸心沫水鮮。", "官閑幸可樂，記買鷓鴣煎。"]'),
('7d79c511-9549-4541-9c9f-a665c9a87c1c','送霸州司理翟曼','蘇轍','宋','宋诗','song-poetry','','[]','大梁能賦客，邊郡繫囚曹。',48,'全唐诗/poet.song.47000.json','["大梁能賦客，邊郡繫囚曹。", "官職不相稱，聲名終自高。", "試觀爲吏苦，應過讀書勞。", "努力事初宦，尺絲無厭繅。"]'),
('55cc73a8-fd0b-4736-85d2-f2e804db51f4','送道士楊見素南遊','蘇轍','宋','宋诗','song-poetry','','[]','黄河春漲入隋溝，往意隨波日夜流。',64,'全唐诗/poet.song.47000.json','["黄河春漲入隋溝，往意隨波日夜流。", "萬里尋山如野鶴，一身浮水似輕鷗。", "湖風送客那論驛，嶽寺留人暗度秋。", "遲子北歸來見我，携琴委曲記深幽。"]'),
('493ad4dc-c4d5-469d-83fd-6331b1c7ac35','利路提刑亡伯郎中挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','好學先鄉黨，登科復妙年。',48,'全唐诗/poet.song.47000.json','["好學先鄉黨，登科復妙年。", "誰爲耆舊傳，最處縉紳先。", "淪謝今亡矣，風流孰繼焉。", "魂歸食里社，世世仰仁賢。"]'),
('ad61b6d4-4b92-4972-bbb8-4f4f4ceee84f','利路提刑亡伯郎中挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','["\u8861\u5c71"]','晚歲官仍困，終身耻自言。',48,'全唐诗/poet.song.47000.json','["晚歲官仍困，終身耻自言。", "廉明漢循吏，仁愛鄭公孫。", "赤縣朝稱理，衡山德共尊。", "遠人應罷市，處處有遺恩。"]'),
('c37df18d-ab00-4b22-a73e-8155b67c5b57','亡伯母同安縣君楊氏挽詞','蘇轍','宋','宋诗','song-poetry','','[]','德盛諸楊族，賢宜伯父家。',48,'全唐诗/poet.song.47000.json','["德盛諸楊族，賢宜伯父家。", "周姜職蘋藻，歜母事桑麻。", "大邑移封近，陰堂去日賒。", "空餘鏡奩在，時出舊笄珈。"]'),
('9c68b46b-0fc4-4a77-8f5e-5b19a75997c3','北京送孫曼叔屯田權三司開坼司','蘇轍','宋','宋诗','song-poetry','','[]','人生不願才，才士困奔走。',120,'全唐诗/poet.song.47000.json','["人生不願才，才士困奔走。", "君爲大農屬，求暇更能否。", "自我遊魏博，相識恨未久。", "誰言但傾蓋，信有勝白首。", "清晨坐風觀，落日語凉牖。", "棋精動如律，弓健不論斗。", "旁觀我不能，晤語君見受。", "秋風起沙漠，凄雨濕征袖。", "送行欲汲汲，富貴恐君後。", "將去聊遲遲，已遠悲朋友。"]'),
('9c3894ce-9303-4280-a73c-bd470f95434c','和强至太博小飲','蘇轍','宋','宋诗','song-poetry','','[]','誰能飲酒如傾水，醉倒坐中扶不起。',64,'全唐诗/poet.song.47000.json','["誰能飲酒如傾水，醉倒坐中扶不起。", "形骸外物已如遺，升斗任君無復避。", "霜梨冰脆寒侵齒，未盡一杯先已醉。", "强將文字笑紅裙，冷淡爲歡何足貴。"]'),
('70481351-6c60-4e95-97d3-1b56a51498f6','和强君瓦亭','蘇轍','宋','宋诗','song-poetry','','[]','君爲魏博三年客，日有江湖萬里心。',64,'全唐诗/poet.song.47000.json','["君爲魏博三年客，日有江湖萬里心。", "蹔得野亭留馬足，强循疏柳步堤陰。", "無人携手共吳語，得意摇頭時越吟。", "何日東郊過微雨，並騎鞍馬去同尋。"]'),
('2a23f86e-5187-4ac6-b9d8-833bea0695af','中秋夜八絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','長空開積雨，清夜流明月。',24,'全唐诗/poet.song.47000.json','["長空開積雨，清夜流明月。", "看盡上樓人，油然就西沒。"]'),
('a58fcdfb-b661-47b6-8f36-0c47489c3de2','中秋夜八絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','誰遣常時月，偏從此夜明。',24,'全唐诗/poet.song.47000.json','["誰遣常時月，偏從此夜明。", "暗添珠百倍，潛感兔多生。"]'),
('e2f2ec54-e618-4c68-916c-5edf6bcb153f','中秋夜八絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','欲見初容燭，將升尚有星。',24,'全唐诗/poet.song.47000.json','["欲見初容燭，將升尚有星。", "漸高圍漸小，雲外轉亭亭。"]'),
('c83e05cb-1165-4781-ac71-a4c72ca32784','中秋夜八絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','明入庭陰白，寒侵酒氣微。',24,'全唐诗/poet.song.47000.json','["明入庭陰白，寒侵酒氣微。", "夜深看更好，樓上漸人稀。"]'),
('71477cc3-0789-4fd8-b2a0-c8a35aeb4bc1','中秋夜八絕  其五','蘇轍','宋','宋诗','song-poetry','','[]','浮光看不定，重露試還無。',24,'全唐诗/poet.song.47000.json','["浮光看不定，重露試還無。", "影翻狂舞客，明誤已棲烏。"]'),
('35f52699-feca-4507-84e8-b70c87312b5f','中秋夜八絕  其六','蘇轍','宋','宋诗','song-poetry','','[]','巧轉上人衣，徐行度樓角。',24,'全唐诗/poet.song.47000.json','["巧轉上人衣，徐行度樓角。", "河漢冷無雲，冥冥獨飛鵲。"]'),
('49a04c57-b23b-4123-be8d-5cb4322ceb49','中秋夜八絕  其七','蘇轍','宋','宋诗','song-poetry','','[]','猿狖號枯木，魚龍泣夜潭。',24,'全唐诗/poet.song.47000.json','["猿狖號枯木，魚龍泣夜潭。", "行人已天北，思婦隔江南。"]'),
('5be00588-a0f9-4b4d-ad26-43e1d72ec69d','中秋夜八絕  其八','蘇轍','宋','宋诗','song-poetry','','[]','看久須扶立，行貪遂失歸。',24,'全唐诗/poet.song.47000.json','["看久須扶立，行貪遂失歸。", "誰能終不睡，爛醉羽觴飛。"]'),
('3cd95387-687e-4b51-a771-03bec9833304','次韵王君貺尚書會六同年','蘇轍','宋','宋诗','song-poetry','','[]','有美佳賓賢主人，布衣曾共脫京塵。',64,'全唐诗/poet.song.47000.json','["有美佳賓賢主人，布衣曾共脫京塵。", "歡來未覺歲華晚，醉後能令秋氣春。", "發譽早同初宦日，收功終藉老成身。", "他年此會應圖畫，傳入誰家屏障新。"]'),
('3760b52d-d965-4eb1-a2d7-63d9df4b5841','王公生日','蘇轍','宋','宋诗','song-poetry','','[]','純陰十月晚，勁氣肅羣驕。',144,'全唐诗/poet.song.47000.json','["純陰十月晚，勁氣肅羣驕。", "惟有喬松在，長看積雪消。", "生賢稟真性，特立冠當朝。", "早歲初成賦，羣雄已失標。", "治才精破竹，廷論壯生飆。", "博士皆推賈，宣皇重試蕭。", "周旋窮政體，出入解心焦。", "九列高稱冠，三台豈足超。", "論功歸潁霸，舉相待虞姚。", "驥騁經新卧，弓强發久弨。", "百年時節在，四海衆心翹。", "當見飛中使，齎金賜此朝。"]'),
('14265313-6681-4ad6-9f06-5fbe5bac9e71','次韵姚孝孫判官見還岐梁唱和詩集','蘇轍','宋','宋诗','song-poetry','','[]','伯氏文章豈敢知，岐梁偶有往還詩。',64,'全唐诗/poet.song.47000.json','["伯氏文章豈敢知，岐梁偶有往還詩。", "自憐兄力能兼弟，誰肯塤終不聽箎。", "西虢春游池百頃，南溪秋入竹千枝。", "恨君曾是關中吏，屬和追陪失此時。"]'),
('bd037041-7d14-4d72-b0bf-f806780b6e79','次韵王臨太博馬上','蘇轍','宋','宋诗','song-poetry','','[]','冬晚霜露重，城遥鞍馬勞。',48,'全唐诗/poet.song.47000.json','["冬晚霜露重，城遥鞍馬勞。", "徒知事奔走，曾未補毫毛。", "水旱嗟嚬蹙，瘡痍費抑搔。", "莫歸何暇食，堆桉簿書高。"]'),
('60d27ef3-c5f0-4064-827f-7ac0c72e199d','次韵王君北都偶成三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','河轉金堤近，天高魏闕新。',48,'全唐诗/poet.song.47000.json','["河轉金堤近，天高魏闕新。", "千夫奉儒將，百獸伏麒麟。", "校獵沙場莫，談兵玉帳春。", "關南知不遠，誰試問蕃鄰。"]'),
('f3d6349a-c102-4df4-87c3-6efefb3ece10','次韵王君北都偶成三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','天寶亂已定，河壖兵更多。',48,'全唐诗/poet.song.47000.json','["天寶亂已定，河壖兵更多。", "故城埋白骨，遺俗喜長戈。", "卧獸常思肉，奔鯨不受羅。", "縱橫竟安在，唯見冢嵯峨。"]'),
('3916fa74-c3f5-4827-a25c-33ca9701c589','次韵王君北都偶成三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','禁籞封金殿，清河貫石門。',48,'全唐诗/poet.song.47000.json','["禁籞封金殿，清河貫石門。", "時平餘古木，兵散有空屯。", "形勝山圍闊，蕃宣海內尊。", "川原不論頃，雲夢可勝吞。"]'),
('a3c4f637-8b6c-4991-a35c-129ea4470a88','次韵沈立少卿白鹿','蘇轍','宋','宋诗','song-poetry','','[]','白鹿何年養，驚猜未肯馴。',96,'全唐诗/poet.song.47000.json','["白鹿何年養，驚猜未肯馴。", "軒除非本性，飲食强依人。", "照影冰浮水，飛毛雪灑塵。", "獨游應已倦，忽見乍疑神。", "野色明幽步，烟蕪薦卧身。", "異姿人共愛，清意爾誰親。", "日暖山苗熟，風微澗草春。", "何緣解韁縶，奔放任天真。"]'),
('67dc9e0a-73c1-4e84-979b-953c040943e5','送陳安期都官出城馬上','蘇轍','宋','宋诗','song-poetry','','[]','城中二月不知春，唯有東風滿面塵。',64,'全唐诗/poet.song.47000.json','["城中二月不知春，唯有東風滿面塵。", "歸意已隨行客去，流年驚見柳條新。", "簿書填委休何日，學問榛蕪愧古人。", "一頃稻田三畝竹，故園何負不收身。"]'),
('47754961-5480-450e-8332-631d6994eb2c','登上水關','蘇轍','宋','宋诗','song-poetry','','[]','淇水沄沄入禁城，城樓中斷過深清。',64,'全唐诗/poet.song.47000.json','["淇水沄沄入禁城，城樓中斷過深清。", "空郊南數牛羊下，落日迴瞻觀闕明。", "歲月逼人行老大，江湖發興感平生。", "畫舫早晚籠新屋，慰意來看水面平。"]'),
('01731363-3a2b-4115-a045-17936c85e1ea','寒食贈遊壓沙諸君','蘇轍','宋','宋诗','song-poetry','','[]','城南壓沙古河淤，沙上種梨千萬株。',224,'全唐诗/poet.song.47000.json','["城南壓沙古河淤，沙上種梨千萬株。", "隆冬十月我獨往，風吹葉盡枝條疏。", "老僧屈指數春候，却後百日花當蘇。", "微風細雨膏潤足，枝頭萬萬排明珠。", "齊開競發不知數，照曜冰雪明村墟。", "此時官閑得遊賞，長堤平穩宜驂駒。", "寺門古木芽葉動，倉庚布穀相和呼。", "及時行樂不可緩，歲長春短花須臾。", "僧言我意兩相值，欲往屢已脂吾車。", "今朝寒食烟火斷，薄雲蔽日風沙除。", "此花久已待我至，况有朋友相携扶。", "來邀反覆不能往，豈獨負君花已辜。", "諸君高邁足才思，佐酒况得萬玉奴。", "坐中未醉慎無起，倒戴當使山公如。"]'),
('681b2412-3bff-45e3-9ed0-0a5c237ce202','明日安厚卿强幾聖復召飲醉次前韵','蘇轍','宋','宋诗','song-poetry','','[]','芳樽酌水清無淤，梨園著雪迷根株。',224,'全唐诗/poet.song.47000.json','["芳樽酌水清無淤，梨園著雪迷根株。", "鄴官士女喜行樂，坐上醉客誰親疏。", "倦遊不知歲月過，痛飲漸覺筋骸蘇。", "風吹落片亂鵝毳，雨結細實駢明珠。", "雲屯冰積動論頃，誰信城郭涵村墟。", "坐觀明媚低照席，行看繁鬧橫遮駒。", "我貧不辦供酒炙，側耳日聽交朋呼。", "無端人事巧拘束，曾不見置閑須臾。", "長鯨渴水求入海，老驥伏櫪思就車。", "清明未過春未老，寒食豈必節與除。", "二君爲我重置酒，席上醉倒交相扶。", "歡娛安用苦酬酢，叫嘯不畏相罪辜。", "昏然已覺萬物小，下視吏役真婢奴。", "請君數具牛酒費，此外百事何能如。"]'),
('21bbc434-7e6b-455c-af81-798ee3a021db','次韵柳子玉郎中見寄','蘇轍','宋','宋诗','song-poetry','','[]','新年始是識君初，顧我塵埃正滿裾。',64,'全唐诗/poet.song.47000.json','["新年始是識君初，顧我塵埃正滿裾。", "談辯未容朝夕聽，情親空愧往還書。", "久聞筆陣無前敵，更擬詩壇託後車。", "待得入城應少暇，相從有約定何如。"]'),
('433d62bf-f5e4-46dc-ba46-49c1df8f99b9','秀州僧本瑩凈照堂','蘇轍','宋','宋诗','song-poetry','','[]','有僧訪我携詩卷，自說初成凈照堂。',64,'全唐诗/poet.song.47000.json','["有僧訪我携詩卷，自說初成凈照堂。", "求得篇章書壁素，不論塵土漬衣黄。", "故山別後成新歲，歸夢春來繞舊房。", "看取盈編定何益，客來無語但循牆。"]'),
('b4cdc799-f14a-40e5-8edd-7ff0747af0a3','京師送王頤殿丞','蘇轍','宋','宋诗','song-poetry','','[]','憶遊長安城，皆飲毋卿宅。',192,'全唐诗/poet.song.47000.json','["憶遊長安城，皆飲毋卿宅。", "身雖坐上賓，心是道路客。", "笑言安能久，車馬就奔迫。", "城南南山近，勝絕聞自昔。", "徘徊竟莫往，指點煩鞭策。", "道傍古龍池，深透河渭澤。", "山行吾不能，愧此纔咫尺。", "壯哉誰開鑿，千頃如一席。", "參差山麓近，滉蕩波光射。", "君時在池上，俗事厭紛劇。", "望門不敢叩，恐笑塵土迹。", "自從旅京城，所向愈無適。", "君來曾未幾，已復向南國。", "扁舟出淮汴，唯見江海碧。", "野人處城市，長願有羽翮。", "脫身相從遊，未果聊自責。"]'),
('52d794f0-b486-4fde-b54a-a8f990ff93a2','石蒼舒醉墨堂','蘇轍','宋','宋诗','song-poetry','','[]','石君得書法，弄筆歲月久。',72,'全唐诗/poet.song.47000.json','["石君得書法，弄筆歲月久。", "經營妙在心，舒卷功隨手。", "惟茲逸羣氣，扶駕須斗酒。", "作堂名醉墨，揮灑動牆牖。", "安得濁酒池，淋漓看濡首。", "但取繼張君，莫顧顛名醜。"]'),
('6cb0c7fa-5085-40bc-9f1a-9ee04861f840','遊凈因院寄璉禪師','蘇轍','宋','宋诗','song-poetry','','[]','歲月潛消日裏冰，依然來見佛堂燈。',64,'全唐诗/poet.song.47000.json','["歲月潛消日裏冰，依然來見佛堂燈。", "此身已自非前我，問法何妨似舊僧。", "灑面飛泉時點點，壓池蒼石尚層層。", "遥知近愛金山好，江水煎茶日幾升。"]'),
('aace19ba-57cd-44af-92d2-1dc731565bb7','送柳子玉','蘇轍','宋','宋诗','song-poetry','','[]','柳侯白首郎，風格終近古。',240,'全唐诗/poet.song.47000.json','["柳侯白首郎，風格終近古。", "舊游日零落，新輩誰與伍。", "人情逐時好，變化無定主。", "試看近時人，相教蹈規矩。", "行身劇孔孟，稱道皆舜禹。", "但求免譏評，豈顧愁肺腑。", "坐令不羈士，舉足遭網罟。", "緬懷我生初，遺俗尚目睹。", "中庸雖已亡，比近則猶愈。", "老成慎趨好，後生守淳魯。", "豈效相謾欺，衒牛沽馬脯。", "過惡酒色間，可罪非可惡。", "譬如嵇與阮，心迹豈深蠹。", "京師逢柳侯，往事能歷數。", "嘆息子美賢，相與實舊故。", "至今存篇章，醉墨龍蛇舞。", "斯人今苟在，亦恐終囚虜。", "惜哉時論隘，安置失處所。", "一麾寄河壖，垂老幸有土。", "世俗安足論，且盡杯中醑。"]'),
('1ac7ff67-bf5b-4d5e-a262-6f417a2e4e6d','送蘇公佐修撰知梓州','蘇轍','宋','宋诗','song-poetry','','[]','乘軺舊西蜀，出鎮復東川。',96,'全唐诗/poet.song.47000.json','["乘軺舊西蜀，出鎮復東川。", "父老知遺愛，壺漿定滿前。", "江山昔年路，旄節異邦權。", "望重朝中舊，疆分劍外天。", "歲登無猛政，蠻服罷防邊。", "去國身雖樂，憂時論獨堅。", "孤誠抱松直，彙進比茅連。", "我亦相從逝，疏狂且自全。"]'),
('277c291c-a229-4de5-b861-c1779e9029df','送任師中通判黄州','蘇轍','宋','宋诗','song-poetry','','[]','一別都門今五年，劇談精壯故依然。',64,'全唐诗/poet.song.47000.json','["一別都門今五年，劇談精壯故依然。", "厭居巴蜀千山底，决住荆河十頃田。", "老去功名無意取，身閑詩筆更能專。", "黄州無事聊須飲，世俗方今自足賢。"]'),
('37396927-74ad-43bd-ad52-abe342784474','南窗','蘇轍','宋','宋诗','song-poetry','','[]','京師三日雪，雪盡泥方深。',84,'全唐诗/poet.song.47000.json','["京師三日雪，雪盡泥方深。", "閉門謝還往，不聞車馬音。", "西齋書帙亂，南窗初日升。", "展轉守床榻，欲起復不能。", "開戶失瓊玉，滿階松竹陰。", "客從遠方來，疑我何苦心。", "疏拙自當爾，有酒聊共斟。"]'),
('7db14d96-a8fd-4f02-8ad8-a8b6046cb20f','次韵楊褒直講攬鏡','蘇轍','宋','宋诗','song-poetry','','[]','鬢髮年來日向衰，相寬不用强裁詩。',64,'全唐诗/poet.song.47000.json','["鬢髮年來日向衰，相寬不用强裁詩。", "壯心付與東流去，霜蟹何妨左手持。", "花發黄鸝巧言語，池開楊柳鬥腰肢。", "勸君行樂還聽否，即是南風苦熱時。"]'),
('8c389c68-b3a1-4e2e-9297-db456aaf28e6','送錢婺州純老','蘇轍','宋','宋诗','song-poetry','','[]','桃花汴水半河流，已作南行第一舟。',64,'全唐诗/poet.song.47000.json','["桃花汴水半河流，已作南行第一舟。", "倦報朝中言嘖亂，喜聞淮上艣咿呦。", "平時答策詞無枉，此去爲邦學更優。", "自古東陽足賢守，請君重賦沈公樓。"]'),
('69250eb4-591c-4a03-b6b4-c15e4777eff5','次韵柳子玉見贈','蘇轍','宋','宋诗','song-poetry','','[]','壯心衰盡愧當年，刻意爲文日幾千。',64,'全唐诗/poet.song.47000.json','["壯心衰盡愧當年，刻意爲文日幾千。", "老去讀書聊度歲，春來多睡苦便氈。", "夢歸似雁長飛去，才短如蠶只自纏。", "唯有聞詩尚思和，可能時寄最高篇。"]'),
('aa7aa58b-8df5-4db9-b590-45be55850a79','次韵任遵聖見寄','蘇轍','宋','宋诗','song-poetry','','[]','故國老成誰復先，壯心空記語當年。',64,'全唐诗/poet.song.47000.json','["故國老成誰復先，壯心空記語當年。", "灌夫失意貧無友，梅福辭官晚作仙。", "詩句清新非世俗，退居安穩卜江天。", "它年我亦從君隠，多買黄魚煮復煎。"]'),
('5c04ac0d-1c5a-4656-8351-5ba02f3abbef','次韵劉貢甫學士畫松石圖歌','蘇轍','宋','宋诗','song-poetry','','[]','長松大石生長見，朅遊塵土嗟空羨。',128,'全唐诗/poet.song.47000.json','["長松大石生長見，朅遊塵土嗟空羨。", "寒翠關心失舊交，榮華過眼驚流電。", "破繒買得古畫圖，遺墨參差隨斷線。", "蟉枝倒掛風自舞，直幹孤生看面面。", "故山舊物遠莫致，愛此隨人共流轉。", "物生真僞竟何有，適意一時寧復辨。", "少年所好老成癖，傍人指笑嗟矜衒。", "京城宅舍松石希，買費百金猶恐賤。"]'),
('417994c6-b6ec-4a1b-b81c-08e2024081b4','送頓起及第還蔡州','蘇轍','宋','宋诗','song-poetry','','[]','詔書京輔起沉淪，歲貢仍居第一人。',64,'全唐诗/poet.song.47000.json','["詔書京輔起沉淪，歲貢仍居第一人。", "不愧得官名暫屈，自誇對策語深淳。", "讀書飽足終無厭，從宦奔馳自此新。", "我去淮陽今不久，鄰邦時得問音塵。"]'),
('2117f30a-dbdc-4166-ac12-4688ecd2726a','初到陳州二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','謀拙身無向，歸田久未成。',48,'全唐诗/poet.song.47000.json','["謀拙身無向，歸田久未成。", "來陳爲懶計，傳道愧虛名。", "俎豆終難合，詩書强欲明。", "斯文吾已試，深恐誤諸生。"]'),
('a07ad385-20cb-4b0e-93c2-72f1c5f6a62f','初到陳州二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','久愛閑居樂，茲行恐遂不。',48,'全唐诗/poet.song.47000.json','["久愛閑居樂，茲行恐遂不。", "上官容碌碌，飽食更悠悠。", "枕畔書成癖，湖邊柳散愁。", "疏慵愧韓子，文字化潮州。"]'),
('b9bacbf3-b770-4174-8caf-1c361c5f6df8','柳湖感物','蘇轍','宋','宋诗','song-poetry','','[]','柳湖萬柳作雲屯，種時亂插不須根。',176,'全唐诗/poet.song.47000.json','["柳湖萬柳作雲屯，種時亂插不須根。", "根如卧蛇身合抱，仰視不見蜩蟬喧。", "開花三月亂飛雪，過牆度水無復還。", "窮高極遠風力盡，棄墜泥土顔色昏。", "偶然直墮湖中水，化爲浮萍輕且繁。", "隨波上下去無定，物性不改天使然。", "南山老松長百尺，根入石底蛟龍蟠。", "秋深葉上露如雨，傾流入土明珠圓。", "乘春發生葉短短，根大如指長而堅。", "神農嘗藥最上品，氣力直壓鍾乳溫。", "物生稟受久已異，世俗何始分愚賢。"]'),
('ebfcfece-c709-457d-a49c-4c54b93ba663','柳湖久無水悵然成咏','蘇轍','宋','宋诗','song-poetry','','[]','平湖水盡起黄埃，惟有長堤萬萬栽。',64,'全唐诗/poet.song.47000.json','["平湖水盡起黄埃，惟有長堤萬萬栽。", "病鶴摧頹沙上舞，游人寂寞岸邊回。", "秋風草木初摇落，日暮樵蘇自往來。", "更試明年春絮起，共看飛雪亂成堆。"]'),
('59bde940-199f-4a78-80a7-6c6f42ac6f8d','次韵孫戶曹朴柳湖','蘇轍','宋','宋诗','song-poetry','','[]','疏慵非敢獨違時，野性顛狂不受羈。',64,'全唐诗/poet.song.47000.json','["疏慵非敢獨違時，野性顛狂不受羈。", "猶有曲湖容笑傲，誰言與物苦參差。", "水乾生草曾非惡，鶴舞因風忽自怡。", "最愛柳陰遲日暖，幅巾輕屨肯相隨。"]'),
('39d603fc-b515-48cd-825c-9c60c16f417e','贈李簡夫司封','蘇轍','宋','宋诗','song-poetry','','[]','平生談笑接諸公，歸老身心著苦空。',64,'全唐诗/poet.song.47000.json','["平生談笑接諸公，歸老身心著苦空。", "往事少能陪晤語，新詩時喜挹清風。", "形骸摩詰羸偏健，筆札西臺晚更工。", "笑我壯年常苦病，異時何以作衰翁。"]'),
('9a0ea73e-a935-4ef3-b6c0-b66f95a0de83','次韵李簡夫秋園','蘇轍','宋','宋诗','song-poetry','','[]','秋色豈相負，小園仍有花。',48,'全唐诗/poet.song.47000.json','["秋色豈相負，小園仍有花。", "繞欄吟落日，拾徑得殘葩。", "菊細初藏蝶，桐疏不庇鴉。", "遊觀須作意，霜雪僅留槎。"]'),
('99da77d5-e007-4ddd-bf2c-875bdaf93570','題李簡夫葆光亭','蘇轍','宋','宋诗','song-poetry','','[]','逕草侵芒屩，庭花墮石臺。',48,'全唐诗/poet.song.47000.json','["逕草侵芒屩，庭花墮石臺。", "小亭幽事足，野色向人來。", "坐上烏皮几，牆間大瓠罍。", "老成無不可，談笑得徘徊。"]'),
('9d3e7987-e67f-472b-a999-1a53288b51f7','次韵李簡夫因病不出','蘇轍','宋','宋诗','song-poetry','','[]','十五年來一味閑，近來推病更安眠。',64,'全唐诗/poet.song.47000.json','["十五年來一味閑，近來推病更安眠。", "鶴形知瘦非關老，僧定端居不計年。", "坐上要須長滿客，杖頭何用出携錢。", "未嫌語笑妨清靜，閑暇陪公几杖前。"]'),
('8605a58a-e0c9-4d88-be54-7943bafb606d','張安道尚書生日','蘇轍','宋','宋诗','song-poetry','','[]','出入三朝望愈尊，淮陽退卧避喧煩。',96,'全唐诗/poet.song.47000.json','["出入三朝望愈尊，淮陽退卧避喧煩。", "崇高歷遍知皆妄，風俗頻遷氣獨存。", "世事直須勞舊德，歸心那復厭名藩。", "赤松作伴功雖切，白髮憂時義所敦。", "仁比高山年自倍，秋逢生日喜盈門。", "知公知命身無禱，聊爲生靈舉壽樽。"]'),
('289cfa3f-4e0d-4ed3-a1b9-cb27e945ab2d','送劉道原學士歸南康','蘇轍','宋','宋诗','song-poetry','','[]','大川傾流萬物俱，根旋脚脫爭奔徂。',160,'全唐诗/poet.song.47000.json','["大川傾流萬物俱，根旋脚脫爭奔徂。", "流萍斷梗誰復數，長林巨石曾須臾。", "軒昂顛倒唯恐後，嗟子何獨强根株。", "三年一語未嘗屈，擬學文舉驚當塗。", "心知勢力非汝敵，獨恐清議無遺餘。", "扁舟歲晚告歸覲，家膳欲及羞蓴鱸。", "隠居高節世所尚，掛冠早歲還州閭。", "紛紜世事不著耳，得失豈復分錙銖。", "投身固已陷泥滓，獨立未免遭霑濡。", "君歸左右識高趣，牛毛細數分賢愚。"]'),
('39887dc1-bc89-40f5-aecc-706914eea1f3','題滑州畫舫齋贈李公擇學士','蘇轍','宋','宋诗','song-poetry','','[]','窗戶重重向日明，船居氣味此中生。',64,'全唐诗/poet.song.47000.json','["窗戶重重向日明，船居氣味此中生。", "汀洲出沒叢花短，波浪澄虛兩岸平。", "竄逐南來身未穩，安閑感物意猶驚。", "前賢事迹君今似，不愧當年畫舫名。"]'),
('d49d01ab-fa80-45ea-9f05-c0f13a2554ee','送王恪郎中知襄州','蘇轍','宋','宋诗','song-poetry','','[]','魏公德業冠當年，汝守威名竦漢邊。',96,'全唐诗/poet.song.47000.json','["魏公德業冠當年，汝守威名竦漢邊。", "將相傳家俱未遠，子孫到處各推賢。", "風流最喜君真似，符竹連分政得專。", "峴首重尋碑墮淚，習池還指客橫鞭。", "逃亡已覺依劉表，寒俊應須禮浩然。", "當有郡人知古意，攔街齊唱接籬篇。"]'),
('53a3b09b-8705-43ed-8c86-46f92090177c','和張安道讀杜集','蘇轍','宋','宋诗','song-poetry','','[]','我公才不世，晚歲道尤高。',240,'全唐诗/poet.song.47000.json','["我公才不世，晚歲道尤高。", "與物都無著，看書未覺勞。", "微言精老易，奇韵喜莊騷。", "杜叟詩篇在，唐人氣力豪。", "近時無沈宋，前輩蔑劉曹。", "天驥精神穩，層臺結構牢。", "龍騰非有迹，鯨轉自生濤。", "浩蕩來何極，雍容去若遨。", "壇高真命將，毳亂始知髦。", "白也空無敵，微之豈少褒。", "論文開錦繡，賦命委蓬蒿。", "初試中書日，旋聞鄜畤逃。", "妻孥隔豺虎，關輔暗旌旄。", "入蜀營三徑，浮江寄一艘。", "投人慚下舍，愛酒類東皋。", "漂泊終浮梗，迂疏獨釣鼇。", "誤身空有賦，掩脛惜無袍。", "卷軸今何益，零丁昔未遭。", "相如元羣世，惠子謾臨濠。", "得失將誰怨，憑公付濁醪。"]'),
('a7ad8ac7-e254-4e82-8676-4b9e392d4a92','送張公安道南都留臺','蘇轍','宋','宋诗','song-poetry','','[]','識公歲已深，從公非一日。',240,'全唐诗/poet.song.47000.json','["識公歲已深，從公非一日。", "仰公如重雲，庇我貧賤迹。", "公歸無留意，我處念平昔。", "少年喜文字，東行始觀國。", "成都多遊士，投謁密如櫛。", "紛然衆人中，顧我好顔色。", "猖狂感一遇，邂逅登仕籍。", "爾來十六年，鬢髮就衰白。", "謀身日已謬，處世復何益。", "從來學俎豆，漸老信典冊。", "自知百不堪，偶未三見黜。", "譬如溝中斷，誰復强收拾。", "高懷絕塵土，舊好等金石。", "庠齋幸無事，樽俎奉清適。", "居然遠憂患，况復取矜式。", "汪洋際海深，淡泊朱弦直。", "狥時非所安，歸去亦何失。", "道存尚可卷，功成古難必。", "還尋赤松子，獨就丹砂術。", "恨無二頃田，伴公老蓬蓽。"]'),
('25faf9ba-ea36-406c-a73d-3277080ee576','傅欽之學士濟源草堂','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聞有高居直百金，西山南麓北山陰。',64,'全唐诗/poet.song.47000.json','["聞有高居直百金，西山南麓北山陰。", "園通濟水池塘好，花近洛川顔色深。", "人去節旄分重鎮，客來猿鶴感幽吟。", "潩溪雨過西湖漲，歸興蕭然定不任。"]'),
('aac43eac-26f8-4d87-af1b-00ddec9ff331','文與可學士墨君堂','蘇轍','宋','宋诗','song-poetry','','[]','虛堂竹叢間，那復厭竹遠。',96,'全唐诗/poet.song.47000.json','["虛堂竹叢間，那復厭竹遠。", "風庭響交戛，月牖散凌亂。", "尚恐晝掩關，嬋娟不長見。", "中堂開素壁，蕭颯起霜幹。", "隨宜賦生意，落筆皆葱蒨。", "根莖雜土石，枝葉互長短。", "依依露下綠，冉冉風中展。", "開門視叢薄，與此終何辨。"]'),
('de00f9a3-bfc5-4944-969e-6967f58f7e30','故成都尹陸介夫挽詞','蘇轍','宋','宋诗','song-poetry','','[]','擁節西南未一年，凄凉道路泣東轅。',64,'全唐诗/poet.song.47000.json','["擁節西南未一年，凄凉道路泣東轅。", "蜀都富樂真當惜，民事艱難誰復論。", "白馬何人趨遠日，青芻盈束更無言。", "異時歸去逢遺老，空聽咨嗟述舊恩。"]'),
('fb5d2491-2432-45b3-90de-d9cb87ab9a93','次韵柳子玉謫官壽春舟過宛丘見寄二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','局冷曾非簿領迷，幽居渾似未官時。',64,'全唐诗/poet.song.47000.json','["局冷曾非簿領迷，幽居渾似未官時。", "忽聞客至驚還喜，出見泥深笑不知。", "謀拙未能憂歲計，身閑聊可飽晨炊。", "行舟借問何匆草，淮口無潮月正虧。"]'),
('4eb385f4-d065-4fbe-9c47-951f2187873a','次韵柳子玉謫官壽春舟過宛丘見寄二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','獻酬不用辭升斗，曲直何勞問尺尋。',64,'全唐诗/poet.song.47000.json','["獻酬不用辭升斗，曲直何勞問尺尋。", "要路風波無限惡，謫居情味最能深。", "交從錦水初無間，鄰卜共山已有心。", "草聖詩豪並神速，數因南雁惠佳音。"]'),
('1daa191e-e1e3-42c2-a3ff-35739e55f000','次韵子瞻潁州留別二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','託身遊宦鄉，終老羨箕潁。',120,'全唐诗/poet.song.47000.json','["託身遊宦鄉，終老羨箕潁。", "隠居亦何樂，親愛形隨影。", "念兄適吳越，霜降水初冷。", "翩然事舟楫，棄此室廬靜。", "平明知當發，中夜抱虛警。", "永懷江上宅，歸計失不猛。", "人生狥所役，有若魚墮井。", "遠行豈易還，劇飲終難醒。", "不如早自乞，閑日庶猶永。", "世事非所憂，多憂亦誰省。"]'),
('b0466904-71b0-49f2-9c99-1f770be9b248','次韵子瞻潁州留別二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','放舟清淮上，蕩潏洗心胸。',120,'全唐诗/poet.song.47000.json','["放舟清淮上，蕩潏洗心胸。", "所遇日轉勝，恨我不得同。", "江淮忽中斷，陂埭何重重。", "紫蟹三寸筐，白鳬五尺童。", "赤鯉寒在汕，紅粳滿霜風。", "西成百物賤，加餐慰貧窮。", "胡爲復相念，未肯安南東。", "人生免饑寒，不受外物攻。", "不見田野人，四壁編茅蓬。", "有食輒自樂，誰知富家翁。"]'),
('c2a6acb9-b092-47a3-9e2f-29816cdf5f50','陪歐陽少師永叔燕潁州西湖','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖草木公所種，仁人實使甘棠重。',128,'全唐诗/poet.song.47000.json','["西湖草木公所種，仁人實使甘棠重。", "歸來築室傍湖東，勝遊還與邦人共。", "公年未老髮先衰，對酒清歡似昔時。", "功成業就了無事，令名付與他人知。", "平生著書今絕筆，閉門燕居未嘗出。", "忽來湖上尋舊遊，坐令湖水生顔色。", "酒行樂作遊人多，爭觀竊語誰能呵。", "十年思潁今在潁，不飲耐此遊人何。"]'),
('781a5fbc-00b9-420e-9595-803198453b1d','歐陽公所蓄石屏','蘇轍','宋','宋诗','song-poetry','','[]','石中枯木雙扶疏，粲然脈理通肌膚。',160,'全唐诗/poet.song.47000.json','["石中枯木雙扶疏，粲然脈理通肌膚。", "剖開左右兩相屬，細看不見毫髮殊。", "老樗剝落但存骨，病松憔悴空留鬚。", "丘陵迤邐山麓近，雲烟澹䨴風雨餘。", "我驚造物巧如此，刻畫瑣細供人須。", "公家此類尚非一，客至不識空嗟吁。", "案頭紫雲抱明月，床上寒木翻饑烏。", "賦形簡易神自足，鄙棄筆墨嗟勤劬。", "天工此意與人競，雜出變怪驚羣愚。", "世間淺拙無與敵，比擬頼有公新書。"]'),
('fc402b8f-f0d4-4a9f-88a2-a2e3f95291ea','次韵子瞻初出潁口見淮山','蘇轍','宋','宋诗','song-poetry','','[]','清淮此日見滄浪，始覺南來道路長。',64,'全唐诗/poet.song.47000.json','["清淮此日見滄浪，始覺南來道路長。", "窗轉山光時隠見，船知水力故軒昂。", "白魚受釣收寒玉，紅稻堆場列遠岡。", "波浪連天東近海，乘桴直恐漸茫茫。"]'),
('2715d3be-d805-44b9-b9c5-0aeac8090cde','次韵子瞻壽州城東龍潭','蘇轍','宋','宋诗','song-poetry','','[]','東行取次閱三州，擊鼓清晨復解舟。',64,'全唐诗/poet.song.47000.json','["東行取次閱三州，擊鼓清晨復解舟。", "車騎紛紜追過客，歌鐘凄咽動潛虬。", "宦遊底處非巢燕，歸計何嫌誚沐猴。", "頼有故人憐遠適，慇懃屢勸酒行周。"]'),
('236f7f41-7588-4cc6-9396-cf9c03691e8b','和子瞻渦口遇風','蘇轍','宋','宋诗','song-poetry','','[]','長淮暮生風，來自渦河口。',96,'全唐诗/poet.song.47000.json','["長淮暮生風，來自渦河口。", "新舟雖云固，波浪亦難受。", "詩來話艱厄，驚恐及兒婦。", "憶同泝荆峽，終夜愁石首。", "餘飆入幃幄，跳沫濺窗牖。", "平生未省見，驚顧欲狂走。", "爾來涉憂患，漸覺成老醜。", "遥喜波浪中，時能飲醇酒。"]'),
('b6a17d15-270e-40fd-b808-52de10b5f39b','和子瞻濠州七絕 塗山','蘇轍','宋','宋诗','song-poetry','','[]','娶婦山中不肯留，會朝山下萬諸侯。',32,'全唐诗/poet.song.47000.json','["娶婦山中不肯留，會朝山下萬諸侯。", "古人辛苦今誰信，只見清淮入海流。"]'),
('4c8d3c28-147e-4c12-9707-130a8c9a2374','和子瞻濠州七絕 彭祖廟','蘇轍','宋','宋诗','song-poetry','','[]','長說先師似老彭，共疑好學古書生。',32,'全唐诗/poet.song.47000.json','["長說先師似老彭，共疑好學古書生。", "不知亦解餐雲母，白日登天萬事輕。"]'),
('c0643ace-2e35-4864-aea3-6aa3cabbc1be','和子瞻濠州七絕 逍遥堂','蘇轍','宋','宋诗','song-poetry','','[]','猖狂戰國古神仙，曳尾泥塗老更安。',32,'全唐诗/poet.song.47000.json','["猖狂戰國古神仙，曳尾泥塗老更安。", "厭世乘雲人不見，空墳聊復葬衣冠。"]'),
('e19f1514-45f5-4665-ac8d-bee73592af33','和子瞻濠州七絕 觀魚臺','蘇轍','宋','宋诗','song-poetry','','[]','莊子談空惠子聽，郢人斤斧俟忘形。',32,'全唐诗/poet.song.47000.json','["莊子談空惠子聽，郢人斤斧俟忘形。", "莫嗟質喪無知者，對石何妨自說經。"]'),
('80472d8e-471d-47f5-8986-aaf073e873c3','和子瞻濠州七絕 虞姬墓','蘇轍','宋','宋诗','song-poetry','','[]','布叛增亡國已空，摧殘羽翮自令窮。',32,'全唐诗/poet.song.47000.json','["布叛增亡國已空，摧殘羽翮自令窮。", "艱難獨與虞姬共，誰使西來敵沛公。"]'),
('4f85d0b9-4a4d-4bec-9686-b78637238093','和子瞻濠州七絕 四望亭','蘇轍','宋','宋诗','song-poetry','','[]','唐史不聞劉嗣之，空傳短李舊歌詩。',32,'全唐诗/poet.song.47000.json','["唐史不聞劉嗣之，空傳短李舊歌詩。", "高亭毀盡唯存記，猶有區區父老知。"]'),
('556675be-046b-47f4-92b4-9c0e6a503773','和子瞻濠州七絕 浮山洞','蘇轍','宋','宋诗','song-poetry','','[]','洞府元依水面開，秋潮每到洞門回。',32,'全唐诗/poet.song.47000.json','["洞府元依水面開，秋潮每到洞門回。", "幽人燕坐門前石，長看長淮船去來。"]'),
('3f8c506d-8c1b-47a4-a85b-defebe934b0f','和子瞻泗州僧伽塔','蘇轍','宋','宋诗','song-poetry','','[]','清淮濁汴爭强雄，龜山下閟支祁宮。',160,'全唐诗/poet.song.47000.json','["清淮濁汴爭强雄，龜山下閟支祁宮。", "高秋水來無遠近，蕩滅洲渚乘城墉。", "千艘銜尾誰復惜，萬人雨泣哀將窮。", "城中古塔高百尺，下有蛻骨黄金容。", "蛟龍百怪不敢近，迴風倒浪歸無蹤。", "越商胡賈豈知道，脫身獻寶酬元功。", "至人已立萬物表，劫火僅置毛孔中。", "區區淮汴亦何有，一挹可注滄溟東。", "胡爲尚與水族較，時出變怪驚愚聾。", "於乎此意不可詰，仰觀飛栱凌晴空。"]'),
('3d60dd61-287c-4635-97ca-3a5111aabd25','次韵子瞻發洪澤遇大風却還宿','蘇轍','宋','宋诗','song-poetry','','[]','昨夜宿洪澤，再來遂如歸。',120,'全唐诗/poet.song.47000.json','["昨夜宿洪澤，再來遂如歸。", "却行雖云拙，乘險諒亦非。", "誰言淮陰近，阻此駭浪飛。", "長風徑千里，蛟蜃相因依。", "眇然恃一葉，此勢安可違。", "冒涉彼何人，勇决生慮微。", "欲速有不達，魚腹豈足肥。", "風帆尚可轉，野廟誰能祈。", "但當擁衾睡，慎閉窗與扉。", "夜聞聲尚惡，起視聊披衣。"]'),
('81d68fca-7bba-43dd-8be7-10842d47cb55','次韵子瞻記十月十六日所見','蘇轍','宋','宋诗','song-poetry','','[]','君不見天高后土黄，變化出入唯陰陽。',161,'全唐诗/poet.song.47000.json','["君不見天高后土黄，變化出入唯陰陽。", "旋凝細霧作飛雹，復遣震雷追日光。", "可憐萬物甚微細，坐聽百變隨顛僵。", "深根固蒂無計遁，倏來忽返安能防。", "平生未見實驚耳，稍遠不知如隔牆。", "君看歌舞醉華屋，下有纍縶排兩廊。", "眼前苦樂尚懸絕，空中造化知有亡。", "我居宛丘厭凝沍，雪翻海水填陂塘。", "但知膏澤利牟麥，恣食餠餌真嘉祥。", "山陽所記亦何事，有酒胡不盡一觴。"]'),
('e220c8b7-d72f-430f-ab87-4c6f7c42a980','次韵子瞻廣陵會三同舍各以其字爲韵 劉貢甫','蘇轍','宋','宋诗','song-poetry','','[]','貢甫少多才，交遊一何衆。',120,'全唐诗/poet.song.47000.json','["貢甫少多才，交遊一何衆。", "談詞坐傾倒，玉麈日揮弄。", "逡巡不爲虐，巧捷有微中。", "羣情忌超邁，微過出嘲諷。", "南遷時已久，未見肯力貢。", "舌在終自奇，髀滿安足痛。", "人生百年內，僅比一朝夢。", "駸駸就消涸，斗水傾漏甕。", "江淮未可嫌，遲晚聊自送。", "試觀終日閑，何似兩耳哄。"]'),
('ca43d65e-1ed1-4224-ab9c-1033abefe793','次韵子瞻廣陵會三同舍各以其字爲韵 孫巨源','蘇轍','宋','宋诗','song-poetry','','[]','巨源學從橫，世事夙討論。',120,'全唐诗/poet.song.47000.json','["巨源學從橫，世事夙討論。", "著書十萬字，辯如白波翻。", "諫垣適多事，憂心生病根。", "立談信無補，閉口出國門。", "棄置卧江海，閔嘿寧復言。", "朝行共長嘆，逐客繼二孫。", "南方固鄉黨，謫官侶鶴猿。", "風俗未寧靜，朋黨爭排跟。", "引去良自得，濁清在澄源。", "往者未可招，冠蓋方駿奔。"]'),
('9aeb0a66-9af5-4430-9d41-5bec79213ea4','次韵子瞻廣陵會三同舍各以其字爲韵 劉莘老','蘇轍','宋','宋诗','song-poetry','','[]','莘老奮徒步，首與觀國賓。',120,'全唐诗/poet.song.47000.json','["莘老奮徒步，首與觀國賓。", "儼然自約束，被服韍與紳。", "黽勉丞相府，接迹輿臺臣。", "顧嫌任安躁，未忍裂坐茵。", "推置冠獬豸，謂言我比鄰。", "三晉固多士，骯髒存斯人。", "竄責不敢辭，狂言見天真。", "南方異風俗，强食魚尾莘。", "應同賈太傅，抱屈耻自陳。", "猶有痛哭書，受釐定何辰。"]'),
('681c5684-c5d0-4574-b922-6a7e7f7d849b','和子瞻金山','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江欲盡闊無邊，金山當中唯一石。',176,'全唐诗/poet.song.47000.json','["長江欲盡闊無邊，金山當中唯一石。", "潮平風靜日浮海，縹緲樓臺轉金碧。", "瓜洲初見石頭城，城下波濤與海平。", "中流轉柂疑無岸，泊舟未定僧先迎。", "山中岑寂恐未足，復將江水繞山麓。", "四無鄰家羣動息，鐘聲鏗鍠答山谷。", "烏鳶力薄墮中路，惟有胡鷹石上宿。", "誰知江海多行舟，遊人上下奪巖幽。", "老僧心定身不定，送往迎來何時竟。", "朝遊未厭夜未歸，愛山如此如公稀。", "不待遊人盡歸去，恐公未識山中趣。"]'),
('b57dac2d-7d1b-4d74-b9dc-aa32aa8dfe4d','和子瞻焦山','蘇轍','宋','宋诗','song-poetry','','[]','金山遊遍入焦山，舟輕帆急須臾間。',192,'全唐诗/poet.song.47000.json','["金山遊遍入焦山，舟輕帆急須臾間。", "涉江已遠風浪闊，遊人到此皆爭還。", "山頭冉冉萬竿竹，樓閣不見門長關。", "金山共此一江水，只有勝絕無此閑。", "野僧終日飽一飯，與世相視如髦蠻。", "門無舟楫斷還往，說法教化黿鼉頑。", "偶然客至話鄉國，西望落日低銅鐶。", "岷峨正在日入處，想象積雪堆青鬟。", "稻田一頃良自給，仕宦不返知誰扳。", "久安祿廩農事廢，强弓一弛無由彎。", "行逢佳處輒嘆息，想見茅屋藏榛菅。", "我知此地便堪隠，稻苗旆旆魚斑斑。"]'),
('3309ff49-2cee-4694-8e39-f67c6a6803be','次韵子瞻遊甘露寺','蘇轍','宋','宋诗','song-poetry','','[]','去國日已遠，涉江歲將闌。',288,'全唐诗/poet.song.47000.json','["去國日已遠，涉江歲將闌。", "東南富山水，跬步留清歡。", "遷延廢行邁，忽忘身在官。", "清晨涉甘露，乘高棄征鞍。", "超然脫闤闠，穿雲撫朱欄。", "下視萬物微，惟覺滄海寬。", "潮來聲洶洶，望極空漫漫。", "一一渡海舶，冉冉移檣竿。", "水怪時出沒，羣嬉類豭羱。", "幽陰自生火，青熒復誰鑽。", "石頭古天險，憑恃分權瞞。", "疑城曜遠目，來騎驚新觀。", "聚散定王業，成毀猶月團。", "金山百圍石，岌岌隨濤瀾。", "猶疑漢宮廷，屹立承露盤。", "狂波恣吞噬，萬古嗟獨完。", "凝眸厭滉漾，繞屋行盤跚。", "此寺歷今古，遺迹皆龍鸞。", "孔明所坐石，牂䍽非人刊。", "經霜衆草短，積雨青苔寒。", "蕭翁嗜佛法，大福將力干。", "坡陀故鑊在，甲錯蒼龍蟠。", "衛公秉節制，佛骨埋金棺。", "長松看百尺，畫像留三嘆。"]'),
('49671893-e450-4317-a743-9d93e8391a3c','李簡夫挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','老成渾欲盡，吊客一潸然。',48,'全唐诗/poet.song.47000.json','["老成渾欲盡，吊客一潸然。", "遺事人人記，清詩句句傳。", "掛冠疏傅早，樂世白公賢。", "嘆息風流在，埋文得細鎸。"]'),
('d06d1822-6ab0-498b-91cb-c3ea87ce2a4f','李簡夫挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','歸隠淮陽市，遨遊十六年。',48,'全唐诗/poet.song.47000.json','["歸隠淮陽市，遨遊十六年。", "養生能淡泊，愛客故留連。", "傾蓋知心晚，論詩卧病前。", "葆光塵滿榻，無復聽談禪。"]'),
('14fae242-9dba-4034-bd4b-e75978508b47','次韵子瞻初到杭州見寄二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','吏治區區豈不任，吳中已自富才能。',32,'全唐诗/poet.song.47000.json','["吏治區區豈不任，吳中已自富才能。", "還應占位書名姓，學取藍田崔縣丞。"]'),
('0a187e6e-5f0f-45be-89a9-18d97503e740','次韵子瞻初到杭州見寄二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','試盡風波萬里身，到官山水却宜人。',32,'全唐诗/poet.song.47000.json','["試盡風波萬里身，到官山水却宜人。", "君知晏子恩仍厚，還與從來舊卜鄰。"]'),
('3fe6fc4a-f9a6-4e18-b20f-ffd71fc880b2','和柳子玉地爐','蘇轍','宋','宋诗','song-poetry','','[]','鑿地泥床不費功，山深炭賤火長紅。',64,'全唐诗/poet.song.47000.json','["鑿地泥床不費功，山深炭賤火長紅。", "擁衾熟睡朝衙後，抱膝微吟莫雪中。", "寵辱兩忘輕世味，冰霜不到傲天工。", "遥知麻步無人客，寒夜清樽誰與同。"]'),
('9a9d42fb-9da8-4ae4-8793-9ca26c24b369','和柳子玉紙帳','蘇轍','宋','宋诗','song-poetry','','[]','夫子清貧不耐冬，書齋還費紙重重。',64,'全唐诗/poet.song.47000.json','["夫子清貧不耐冬，書齋還費紙重重。", "窗明曉日從教入，帳厚霜飆定不容。", "京兆牛衣聊可藉，公孫布被旋須縫。", "吳綾蜀錦非嫌汝，簡淡爲生要易供。"]'),
('ed85c304-2ab7-4edb-87e0-4044aa643bb7','次韵子瞻遊孤山訪惠懃惠思','蘇轍','宋','宋诗','song-poetry','','[]','鳥依山，魚依湖，但有所有無所無。',160,'全唐诗/poet.song.47000.json','["鳥依山，魚依湖，但有所有無所無。", "輕舟沿泝窮遠近，肩輿上下更傳呼。", "翩然獨往不携孥，兼擅魚鳥兩所娛。", "困依巖石坐巉絕，行牽翠蔓隨纏紆。", "道逢懃思訪其廬，誦詩清切秋蟬孤。", "隠居羞踏陌上土，何人起愛輪下蒲。", "水南巷中羅百夫，雞鳴朝謁至日晡。", "人生變化安可料，憐汝久遁終無圖。", "鳧鷖不足鶴有餘，一俯一仰戚與蘧。", "嗟我久欲從逃逋，方圓不敢左右摹。"]'),
('5369cb2a-3626-4358-8911-1c0c7f2a5fe1','宛丘二咏  其一','蘇轍','宋','宋诗','song-poetry','','[]','旱湖堤上柳空多，倚岸輕舟奈汝何。',64,'全唐诗/poet.song.47000.json','["旱湖堤上柳空多，倚岸輕舟奈汝何。", "秋雨連渠添積潤，春風吹凍忽生波。", "蟲魚便爾來無數，鳬雁猶疑未肯過。", "持詫錢塘應笑我，坳中浮芥兩幺麽。"]'),
('0f95b7ff-836e-470a-b604-53a4479fa977','宛丘二咏  其二','蘇轍','宋','宋诗','song-poetry','','[]','古殿山花叢百圍，故園曾見色依依。',64,'全唐诗/poet.song.47000.json','["古殿山花叢百圍，故園曾見色依依。", "凌寒强比松筠秀，吐艷空驚歲月非。", "冰雪紛紜真性在，根株老大衆園希。", "山中草木誰携種，潦倒塵埃不復歸。"]'),
('3b3be9a8-2c5d-456d-b5e1-292806dd5ef7','贈提刑賈司門青','蘇轍','宋','宋诗','song-poetry','','[]','前年乘舟護南河，宛丘官舍酣且歌。',128,'全唐诗/poet.song.47000.json','["前年乘舟護南河，宛丘官舍酣且歌。", "去年持節憂犴獄，驅車道路日不足。", "今年春風塵土黄，遠赴三州議繇役。", "天子憂民法令新，整齊百事無閑人。", "苗耘髮櫛何時已，回首昔遊如夢寐。", "區區學舍曾未知，春晚日長唯有睡。", "才智有餘安得閑，疏慵顧我自當然。", "喜君未忘太平事，獨稱赦書旌孝子。"]'),
('c1ad7102-553b-442f-a378-ede3666d38a0','同陳述古舍人觀芍藥','蘇轍','宋','宋诗','song-poetry','','[]','藹藹堂西十畝園，晚凉迎步綠陰繁。',64,'全唐诗/poet.song.47000.json','["藹藹堂西十畝園，晚凉迎步綠陰繁。", "共驚春去已多日，爭看花開最後番。", "未許狂風催爛熳，故將青幄强安存。", "請公作意勤歡賞，趁取殘紅照酒樽。"]'),
('6c63818f-9ce7-416b-aacb-076422eb332e','次韵子瞻見寄','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我將西歸老故丘，長江欲濟無行舟。',240,'全唐诗/poet.song.47000.json','["我將西歸老故丘，長江欲濟無行舟。", "宦游已如馬受軛，衰病擬學龜藏頭。", "三年學舍百不與，糜費廩粟常慚羞。", "矯時自信力不足，從政敢謂學已優。", "閉門却掃誰與語，晝夢時作鈞天游。", "自從四方多法律，深山更深逃無術。", "衆人奔走我獨閑，何異端居割蜂蜜。", "懷安已久心自知，彈劾未至理先屈。", "餘杭軍府百事勞，經年未見持干旄。", "賈生作傅無封事，屈平憂世多離騷。", "煩刑弊法非公耻，怒馬奔車忌鞭箠。", "藐藐何自聽諄諄，諤諤未必賢唯唯。", "求田問舍古所非，荒畦弊宅今餘幾。", "出從王事當有程，去須膰肉嫌無名。", "掃除百憂唯有酒，未退聊取身心輕。"]'),
('aeac13ab-95ee-4894-b385-59d1743711f3','趙少師自南都訪歐陽少師於潁州留西湖久之作詩獻歐陽公','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','公居潁水上，德與潁水清。',240,'全唐诗/poet.song.47000.json','["公居潁水上，德與潁水清。", "身閑道轉勝，內足無復營。", "平昔富交遊，開門坐常盈。", "退居萬事樂，獨恨無友生。", "汝潁亦多士，後來非老成。", "趙公平生舊，情好均弟兄。", "少年結意氣，晚歲齊功名。", "携手踐廊廟，躡足辭鈞衡。", "徜徉里閭間，脫略世俗縈。", "興來忽命駕，一往千里輕。", "白髮儼相映，元勳各崢嶸。", "人生會面難，此會有餘情。", "遨遊西湖中，仲夏草木榮。", "壺觴列四坐，歌舞羅前楹。", "畫舫極沿泝，肩輿並逢迎。", "棹進鳬鴨亂，樂作蟲魚驚。", "近寺駢履迹，高臺吹笑聲。", "往事語京洛，餘歡發吟賡。", "拳拳主人厚，款款來客誠。", "此樂有時盡，此好何由傾。"]'),
('67c6eed3-410b-432f-81f5-9bfa7c118e16','次韵子瞻望湖樓上五絕  其一','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','欲看西湖兩岸山，卧乘湖上木蘭船。',32,'全唐诗/poet.song.47000.json','["欲看西湖兩岸山，卧乘湖上木蘭船。", "湖山已自隨船改，更值陰晴欲雨天。"]'),
('ca4d40b6-8e24-45ad-a688-364e7eeb3d54','次韵子瞻望湖樓上五絕  其二','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','眼看西湖不暫來，簿書無算撥還開。',32,'全唐诗/poet.song.47000.json','["眼看西湖不暫來，簿書無算撥還開。", "三年屈指渾將盡，記取從今得幾回。"]'),
('284a6672-e7bf-49c4-bedb-85b8b7dcd1f5','次韵子瞻望湖樓上五絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','湖山欲買恨無錢，且盡芳樽對玉盤。',32,'全唐诗/poet.song.47000.json','["湖山欲買恨無錢，且盡芳樽對玉盤。", "菱角鷄頭應已厭，蟹螯馬頰更勤餐。"]'),
('956010aa-3a6b-4c94-91a2-fc6b600f2f62','次韵子瞻望湖樓上五絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','終日清漪弄短橈，久忘車乘走翹翹。',32,'全唐诗/poet.song.47000.json','["終日清漪弄短橈，久忘車乘走翹翹。", "秋風且食鱸魚美，洛下諸生未可招。"]'),
('05c85577-d093-4e20-8db5-fb0355999b78','次韵子瞻望湖樓上五絕  其五','蘇轍','宋','宋诗','song-poetry','','[]','滯留朝市常嫌鬧，放棄江湖也未閑。',32,'全唐诗/poet.song.47000.json','["滯留朝市常嫌鬧，放棄江湖也未閑。", "孤舫粗窮千頃浪，肩輿未盡百重山。"]'),
('0e65168f-8cff-4b01-ba7f-7a120534c089','和柳子玉共城新開御河過所居牆下','蘇轍','宋','宋诗','song-poetry','','[]','卜築共山功欲成，新河入縣巧相縈。',64,'全唐诗/poet.song.47000.json','["卜築共山功欲成，新河入縣巧相縈。", "誰將畚鍤千夫力，添上園林一倍清。", "生長魚蝦供晚饌，浮沉鵝鴨放春聲。", "爲鄰有意非今日，丐我餘波伴濯纓。"]'),
('1c952722-b108-4276-8833-5beac627bde4','歐陽太師挽詞三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','雄文元命世，直氣早成風。',48,'全唐诗/poet.song.47000.json','["雄文元命世，直氣早成風。", "受任衰遲後，安邦反側中。", "迴天深有力，扈聖耻言功。", "事已身隨去，驚嗟柱石空。"]'),
('049e7ce1-aa01-4882-984e-2cdae19a1b4b','歐陽太師挽詞三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','唐弊文初喪，書成法至今。',48,'全唐诗/poet.song.47000.json','["唐弊文初喪，書成法至今。", "雍容趨聖處，深切可人心。", "氣力知難繼，風流喜不淫。", "懸知公欲謝，異說勇交侵。"]'),
('c26e46ff-d4d5-41ca-84ce-06bd2bbd3b6e','歐陽太師挽詞三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','推轂誠多士，登龍盛一時。',48,'全唐诗/poet.song.47000.json','["推轂誠多士，登龍盛一時。", "西門行有慟，東閣見無期。", "念昔先君子，嘗蒙國士知。", "舊恩終未報，感嘆不勝悲。"]'),
('bfdc4c3c-127f-4a8a-90a6-193bde96d6c9','賦黄鶴樓贈李公擇公擇時知鄂州','蘇轍','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','前年見君河之浦，東風吹河沙如霧。',160,'全唐诗/poet.song.47000.json','["前年見君河之浦，東風吹河沙如霧。", "北潭楊柳强知春，樽酒相携終日語。", "君家東南風氣清，謫官河壖不稱情。", "一麾夏口亦何有，高樓黄鶴慰平生。", "荆江洞庭春浪起，漢沔初來入江水。", "岸頭南北不相知，惟見風濤湧天地。", "巫峽瀟湘萬里船，中流鼓楫四茫然。", "高城枕山望如带，華榱照日光流淵。", "樓上騷人多古意，坐忘朝市無窮事。", "誰道武昌岸下魚，不如建業城邊水。"]'),
('8b8cf693-2d07-4b9c-8023-209052d0ee0e','次韵子瞻餘杭法喜寺綠野亭懷吳興太守孫莘老','蘇轍','宋','宋诗','song-poetry','','[]','信美非吾土，三吳一水中。',96,'全唐诗/poet.song.47000.json','["信美非吾土，三吳一水中。", "亭高望已極，舟入去無窮。", "朝市知安在，湖山信有功。", "遨遊逐鳬鴨，飲食數魚蟲。", "波浪喧朝夕，梅烝變綠紅。", "逢人問京洛，去國長兒童。", "同舍情相接，鄰邦信屢通。", "相邀欲相過，道里訊溪翁。"]'),
('20c3845c-a480-4e0b-b8ae-916def2652f5','和子瞻宿臨安浄土寺','蘇轍','宋','宋诗','song-poetry','','[]','四方清浄居，多被僧所占。',144,'全唐诗/poet.song.47000.json','["四方清浄居，多被僧所占。", "既無世俗營，百事得豐贍。", "家居每紛薄，奉養出寒欠。", "昔年旅東都，局促吁已厭。", "城西近精廬，長老時一覘。", "每來獲所求，食飽山茶釅。", "塵埃就湯沐，垢膩脫巾韂。", "不知禪味深，但取饑腸饜。", "京城苦煩溷，物景費治染。", "吳都况清華，觀剎吐光艷。", "石矼度空闊，泉溜瀉深塹。", "經過未足多，終老應長歉。"]'),
('004f7fd2-9c39-4799-9076-0ee73b57ef5b','和子瞻自浄土步至功臣寺','蘇轍','宋','宋诗','song-poetry','','[]','山平村塢連，野寺鐘相答。',168,'全唐诗/poet.song.47000.json','["山平村塢連，野寺鐘相答。", "晚陰生林莽，落日猶在塔。", "行招兩社僧，共步青山月。", "送客渡石橋，迎客出林樾。", "幽尋本真性，往事聽徐說。", "錢王方壯年，此邦事輕俠。", "鄉人鄙貧賤，異類識英傑。", "立石象興王，遺迹今岌嶪。", "功勳三吳定，富貴四海甲。", "歸來父老藏，崇高畏摧壓。", "詩人巧譏病，牛領恣挑抉。", "流傳後世人，談笑資口舌。", "是非亦已矣，興廢何倉卒。", "持歸問禪翁，笑指浮漚沒。"]'),
('c07ef2f2-6781-4dd3-a33a-aa89bf5590f3','次韵子瞻遊徑山','蘇轍','宋','宋诗','song-poetry','','[]','去年渡江愛吳山，忽忘蜀道輕秦川。',224,'全唐诗/poet.song.47000.json','["去年渡江愛吳山，忽忘蜀道輕秦川。", "錢塘後到山最勝，下枕湖水相縈旋。", "坐疑吳會無復有，扁舟屢出凌濤淵。", "今秋復入徑山寺，勢壓衆嶺皆摧顛。", "連峰沓嶂不知數，重重相抱如青蓮。", "散爲雲霧翳星斗，聚作潭井藏蜿蜒。", "欽翁未到人迹絕，千里受記來安禪。", "荒榛野草置茅屋，坐令海賈輸金錢。", "至今傳法破煩惱，飽食過客容安眠。", "解裝投錫不復去，紛紛四合來烏鳶。", "或言此處猶未好，海上人少無煩煎。", "天台雁蕩最深秀，水驚石瘦尤清便。", "青山獨往無不可，論說好醜徒紛然。", "終當直去無遠近，藤鞋竹杖聊窮年。"]'),
('993804df-f9be-4926-b123-ac179ddcd085','次韵子瞻自徑山回宿湖上','蘇轍','宋','宋诗','song-poetry','','[]','朝從徑山來，泱莽徑山色。',108,'全唐诗/poet.song.47000.json','["朝從徑山來，泱莽徑山色。", "莫從湖上歸，滉漾湖光碧。", "借問泛湖舟，何似登山屐。", "高懷厭朝市，遠去忘憂慄。", "目向幽人青，顔從濁醪赤。", "塵埃解羅網，宇宙爲安宅。", "油然了無營，此意誰能詰。", "嗟子別離久，欲往徒反側。", "留滯亦何爲，空驚突深黑。"]'),
('c34c9322-e47a-4d8a-a0d8-4b6b06b576f0','次韵子瞻題孫莘老墨妙亭','蘇轍','宋','宋诗','song-poetry','','[]','高岸爲谷谷爲陵，一時豪傑空飛騰。',192,'全唐诗/poet.song.47000.json','["高岸爲谷谷爲陵，一時豪傑空飛騰。", "身隨造化不復返，忽若野雀逢蒼鷹。", "當年碑刻最深固，風吹土蝕消無稜。", "遺文漫滅雨中迹，翠石斷裂春後冰。", "古墳欲毀野廟廢，行人不去征鞍憑。", "書生耽翫立風雪，饑馿厭苦疲奴憎。", "愛之欲取恨無力，旋揉翠墨濡黄繒。", "不如好事孫太守，牛車徙置華堂登。", "繞牆羅列耀珪璧，罷宴起讀留賓朋。", "却思遺迹本安在，原隰處處荒榛藤。", "田夫野老誰復顧，鬼火夜照來寒燈。", "廢興聚散一如此，反使涕泗沾人膺。"]'),
('518b368b-1bd7-4b94-830f-da8c1dcf2fd4','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 洛陽試院樓上新晴五絕 其一','蘇轍','宋','宋诗','song-poetry','','[]','縹緲危譙面面山，朝來雲作雨潺潺。',32,'全唐诗/poet.song.47000.json','["縹緲危譙面面山，朝來雲作雨潺潺。", "忽然風卷歸何處，百里陰晴反掌間。"]'),
('418aeb7e-f761-42b0-805a-6a3a93edab72','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 洛陽試院樓上新晴五絕 其二','蘇轍','宋','宋诗','song-poetry','','[]','嵩少猶藏薄霧中，前山迤邐夕陽紅。',32,'全唐诗/poet.song.47000.json','["嵩少猶藏薄霧中，前山迤邐夕陽紅。", "高樓一閉三十日，遥憶巖頭種藥翁。"]'),
('623c4214-86c1-46aa-af86-e5991b74271e','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 洛陽試院樓上新晴五絕 其三','蘇轍','宋','宋诗','song-poetry','','[]','伊闕遥臨鳳闕前，龍門女几氣蒼然。',32,'全唐诗/poet.song.47000.json','["伊闕遥臨鳳闕前，龍門女几氣蒼然。", "唐朝御路依稀在，猶想東巡塵暗天。"]'),
('54b49731-69e0-43c9-9e9f-29a936198828','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 洛陽試院樓上新晴五絕 其四','蘇轍','宋','宋诗','song-poetry','','[]','天壇王屋北侵河，高比嵩丘一倍多。',32,'全唐诗/poet.song.47000.json','["天壇王屋北侵河，高比嵩丘一倍多。", "小有清靈今尚在，俗緣深重奈成魔。"]'),
('2a505cee-7e15-408d-aca3-14723e2fd33e','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 洛陽試院樓上新晴五絕 其五','蘇轍','宋','宋诗','song-poetry','','[]','前朝宮闕倚芒山，殿閣層層半嶺間。',32,'全唐诗/poet.song.47000.json','["前朝宮闕倚芒山，殿閣層層半嶺間。", "猶恐北來岡阜淺，太行東抱故孱顔。"]'),
('0a610531-0588-45cc-8572-ce708a898864','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 和頓主簿起見贈二首 其一','蘇轍','宋','宋诗','song-poetry','','[]','聲病消磨只古文，諸儒經術鬥紛紜。',64,'全唐诗/poet.song.47000.json','["聲病消磨只古文，諸儒經術鬥紛紜。", "不知舊學都無用，猶把新書强欲分。", "老病心情愁見敵，少年詞氣動干雲。", "搜賢報國吾何敢，欲補空疏但有勤。"]'),
('c0d7c0a8-4a1d-4a50-808a-fd35530732ae','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 和頓主簿起見贈二首 其二','蘇轍','宋','宋诗','song-poetry','','[]','一鎖樓中暗度秋，微官黽勉未能休。',64,'全唐诗/poet.song.47000.json','["一鎖樓中暗度秋，微官黽勉未能休。", "笑談容我聊紓放，文字憑君便去留。", "杯酒淋漓已非敵，清詩窈眇更難酬。", "東歸猶得聯征騎，同上嵩高望九州。"]'),
('4bd7a193-9d38-44ac-8cc4-6cf2faafc9ea','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 將出洛城過廣愛寺見三學演師引觀楊惠之塑寶山朱瑶畫文殊普賢爲賦三首 其一','蘇轍','宋','宋诗','song-poetry','','[]','寺古依喬木，僧閑正莫年。',48,'全唐诗/poet.song.47000.json','["寺古依喬木，僧閑正莫年。", "爲生何寂寞，愛客尚留連。", "虛牖羅修竹，空厨響細泉。", "坐聽談舊事，遍識洛中賢。"]'),
('fd37ed08-1135-48e7-8fc4-09e59e5d8433','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 將出洛城過廣愛寺見三學演師引觀楊惠之塑寶山朱瑶畫文殊普賢爲賦三首 其二','蘇轍','宋','宋诗','song-poetry','','[]','虛室無尋丈，青山有百層。',48,'全唐诗/poet.song.47000.json','["虛室無尋丈，青山有百層。", "迴峰看不足，危石恐將崩。", "聽法來天女，依巖老梵僧。", "須彌傳納芥，觀此信還曾。"]'),
('c03b8eae-d4cc-4fa5-abfc-2a8018267051','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 將出洛城過廣愛寺見三學演師引觀楊惠之塑寶山朱瑶畫文殊普賢爲賦三首 其三','蘇轍','宋','宋诗','song-poetry','','[]','壁毀丹青在，移來殿廡深。',48,'全唐诗/poet.song.47000.json','["壁毀丹青在，移來殿廡深。", "賦形驚變態，觀佛覺無心。", "旌旆翻空色，笙竽含妙音。", "風流出吳樣，遺法到如今。"]'),
('fbc497b6-da19-4838-ab44-ba58daad17a9','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登封道中三絕 其一','蘇轍','宋','宋诗','song-poetry','','[]','飛仙不返周王子，重阜相連少室孫。',32,'全唐诗/poet.song.47000.json','["飛仙不返周王子，重阜相連少室孫。", "夜靜笙聲兼鶴下，迴看惟有故山存。"]'),
('b138d13d-246a-46bb-b2b9-32e81d1f548c','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登封道中三絕 其二','蘇轍','宋','宋诗','song-poetry','','[]','青山欲上疑無路，澗道相縈九十盤。',32,'全唐诗/poet.song.47000.json','["青山欲上疑無路，澗道相縈九十盤。", "東望嵩高分草木，回瞻原隰湧波瀾。"]'),
('5c7d3db6-97f7-47f1-93b6-1ac9bfe3c8c0','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登封道中三絕 其三','蘇轍','宋','宋诗','song-poetry','','[]','一徑喬林下黄葉，三山翠壁繞禪居。',32,'全唐诗/poet.song.47000.json','["一徑喬林下黄葉，三山翠壁繞禪居。", "共君將住還歸去，欲問安心知已疏。"]'),
('47a9dad8-4f84-434e-bba4-47d2a2436e46','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其一','蘇轍','宋','宋诗','song-poetry','','[]','蒼壁上參天，微徑隨流水。',48,'全唐诗/poet.song.47000.json','["蒼壁上參天，微徑隨流水。", "聱牙石齒亂，紛薄黄葉委。", "牽攀不得上，顛仆幾將止。", "勉强終此行，更老知難至。"]'),
('e9681489-fc35-4e7f-86ad-4686836c1e70','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其二','蘇轍','宋','宋诗','song-poetry','','[]','巖竇有虛明，曨曨發晴曉。',48,'全唐诗/poet.song.47000.json','["巖竇有虛明，曨曨發晴曉。", "真人無儔匹，窗下晨妝早。", "門開秋雨入，室靜長風掃。", "絕迹杳難尋，朱顔未嘗老。"]'),
('bec598ea-df8b-4e8c-ba6b-cc06d517170c','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其三','蘇轍','宋','宋诗','song-poetry','','[]','玉女雲爲衣，飄摇不須擣。',48,'全唐诗/poet.song.47000.json','["玉女雲爲衣，飄摇不須擣。", "空傳巖下石，夜杵知誰抱。", "清泉供澣濯，素月鋪繒縞。", "人世迫秋寒，處處砧聲早。"]'),
('862ea16c-6b22-4879-9acf-80196bce928c','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其四','蘇轍','宋','宋诗','song-poetry','','[]','上山苦饑渴，中道得寒泉。',48,'全唐诗/poet.song.47000.json','["上山苦饑渴，中道得寒泉。", "舉瓢石竇響，入口煩痾痊。", "洑流去不見，落澗聲鏘然。", "莫歸復相值，相從下平川。"]'),
('d27cbdab-13ae-4068-ab15-8d1185389cbe','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其五','蘇轍','宋','宋诗','song-poetry','','[]','重重山前峰，上上終非頂。',48,'全唐诗/poet.song.47000.json','["重重山前峰，上上終非頂。", "行登衆嶺徹，始得山門迥。", "高風慘多寒，落日側先暝。", "却視向所經，眇如在深井。"]'),
('b85e9016-6e34-43bf-a45c-c1c8aeddeae2','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其六','蘇轍','宋','宋诗','song-poetry','','[]','登封事已遥，大碑摧風雨。',48,'全唐诗/poet.song.47000.json','["登封事已遥，大碑摧風雨。", "靈壇久銷禿，古木中梁柱。", "峰巒至此盡，蒼石無寸土。", "俯視萬仞高，悲辛但狂顧。"]'),
('7a9f98af-93db-4a65-8e09-87071f2f0810','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其七','蘇轍','宋','宋诗','song-poetry','','[]','飛橋走巖居，茅屋今已破。',48,'全唐诗/poet.song.47000.json','["飛橋走巖居，茅屋今已破。", "何年避世僧，此地常獨卧。", "秋風高鳥入，夜月寒猿過。", "自非心已灰，靜極生悲惰。"]'),
('e328ec4c-f602-4dca-ad8e-3a6fe0a443a8','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其八','蘇轍','宋','宋诗','song-poetry','','[]','肅肅避暑宮，石殿秋日冷。',48,'全唐诗/poet.song.47000.json','["肅肅避暑宮，石殿秋日冷。", "凜然中庭柏，氣壓千夫整。", "風聲答萬壑，雲色通諸嶺。", "材大難爲工，甘與蓬蒿屏。"]'),
('b98d4817-1edd-498f-ad7f-dbd9632d6213','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其九','蘇轍','宋','宋诗','song-poetry','','[]','浮埃古壁上，蕭然四真人。',48,'全唐诗/poet.song.47000.json','["浮埃古壁上，蕭然四真人。", "矯如雲中鶴，猶若畏四鄰。", "坐令世俗士，自慚汙濁身。", "勿謂今所無，嵩少多隠淪。"]'),
('71355f0f-bf58-481b-99f9-3984c736f62d','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 登嵩山十首 其一○','蘇轍','宋','宋诗','song-poetry','','[]','神夫化黄熊，神母化白石。',48,'全唐诗/poet.song.47000.json','["神夫化黄熊，神母化白石。", "嬰兒剖還父，涕泣何暇卹。", "爾來三千歲，往事誰復識。", "惟有少姨存，相望居二室。"]'),
('1203beaa-2e87-4cb7-bd8c-96862f6f2f9b','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 過韓許州石淙莊','蘇轍','宋','宋诗','song-poetry','','[]','飛泉來無窮，發自嵩嶺背。',168,'全唐诗/poet.song.47000.json','["飛泉來無窮，發自嵩嶺背。", "奔馳兩山間，偶與亂石會。", "傾流勢摧毀，泥土久崩潰。", "堅姿未消釋，巀嶭儼相對。", "居然受噴潑，雷轉諸壑內。", "初喧墮深谷，稍放脫重隘。", "跳沫濺霏微，餘瀾洶澎湃。", "宸遊昔事遠，絕壁遺刻在。", "人迹久寂寥，物理係興廢。", "相君厭紛華，築室俯湍瀨。", "濯纓離塵垢，洗耳聽天籟。", "將追赤松遊，自置青雲外。", "道人亦何者，預此事歸計。", "猶恐山未深，更種萬株檜。"]'),
('c4eae737-d292-44d5-a50e-c1c9ce2fa206','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 過登封閻氏園','蘇轍','宋','宋诗','song-poetry','','[]','秋暑尚煩襟，林泉凈客心。',48,'全唐诗/poet.song.47000.json','["秋暑尚煩襟，林泉凈客心。", "菊殘知節過，荷盡覺池深。", "疏柳摇山色，青苔遍竹陰。", "猶嫌近官道，轣轆聽車音。"]'),
('d86e409f-c0cd-411d-ae53-1a39ecac935d','熙寧壬子八月於洛陽妙覺寺考試舉人及還道出嵩少之間至許昌共得大小詩二十六首 許州留別頓主簿','蘇轍','宋','宋诗','song-poetry','','[]','洛寺相從不出門，繞城空復記名園。',64,'全唐诗/poet.song.47000.json','["洛寺相從不出門，繞城空復記名園。", "程文堆案晨興早，竹簟連床夜雨喧。", "歸路逢僧暫容與，登山無力强扳援。", "遥知別後都如夢，頼有君詩一一存。"]'),
('21039a8d-8700-4bd8-9740-155ad40ce515','次韵子瞻登望海樓五絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','山色潮聲四面來，城中金碧爛成堆。',32,'全唐诗/poet.song.47000.json','["山色潮聲四面來，城中金碧爛成堆。", "不愁門外嚴扃鎖，終日憑欄未擬迴。"]'),
('dffe8a9c-9954-4dd9-958b-03f6ee1b11c1','次韵子瞻登望海樓五絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','湖色蒼蒼日向斜，烟波萬狀不容誇。',32,'全唐诗/poet.song.47000.json','["湖色蒼蒼日向斜，烟波萬狀不容誇。", "畫船人去浮紅葉，石徑僧歸躡白蛇。"]'),
('cdfabf40-a42f-4fb1-a745-f328b35912f7','次韵子瞻登望海樓五絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','樓觀爭高不計層，噰噰過雁自相譍。',32,'全唐诗/poet.song.47000.json','["樓觀爭高不計層，噰噰過雁自相譍。", "錢王舊業依稀在，歲久無人話廢興。"]'),
('caa5f7df-dabb-40b0-97cc-207bc4a6d2ea','次韵子瞻登望海樓五絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','荷葉初乾稻穗香，驚雷急雨送微凉。',32,'全唐诗/poet.song.47000.json','["荷葉初乾稻穗香，驚雷急雨送微凉。", "晚晴稍放秋山色，洗却濃妝作淡妝。"]'),
('98f69cd8-6ac4-4a7b-90b9-2f0c1be13b0f','次韵子瞻登望海樓五絕  其五','蘇轍','宋','宋诗','song-poetry','','[]','白酒傾漿膾斫紅，晝遊未厭月明中。',32,'全唐诗/poet.song.47000.json','["白酒傾漿膾斫紅，晝遊未厭月明中。", "樓高只辦聽歌鼓，不見遊人轉似蓬。"]'),
('ee7cc7f5-4b73-49c6-b154-09536b5de54d','和子瞻監試舉人','蘇轍','宋','宋诗','song-poetry','','[]','登科歲云徂，舊學日將落。',288,'全唐诗/poet.song.47000.json','["登科歲云徂，舊學日將落。", "外遭饑寒侵，內苦憂患鑠。", "傳家足墳史，遺說本精約。", "羣言久紛蕩，開卷每驚矍。", "居官忝庠序，授業止干籥。", "朝廷發新令，長短棄前彠。", "緣飾小學家，睥睨前王作。", "聲形一分解，道義因附託。", "安行厭衢路，强挽就縻縛。", "縱橫施口鼻，爛熳塗丹堊。", "强辯忽橫流，漂蕩終安泊。", "憶惟法初傳，欲講面先怍。", "新科勸多士，從者盡高爵。", "徘徊始未信，衒誘終難却。", "嗟哉守愚鈍，幾不被譏謔。", "獨醒慚餔糟，未信耻輕諾。", "敢言折鋒鋩，但自保城郭。", "有司顧未知，選試謬西洛。", "羣儒誰號令，新語競投削。", "雖云心所安，恐異時量度。", "詭遇便巧射，晚嫁由拙妁。", "誰能力春耕，忍饑待秋穫。", "聞兄職在監，考較筆仍閣。", "縮手看傍人，此意殊未惡。"]'),
('958196cd-d5be-43d5-af8d-ecd8e99f304c','和子瞻煎茶','蘇轍','宋','宋诗','song-poetry','','[]','年來病懶百不堪，未廢飲食求芳甘。',142,'全唐诗/poet.song.47000.json','["年來病懶百不堪，未廢飲食求芳甘。", "煎茶舊法出西蜀，水聲火候猶能諳。", "相傳煎茶只煎水，茶性仍存偏有味。", "君不見閩中茶品天下高，傾身事茶不知勞。", "又不見北方俚人茗飲無不有，鹽酪椒薑誇滿口。", "我今倦遊思故鄉，不學南方與北方。", "銅鐺得火蚯蚓叫，匙脚旋轉秋螢光。", "何時茅檐歸去炙背讀文字，遣兒折取枯竹女煎湯。"]'),
('ad8bc9d6-5c4f-49e9-89af-b48dc07c5031','次韵子瞻對月見憶並簡崔度','蘇轍','宋','宋诗','song-poetry','','[]','先師客陳未嘗飽，弟子于今敢言巧。',96,'全唐诗/poet.song.47000.json','["先師客陳未嘗飽，弟子于今敢言巧。", "敗牆破屋秋雨多，夜視陰精過畢昴。", "齏鹽冷落空杯盤，且依道士修還丹。", "丹田發火五臟暖，未補漫漫長夜寒。", "我生疲駑戀莝豆，崔翁遊邊指北斗。", "唯有王江亦未歸，閉門無客邀沽酒。"]'),
('113ed5d0-75fe-4e18-bf96-219ec28061df','和子瞻開湯村運鹽河雨中督役','蘇轍','宋','宋诗','song-poetry','','[]','興事常苦易，成事常苦難。',120,'全唐诗/poet.song.47000.json','["興事常苦易，成事常苦難。", "不督雨中役，安知民力殫。", "年來上功勳，智者爭雕鑽。", "山河不自保，疏鑿非一端。", "譏訶西門豹，仁智未得完。", "方以勇自許，未卹衆口嘆。", "天心閔劬勞，雨涕爲汍瀾。", "不知泥滓中，更益手足寒。", "誰謂邑中黔，鞭箠亦不寬。", "王事未可回，后土何由乾。"]'),
('c9eed846-727c-421e-9ce9-577914deb661','次韵子瞻雨中督役夜宿水陸寺二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','雲氣連山雨瀉盆，莫投僧舍欲關門。',64,'全唐诗/poet.song.47000.json','["雲氣連山雨瀉盆，莫投僧舍欲關門。", "暫時灑掃寬行役，終夕崎嶇入夢魂。", "煩熱暗消秋簟冷，烝濡未解夜燈昏。", "二年遊宦多勞苦，何日相從得細論。"]'),
('01ae8938-a704-4de2-8b7b-2c1ebe59e70c','次韵子瞻雨中督役夜宿水陸寺二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','野寺蕭條厭客喧，雨披修竹亂紛然。',64,'全唐诗/poet.song.47000.json','["野寺蕭條厭客喧，雨披修竹亂紛然。", "已因無食聊從仕，深悟勞生不問禪。", "未至莫憂明日事，偷閑且就此宵眠。", "天明歸去芒鞋滑，雖有藤輿懶上肩。"]'),
('d484d58e-515f-459b-ac06-6aa529e6505c','次韵子瞻將之吳興贈孫莘老','蘇轍','宋','宋诗','song-poetry','','[]','宦遊莫向長城窟，冬冰折膠弦亦絕。',96,'全唐诗/poet.song.47000.json','["宦遊莫向長城窟，冬冰折膠弦亦絕。", "吳中臘月百事便，蟹煮黄金鱸鱠雪。", "京城舊友一分散，近憶吳興須滿頰。", "世事反復如翻飛，今日共鯀前益垂。", "畏人但恐去不遠，適意未覺歸來遲。", "借問校讎天祿閣，何如江海同遊嬉。"]'),
('45eb8aae-0e98-4da9-862d-c7617fe8d54d','和子瞻畫魚歌','蘇轍','宋','宋诗','song-poetry','','[]','潛魚在淵安可及，垂餌投竿易如拾。',96,'全唐诗/poet.song.47000.json','["潛魚在淵安可及，垂餌投竿易如拾。", "橫江設網雖不仁，一瞬未移收百十。", "畫魚何者漫區區，終日辛勤手拮据。", "已嫌長網不能遍，肯信一竿良有餘。", "鯤鯢駭散蛟龍泣，獲少驚多亦何益。", "願從網罟登君庖，碎首屠鱗非所惜。"]'),
('eb5eac08-6185-4e1e-9914-3dd88749a0f9','次韵子瞻吳中田婦嘆','蘇轍','宋','宋诗','song-poetry','','[]','久雨得晴唯恐遲，既晴求雨來何時。',128,'全唐诗/poet.song.47000.json','["久雨得晴唯恐遲，既晴求雨來何時。", "今年舟楫委平地，去年簑笠爲裳衣。", "不知天公誰怨怒，棄置下土塵與泥。", "丈夫强健四方走，婦女齷齪將安歸。", "塌然四壁倚機杼，收拾遺粒吹糠粞。", "東鄰十日營一炊，西鄰誰使救汝饑。", "海邊唯有鹽不旱，賣鹽連坐收嬰兒。", "傳聞四方同此苦，不關東海誅孝婦。"]'),
('158fc4ac-917f-4eb3-9978-ba97d27a0b85','次韵子瞻遊道場山何山','蘇轍','宋','宋诗','song-poetry','','[]','兩山相負爲峰麓，流水重重注溪谷。',160,'全唐诗/poet.song.47000.json','["兩山相負爲峰麓，流水重重注溪谷。", "遊人上尋流水源，未覺崎嶇病雙足。", "山深下視雲漫漫，徑垂石底千屈盤。", "松林陰森白日靜，忽驚人世如奔湍。", "客行不避苦寒出，僧定端居不下席。", "人生嗟與草木同，置身所在由初植。", "堂中白佛青髻鬟，氣象沖淡非人間。", "坐令遠客厭奔走，徑欲築室依空山。", "木魚桹桹夜將旦，星斗欹斜掛山半。", "行役有程未可留，將出山門復長嘆。"]'),
('a31f3d64-e0e0-442c-8b0e-be5038aff707','癸丑二月重到汝陰寄子瞻二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','憶赴錢塘九月秋，同來潁尾一扁舟。',64,'全唐诗/poet.song.47000.json','["憶赴錢塘九月秋，同來潁尾一扁舟。", "退居尚有三師在，好事須爲十日留。", "傾瀉向人懷抱盡，忠誠爲國始終憂。", "重來東閣皆塵土，淚滴春風自不收。"]'),
('dc33fee3-4a81-4f59-b5a3-d5d2ac1aa582','癸丑二月重到汝陰寄子瞻二首  其二','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百頃西湖十里源，近依城郭带川原。',64,'全唐诗/poet.song.47000.json','["百頃西湖十里源，近依城郭带川原。", "古臺駊騀先臨水，野寺參差半掩門。", "遠泛便成終日醉，幽尋不盡數家園。", "錢塘未到能先說，更着青山兩岸屯。"]'),
('57269410-6eb8-47d9-85a2-2f422a54b66b','次韵子瞻二月十日雪','蘇轍','宋','宋诗','song-poetry','','[]','春雪漫天密又稀，勾芒失據走靈威。',64,'全唐诗/poet.song.47000.json','["春雪漫天密又稀，勾芒失據走靈威。", "故欺貧窶冬裘盡，巧助遨遊酒盞飛。", "林下細花添百草，階前輕素剪新機。", "老農先解憂桑柘，九月家人當授衣。"]'),
('a17371d4-9fc7-487a-84ef-33a77dd52199','和子瞻題風水洞','蘇轍','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','風送江湖滿洞天，洞門可聽入無緣。',64,'全唐诗/poet.song.48000.json','["風送江湖滿洞天，洞門可聽入無緣。", "土囊鬰怒聲初散，石齒聱牙勢未前。", "樂奏洞庭真跌宕，歌傳帝所亦清便。", "何人隠几觀遺韵，重使顔成問嗒然。"]'),
('d07bd25f-f5da-49ae-8137-3395d346bfc0','次韵子瞻新城道中','蘇轍','宋','宋诗','song-poetry','','[]','春深溪路少人行，時聽田間耒耜聲。',64,'全唐诗/poet.song.48000.json','["春深溪路少人行，時聽田間耒耜聲。", "饑就野農分餉黍，迎嫌尉卒鬧金鉦。", "閑花開盡香仍在，白酒沽來壓未清。", "此味暫時猶覺勝，問兄何日便歸耕。"]'),
('27531512-9344-4327-af3c-9608b0841710','次韵子瞻山村五絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','山行喜遇酒旗斜，無限桃花續杏花。',32,'全唐诗/poet.song.48000.json','["山行喜遇酒旗斜，無限桃花續杏花。", "與世浮沉真避世，將家漂蕩似無家。"]'),
('34d8bf19-26c7-453b-9bee-8f909fc9a0f7','次韵子瞻山村五絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','塍間白水細無聲，日暖泥融草不生。',32,'全唐诗/poet.song.48000.json','["塍間白水細無聲，日暖泥融草不生。", "似恐田家忘帝力，多差使者出催耕。"]'),
('8d104b55-d445-4b04-a6e7-46d8a52b2dcc','次韵子瞻山村五絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','旋舂紅稻始經鎌，新煮黄鷄取次甜。',32,'全唐诗/poet.song.48000.json','["旋舂紅稻始經鎌，新煮黄鷄取次甜。", "無慕無營人自樂，莫將西子愧無鹽。"]'),
('34dc97f2-965c-44db-88f7-80a9a1ebd963','次韵子瞻山村五絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','升平事業苦匆匆，未信浮名到底空。',32,'全唐诗/poet.song.48000.json','["升平事業苦匆匆，未信浮名到底空。", "保用橐駝朝塞外，試聽碌軸語場中。"]'),
('ec1ba8a9-0294-4247-8a8a-c277f314b9bd','次韵子瞻山村五絕  其五','蘇轍','宋','宋诗','song-poetry','','[]','貧賤終身未要羞，山林難處便堪愁。',32,'全唐诗/poet.song.48000.json','["貧賤終身未要羞，山林難處便堪愁。", "近來南海波尤惡，未許乘桴自在遊。"]'),
('6c7424a0-298a-4c41-b59d-3b18fe86f372','次韵子瞻遊富陽普照寺','蘇轍','宋','宋诗','song-poetry','','[]','塵埃日已遠，斗藪更無餘。',48,'全唐诗/poet.song.48000.json','["塵埃日已遠，斗藪更無餘。", "寺到逢門入，詩成信手書。", "山深僧自樂，路遠客終疏。", "訪盡前朝景，它年一告予。"]'),
('b19dda1e-f6ce-42ab-a565-1bc03bdf8a52','次韵子瞻自普照入山獨遊二庵','蘇轍','宋','宋诗','song-poetry','','[]','披榛入山山路細，鐘聲出寺門將閉。',96,'全唐诗/poet.song.48000.json','["披榛入山山路細，鐘聲出寺門將閉。", "石苔冉冉上芒鞋，草露漙漙著衣袂。", "野人茅茨苫竹屋，終身局促無生計。", "天公未省長困人，春田米盡秋田繼。", "老妻稚子亦自樂，野草山花還插髻。", "長笑人間醉未醒，終老辛勤漫欺世。"]'),
('3163d2d2-dc3e-4187-a31b-bd3b792417b5','次韵子瞻與蘇世美同年夜飲','蘇轍','宋','宋诗','song-poetry','','[]','晚歲事遊宦，相從未嘗足。',76,'全唐诗/poet.song.48000.json','["晚歲事遊宦，相從未嘗足。", "羨君四海皆兄弟，棧中直木不容曲。", "臨安老令况同科，相逢豈厭樽中牀。", "潦倒誰憐澗底松，歲寒尚有霜前竹。", "聞道渠家八丈夫，它日歸耕免幽獨。"]'),
('3bef90b9-d0fa-4c11-9cf0-2d86483e24fb','次韵子瞻病中遊虎跑泉僧舍二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','掃地開門松檜香，僧家長夏亦清凉。',64,'全唐诗/poet.song.48000.json','["掃地開門松檜香，僧家長夏亦清凉。", "公庭多事久來厭，凈處安眠計甚長。", "修竹填窗藤簟綠，白蓮當戶石盆方。", "香厨晚飯紅粳熟，忽憶烹鷄田舍嘗。"]'),
('2525afc5-34bd-4076-8bdc-9540f6d0853e','次韵子瞻病中遊虎跑泉僧舍二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','澗谷新晴草木香，野情蕭散自生凉。',64,'全唐诗/poet.song.48000.json','["澗谷新晴草木香，野情蕭散自生凉。", "雨添山色翠將溜，日轉松陰晚更長。", "病客獨來唯有睡，遊僧相見亦它方。", "還家煩熱都消盡，不信醫王與藥嘗。"]'),
('ada45439-edc9-4d3b-acce-8950ef5c0642','和子瞻東陽水樂亭歌','蘇轍','宋','宋诗','song-poetry','','[]','君不見武安前堂立曲旃，官高利厚多憂患。',154,'全唐诗/poet.song.48000.json','["君不見武安前堂立曲旃，官高利厚多憂患。", "又不見夏侯好妓貧無力，簾箔爲衣人莫識。", "兩人操行雖不同，辛苦經營實如一。", "不如君家激水石中流，聽之有聲百無憂。", "笙竽窈眇度溪谷，琴筑凄咽穿林丘。", "高人處世心淡泊，衆聲過耳皆爲樂。", "退食委蛇石上眠，幽音斷續床前作。", "正如古人樂易多歡娛，積土爲鼓塊爲桴。", "但能復作太古意，君家水樂真有餘。"]'),
('d3dc51fe-0ace-4c66-a3a3-23382fbc3835','次韵子瞻有美堂夜歸','蘇轍','宋','宋诗','song-poetry','','[]','飲闌鐘虡欲移軒，香霧猶殘金博山。',64,'全唐诗/poet.song.48000.json','["飲闌鐘虡欲移軒，香霧猶殘金博山。", "明月飛來松嶺外，遊人散落馬蹄間。", "城嚴畫鼓初傳角，路暗山花自落鬟。", "清境暫時都不見，夜深人盡始來還。"]'),
('f417b706-284a-479d-8304-ecf42cd4e70b','次韵子瞻祈雨','蘇轍','宋','宋诗','song-poetry','','[]','世故紛紛誰復閑，蛟龍不雨獨安眠。',64,'全唐诗/poet.song.48000.json','["世故紛紛誰復閑，蛟龍不雨獨安眠。", "人間已厭三秋旱，澗底猶慳一掬泉。", "廟令酒肴時醉飽，田家糠粃久安便。", "憂心未已誰知卹，更把爐香試一燃。"]'),
('9c266592-5f3a-402e-9017-c627fb4f813a','次韵子瞻再遊徑山','蘇轍','宋','宋诗','song-poetry','','[]','我兄東南遊，我亦夢中去。',96,'全唐诗/poet.song.48000.json','["我兄東南遊，我亦夢中去。", "徑山聞已熟，往意穿雲霧。", "夢經山前溪，足冷忽先渡。", "舉頭雲峰合，到寺霜日莫。", "香厨饌巖蔌，野徑踏藤屨。", "平生共遊處，騫足躡高步。", "崎嶇每生胝，眩晃屢回顧。", "何年棄微官，携手衆山路。"]'),
('bcdd595c-7406-4ecb-bcca-1fb2f5df80ff','王仲儀尚書挽詞','蘇轍','宋','宋诗','song-poetry','','[]','謝公德業久彌新，幼度英奇也絕倫。',64,'全唐诗/poet.song.48000.json','["謝公德業久彌新，幼度英奇也絕倫。", "父子俱賢真不朽，功名自致豈相因。", "邊兵屢動思良將，廷論蕭條憶諍臣。", "青史世家它日事，新阡宿草倍沾巾。"]'),
('32754729-b580-4cdf-b18e-567a7e029b40','次韵范景仁侍郎移竹','蘇轍','宋','宋诗','song-poetry','','[]','雙檜生南戶，叢筠種北牆。',48,'全唐诗/poet.song.48000.json','["雙檜生南戶，叢筠種北牆。", "交陰奉君子，爲伴老中堂。", "露洗秋階綠，風含夏簟凉。", "栽花知已誤，新上一番霜。"]'),
('71db93b8-f007-4fd6-b6fd-433168854ad4','寄題蒲傳正學士閬中藏書閣','蘇轍','宋','宋诗','song-poetry','','[]','朱欄碧瓦照山隈，竹簡牙籤次第開。',64,'全唐诗/poet.song.48000.json','["朱欄碧瓦照山隈，竹簡牙籤次第開。", "讀破文章隨意得，學成富貴逼身來。", "詩書教子真田宅，金玉傳家定糞灰。", "更把遺編觀得失，君家舊物豈須猜。"]'),
('f0e41a41-aa38-4e10-afe2-1bfea137c740','自陳適齊戲題','蘇轍','宋','宋诗','song-poetry','','[]','庠齋三歲最無功，羞愧宣王祿萬鍾。',64,'全唐诗/poet.song.48000.json','["庠齋三歲最無功，羞愧宣王祿萬鍾。", "猶欲談經誰復信，相招執籥更須從。", "陳風清凈眠真足，齊俗强梁懶不容。", "久爾安閑長自怪，此行磨折信天工。"]'),
('1070642a-5686-4a58-b128-42b0c9219ded','送董揚休比部知真州','蘇轍','宋','宋诗','song-poetry','','[]','奏課西南最，分符江海衝。',48,'全唐诗/poet.song.48000.json','["奏課西南最，分符江海衝。", "往來觀惠術，蟠錯試餘鋒。", "文字從堆案，樽罍强解容。", "金山只隔水，時復聽晨鐘。"]'),
('4e394209-72a5-49ca-9df8-2071046f2b39','送排保甲陳祐甫','蘇轍','宋','宋诗','song-poetry','','[]','我生本西南，爲學慕齊魯。',120,'全唐诗/poet.song.48000.json','["我生本西南，爲學慕齊魯。", "從事東諸侯，結綬濟南府。", "誰言到官舍，旱氣裂后土。", "饑饉費囷倉，剽奪驚桴鼓。", "緬焉禮義邦，憂作流亡聚。", "君來正此時，王事最勤苦。", "驅馳黄塵中，勸說野田父。", "穰穰百萬家，一一連什伍。", "政令當及期，田閭貴安堵。", "歸乘忽言西，劬勞共誰語。"]'),
('7cce6cde-833a-445a-9aec-6e3b3fc6f401','送韓祗嚴戶曹得替省親成都','蘇轍','宋','宋诗','song-poetry','','[]','宦遊東土暫相依，政役頻煩會合稀。',64,'全唐诗/poet.song.48000.json','["宦遊東土暫相依，政役頻煩會合稀。", "每恃詳明容老病，不堪羈旅送將歸。", "思親道路寧論遠，入蜀山河漸覺非。", "我有舊廬江水上，因君聊復夢魂飛。"]'),
('12ecf8e1-66ab-4af5-a8af-8bea73aaf5cb','和孔教授武仲濟南四咏 環波亭','蘇轍','宋','宋诗','song-poetry','','[]','南山迤邐入南塘，北渚岧嶢枕北牆。',64,'全唐诗/poet.song.48000.json','["南山迤邐入南塘，北渚岧嶢枕北牆。", "過盡綠荷橋斷處，忽逢朱檻水中央。", "鳧鷖聚散湖光凈，魚鱉浮沉瓦影凉。", "清境不知三伏熱，病身唯要一藤床。"]'),
('d13af9b0-0751-4f0a-b670-f2c79c6f4bd6','和孔教授武仲濟南四咏 北渚亭','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖已過百花汀，未厭相携上古城。',64,'全唐诗/poet.song.48000.json','["西湖已過百花汀，未厭相携上古城。", "雲放連山瞻嶽麓，雪消平野看春耕。", "臨風舉酒千鍾盡，步月吹笳十里聲。", "猶恨雨中人不到，風雲飄蕩恐神驚。"]'),
('70c78aaa-30b0-497c-9c17-39bebf37accb','和孔教授武仲濟南四咏 鵲山亭','蘇轍','宋','宋诗','song-poetry','','[]','築臺臨水巧安排，萬象軒昂發瘞埋。',64,'全唐诗/poet.song.48000.json','["築臺臨水巧安排，萬象軒昂發瘞埋。", "南嶺崩騰來不盡，北山斷續意尤佳。", "平時戰伐皆荒草，永日登臨慰病懷。", "更欲留詩題素壁，坐中誰與少陵偕。"]'),
('1aa471f7-712e-4a0c-b308-ace1c09507e3','和孔教授武仲濟南四咏 檻泉亭','蘇轍','宋','宋诗','song-poetry','','[]','連山带郭走平川，伏澗潛流發湧泉。',64,'全唐诗/poet.song.48000.json','["連山带郭走平川，伏澗潛流發湧泉。", "洶洶秋聲明月夜，蓬蓬曉氣欲晴天。", "誰家鵝鴨橫波去，日暮牛羊飲道邊。", "滓穢未能妨潔凈，孤亭每到一依然。"]'),
('1d8b7180-4daf-4461-831c-3a5c94d1e1a6','踏藕','蘇轍','宋','宋诗','song-poetry','','[]','春湖柳色黄，宿藕凍猶僵。',48,'全唐诗/poet.song.48000.json','["春湖柳色黄，宿藕凍猶僵。", "翻沼龍蛇動，撐船牙角長。", "清泉浴泥滓，粲齒碎冰霜。", "莫使新梢盡，炎風翠蓋凉。"]'),
('b1ef88f5-a9e8-4dc3-a205-1af8c78fbc8d','和李誠之待制宴別西湖','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東來亦何恃，夫子此分符。',96,'全唐诗/poet.song.48000.json','["東來亦何恃，夫子此分符。", "談笑萬事畢，樽罍衆客俱。", "高情生遠岫，清興發平湖。", "坐使羈遊士，能忘歲月徂。", "縱歡真樂易，恨別不須臾。", "廟幄新謀帥，河間最近胡。", "安邊本餘事，清賞信良圖。", "應念茲園好，流泉海內無。"]'),
('5aedec4d-d429-4711-94dc-91b15d06a753','送李誠之知瀛州','蘇轍','宋','宋诗','song-poetry','','[]','少年學詩書，晚歲探至道。',120,'全唐诗/poet.song.48000.json','["少年學詩書，晚歲探至道。", "豈伊封疆臣，乃是廊廟寶。", "苦恨富貴遲，聲名得空早。", "憶惟西羌桀，始建元戎纛。", "恩威炳朝日，號令靡秋草。", "功勳不容究，孤高易摧倒。", "歸來易三邦，但養胸中顥。", "寧知北邊將，還須用耆老。", "春風吹旌旆，先聲遍城堡。", "往事安足懲，遺黎待公保。"]'),
('140394cb-804a-43e2-aaa8-db906a896231','西湖二咏 觀捕魚','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖不放長竿入，羣魚空作淘河食。',128,'全唐诗/poet.song.48000.json','["西湖不放長竿入，羣魚空作淘河食。", "漁人攘臂下前汀，蕩漾清波浮兩腋。", "藕梢菱蔓不容網，箔作長圍徒手得。", "逡巡小舟十斛重，踊躍長魚一夫力。", "柳條穿頰洗黄金，鱠縷堆盤雪花積。", "燒薤香橙巧相與，白飯青蔬甘莫逆。", "食罷相携堤上步，將散重煎葉家白。", "人生此事最便身，金印垂腰定何益。"]'),
('35cb3296-b155-4e02-8e35-329c23497bdc','西湖二咏 食鷄頭','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','芡葉初生縐如縠，南風吹開輪脫轂。',128,'全唐诗/poet.song.48000.json','["芡葉初生縐如縠，南風吹開輪脫轂。", "紫苞青刺攢蝟毛，水面放花波底熟。", "森然赤手初莫近，誰料明珠藏滿腹。", "剖開膏液尚模糊，大盎磨聲風雨速。", "清泉活火曾未久，滿堂坐客分升掬。", "紛然咀噍惟恐遲，勢若羣雛方脫粟。", "東都每憶會靈沼，南國陂塘種尤足。", "東遊塵土未應嫌，此物秋來日嘗食。"]'),
('2b0c35e8-d66c-4c80-bcec-d72a2a4135d4','次韵孫推官朴見寄二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','蒙慍未能憂悄悄，得閑時復醉昏昏。',32,'全唐诗/poet.song.48000.json','["蒙慍未能憂悄悄，得閑時復醉昏昏。", "知君亦學無言語，豈悟維摩不二門。"]'),
('3e0e2389-4e67-489d-923b-007b6e19a02a','次韵孫推官朴見寄二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','病懶近來全廢學，宦游唯是苦思鄉。',64,'全唐诗/poet.song.48000.json','["病懶近來全廢學，宦游唯是苦思鄉。", "粗知會計猶堪仕，貪就功名有底忙。", "懷舊暗聽秋雁過，夢歸偏愛曉更長。", "故人知我今何念，擬向東山賦首章。"]'),
('1bd19699-452c-46e8-98fe-608395a101c3','送張正彥法曹','蘇轍','宋','宋诗','song-poetry','','[]','憶見君兄弟，相携謁侍郎。',72,'全唐诗/poet.song.48000.json','["憶見君兄弟，相携謁侍郎。", "通經誇早歲，落筆盡成章。", "試劇何輕銳，當官便激昂。", "三年知力竭，大府覺才長。", "知已未如格，歸貲纔滿囊。", "舊書還讀否，師說近凄凉。"]'),
('69a52f56-21c6-42c6-a3ae-f13d8f3df86d','送青州簽判俞退翁致仕還湖州','蘇轍','宋','宋诗','song-poetry','','[]','不作清時言事官，海邦那復久盤桓。',64,'全唐诗/poet.song.48000.json','["不作清時言事官，海邦那復久盤桓。", "早依蓮社塵緣少，新就草堂歸計安。", "富貴暫時朝露過，江山故國水精寒。", "宦游從此知多事，收取楞伽靜處看。"]'),
('91e5941c-faed-4613-a78a-d24ebf5db2f1','和青州教授頓起九日見寄','蘇轍','宋','宋诗','song-poetry','','[]','歲月飄然風際煙，紫萸黄菊又霜天。',64,'全唐诗/poet.song.48000.json','["歲月飄然風際煙，紫萸黄菊又霜天。", "莫思太室杉松外，且醉青州歌舞前。", "杯酒追歡真一夢，天涯回望正三年。", "近來又欲東觀海，聽說毛詩雅頌篇。"]'),
('935e8aa1-fca9-41ca-aaaf-965231cc7f14','題徐正權秀才城西溪亭','蘇轍','宋','宋诗','song-poetry','','[]','竹林分徑水通渠，真與幽人作隠居。',64,'全唐诗/poet.song.48000.json','["竹林分徑水通渠，真與幽人作隠居。", "溪上路窮惟畫舫，城中客至有罾魚。", "東來只爲林泉好，野外從教簿領疏。", "不識徂徠石夫子，兼因女婿覓遺書。"]'),
('eb5d486f-738e-4e24-b2ae-55654249e239','和子瞻喜虎兒生','蘇轍','宋','宋诗','song-poetry','','[]','生男如狼猶恐尪，寅年生虎慰爺娘。',96,'全唐诗/poet.song.48000.json','["生男如狼猶恐尪，寅年生虎慰爺娘。", "汝家家世事文史，門戶豈有空剛强。", "試看猛虎在山谷，斧牙鈎爪旗尾揚。", "徐行當道擇牛羊，狐狸驚走熊豬忙。", "我今老病思退藏，生子安得尚激昂。", "不見伯父擅文章，逡巡議論前無當。"]'),
('87c18148-d7d1-4b5b-b379-418daa52414a','次韵子瞻病中贈提刑段繹','蘇轍','宋','宋诗','song-poetry','','[]','京東分東西，中劃齊魯半。',192,'全唐诗/poet.song.48000.json','["京東分東西，中劃齊魯半。", "兄來本相從，路絕一長嘆。", "前朝使者還，手把新詩玩。", "憐我久別離，卷帙爲舒散。", "誰言窮陋邦，得此唱酬伴。", "相逢傾蓋間，晤語何旦旦。", "宦遊少娛樂，纏縛苦文案。", "能於王事餘，時作楚詞亂。", "譬如近膏油，未肯忘濯盥。", "賢豪真勉强，功業畏繚緩。", "伊余獨何爲，舊籍西南貫。", "竊祿未遑歸，自笑嗟已懦。", "方當四海寒，戀此一寸炭。", "主倦客欲留，逡巡要奪館。", "奈何獨見收，軟言强溫暖。", "此意定難酬，還予授子粲。"]'),
('bf5f75d8-ad64-4c99-9238-d01e28ea1e63','次韵子瞻賦雪二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','麥苗出土正纖纖，春早寒官令尚嚴。',64,'全唐诗/poet.song.48000.json','["麥苗出土正纖纖，春早寒官令尚嚴。", "雲覆南山初半嶺，風乾東海盡成鹽。", "來時瞬息平吞野，積久欹危欲敗檐。", "强付酒樽判醉熟，更尋詩句鬥新尖。"]'),
('d7d4dbc6-aeec-401e-be3e-4515afa1602c','次韵子瞻賦雪二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','點綴偏工亂鵠鴉，淹留欲解惱船車。',64,'全唐诗/poet.song.48000.json','["點綴偏工亂鵠鴉，淹留欲解惱船車。", "乘春已覺矜餘力，騁巧時能作細花。", "僵雁墮鴟誰得罪，敗牆破壁若爲家。", "天公愛物遥憐汝，應是門前守夜叉。"]'),
('752f2502-5f0a-46e4-9af4-c3ca8e6e1219','次韵韓宗弼太祝送遊太山','蘇轍','宋','宋诗','song-poetry','','[]','羨君官局最優遊，笑我區區學問囚。',64,'全唐诗/poet.song.48000.json','["羨君官局最優遊，笑我區區學問囚。", "今日登臨成獨往，終年勤苦粗相酬。", "春深綠野初開繡，雲解青山半脫裘。", "回首紅塵讀書處，煮茶留客小亭幽。"]'),
('752238bb-efcf-4bd2-bc03-01dd9d5a671d','次韵劉敏殿丞送春','蘇轍','宋','宋诗','song-poetry','','[]','春去堂堂不復追，空餘草木弄晴暉。',64,'全唐诗/poet.song.48000.json','["春去堂堂不復追，空餘草木弄晴暉。", "交遊歸雁行將盡，蹤迹鳴鳩懶不飛。", "老大未須驚節物，醉狂兼得避危機。", "東風雖有經旬在，芳意從今日日非。"]'),
('7322e636-e0b6-4870-93bd-54573ec43778','次韵趙至節推首夏','蘇轍','宋','宋诗','song-poetry','','[]','首夏尋芳也未遲，繞園紅紫尚菲菲。',64,'全唐诗/poet.song.48000.json','["首夏尋芳也未遲，繞園紅紫尚菲菲。", "無心與物真皆可，有酒逢人勸莫違。", "夢逐楊花無限思，身慚啼鳥不如歸。", "官居寂寞如僧舍，海燕憐貧故入扉。"]'),
('9bf4c396-ebc2-4713-920d-675f04c973e4','次韵李昭敘供備宴別湖亭','蘇轍','宋','宋诗','song-poetry','','[]','池亭雨過一番凉，雲髻羅裙客兩旁。',64,'全唐诗/poet.song.48000.json','["池亭雨過一番凉，雲髻羅裙客兩旁。", "不覺行人離恨遠，貪看積水照筵光。", "滿堂樽俎歡方劇，極目江湖意自長。", "歸去伊川瀟灑地，不須遺念屬清湘。"]'),
('4e3cc22c-6588-4897-8974-8549df64428c','送李昭敘移黎陽都監歸洛省親','蘇轍','宋','宋诗','song-poetry','','[]','與君非舊識，傾蓋便相親。',96,'全唐诗/poet.song.48000.json','["與君非舊識，傾蓋便相親。", "共事林泉郡，忘歸南北人。", "煮茶流水曲，載酒後湖滣。", "未覺遊從厭，空驚別恨新。", "瀕河今重地，知己舊元臣。", "洛下聞鷄犬，家書不浹旬。", "西還倚門罷，北渡羽書頻。", "忠孝傳家事，風流待一振。"]'),
('b0389cbe-166e-4446-856c-6bf585c842a0','遊太山四首 初入南山','蘇轍','宋','宋诗','song-poetry','','[]','自我來濟南，經年未嘗出。',144,'全唐诗/poet.song.48000.json','["自我來濟南，經年未嘗出。", "不知西城外，有路通石壁。", "初行澗谷淺，漸遠峰巒積。", "翠屏互舒卷，耕耨隨欹側。", "雲木散山阿，逆旅時百室。", "茲人謂川路，此意屬行客。", "久遊自多念，忽誤向所歷。", "嘉陵萬壑底，棧道百迴屈。", "崖巘遞崢嶸，征夫時出沒。", "行李雖云艱，幽邃亦已劇。", "坐緣斗升米，被此塵土厄。", "何年道褒斜，長嘯理輕策。"]'),
('6d35869f-18aa-4bde-842c-b1029babc205','遊太山四首 四禪寺','蘇轍','宋','宋诗','song-poetry','','[]','山蹊容車箱，深入遂有得。',144,'全唐诗/poet.song.48000.json','["山蹊容車箱，深入遂有得。", "古寺依巖根，連峰轉相揖。", "樵蘇草木盡，佛事亦蕭瑟。", "居僧麋鹿人，對客但羞澀。", "雙碑立風雨，八分存法則。", "云昔義靖師，萬里窮西域。", "華嚴具多紙，歸來手親譯。", "蛻骨儼未移，至今存石室。", "遺文盡法界，廣大包萬億。", "變化浩難名，丹青畫京邑。", "粲然共一理，眩晃莫能識。", "末法漸衰微，徒使真人泣。"]'),
('75032a21-73ad-4e2c-a750-36333e1f4705','遊太山四首 靈巖寺','蘇轍','宋','宋诗','song-poetry','','[]','青山何重重，行盡土囊底。',144,'全唐诗/poet.song.48000.json','["青山何重重，行盡土囊底。", "巖高日氣薄，秀色如新洗。", "入門塵慮息，盥漱得清泚。", "高堂見真人，不覺首自稽。", "祖師古禪伯，荆棘昔親啟。", "人迹尚蕭條，豺狼夜相觝。", "白鶴導清泉，甘芳勝醇醴。", "聲鳴青龍口，光照白石陛。", "尚可滿畦塍，豈惟濯蔬米。", "居僧三百人，飲食安四體。", "一念但清凉，四方盡兄弟。", "何言庇華屋，食苦當如薺。"]'),
('ca61b1dc-defe-4f98-952e-a24bda021ab2','遊太山四首 嶽下','蘇轍','宋','宋诗','song-poetry','','[]','東來亦何求，聊欲觀海岱。',288,'全唐诗/poet.song.48000.json','["東來亦何求，聊欲觀海岱。", "海西尚千里，將行勇還退。", "岱陰即齊疆，南往曾歷塊。", "春深草木長，山暖冰雪潰。", "中巷無居人，南畝釋耕耒。", "車徒八方至，塵坌百里內。", "牛馬汗淋漓，綺紈聲綷縩。", "喧闐六師合，洶湧衆流匯。", "無復問誰何，但自舍耽愛。", "龍鸞畫車服，貝玉飾冠佩。", "驊騮蹴騰騫，幡旆飛晻曖。", "腥羶及魚鼈，瑣細或蒲菜。", "遊墯愧無齎，技巧窮殊態。", "縱觀𥈭未已，精意殫一酹。", "出門青山屯，繞廊遺迹昧。", "登封尚壇壝，古觀寫旗隊。", "戈矛認毫末，舒卷分向背。", "雍容太平業，磊落豐碑在。", "往事半蓬蒿，遺氓但悲慨。", "回瞻最高峰，遠謝徂徠對。", "欲將有限力，一放目所迨。", "天門四十里，預恐雙足廢。", "三宿遂徘徊，歸來欲誰懟。", "前年道轘轅，直上嵩嶺背。"]'),
('3667700f-9b14-4c97-8b1b-93a41a50c85d','送王璋長官赴真定孫和甫辟書','蘇轍','宋','宋诗','song-poetry','','[]','昔年旅南服，始識王荆州。',120,'全唐诗/poet.song.48000.json','["昔年旅南服，始識王荆州。", "威動千里肅，恩寬行客留。", "從容見少子，風采傾凡儔。", "溫然吐詞氣，已覺清且修。", "不見十五年，相逢話百憂。", "青衫走塵土，白髮各滿頭。", "新棄東海邑，願從北諸侯。", "北鄙事方夥，饑饉連戈矛。", "盟好未可輕，念當事懷柔。", "主將今老成，勉盡良計籌。"]'),
('1e0465e7-e06a-4440-beb1-89570e472a15','寄孫朴','蘇轍','宋','宋诗','song-poetry','','[]','憶昔補官太皞墟，泮宮蕭條人事疏。',160,'全唐诗/poet.song.48000.json','["憶昔補官太皞墟，泮宮蕭條人事疏。", "日高鼾睡聲噓噓，往還廢絕門無車。", "君爲戶曹畏簡書，放懷疏懶亦似余。", "相逢語笑夜躊躇，烹煮梨栗羞殽蔬。", "官居一去真蘧廬，東來失計悔厥初。", "夜聞桴鼓驚閻閭，事如牛毛費耘鉏。", "違失真性從吏胥，目視紾臂邀徐徐。", "羨君不出心自如，北潭秋水多芙蕖。", "青荷包飯蒲爲菹，翛然獨往深淵魚。", "人生如此樂有餘，胡爲自投檻中狙。"]'),
('78c6f091-44c5-400f-8248-2ceeaa323d2c','和韓宗弼暴雨','蘇轍','宋','宋诗','song-poetry','','[]','執熱卧北窗，淋漓汗流注。',144,'全唐诗/poet.song.48000.json','["執熱卧北窗，淋漓汗流注。", "蛟龍遁水府，誰起叩天戶。", "偶然終日風，振擾北山霧。", "崩騰轉相軋，變化不容睹。", "雷聲運車轂，雨點傾豆黍。", "逡巡溜河漢，指顧纔笑語。", "破屋少乾床，茅苫固難禦。", "出門泥沒足，此厄比鄰溥。", "苟令終歲熟，敢有今日怒。", "晚照上東軒，清風襲虛廡。", "微生免荷鉏，但喜脫煩暑。", "農父更事多，缺塘已增土。"]'),
('9535fa86-490e-4f1f-a577-d6e0d5deacf7','舜泉復發','蘇轍','宋','宋诗','song-poetry','','[]','奕奕清波舊繞城，旱來泉眼亦塵生。',64,'全唐诗/poet.song.48000.json','["奕奕清波舊繞城，旱來泉眼亦塵生。", "連宵暑雨源初接，發地春雷夜有聲。", "復理溝渠通屈曲，重開池沼放澄清。", "通衢細灑浮埃凈，車馬歸來似晚晴。"]'),
('31379967-a0e5-46eb-a550-f050fc5bf81a','次韵徐正權謝示閔子廟記及惠紙','蘇轍','宋','宋诗','song-poetry','','[]','西溪秋思日盈箋，幕府拘愁學久騫。',64,'全唐诗/poet.song.48000.json','["西溪秋思日盈箋，幕府拘愁學久騫。", "記廟終慚無好句，酹墳猶喜有前篇。", "屏除筆硯真良計，寫寄交遊畏妄傳。", "吳紙贈君君莫怪，耕耘廢罷有閑田。"]'),
('80919341-18f8-4cf2-9416-729683668e61','張文裕侍郎挽詞','蘇轍','宋','宋诗','song-poetry','','[]','持節西南二十年，華堂遺像已蒼然。',64,'全唐诗/poet.song.48000.json','["持節西南二十年，華堂遺像已蒼然。", "歸來侍從三朝舊，老去雍容平地仙。", "落筆縱橫題壁處，誦詩清壯舉杯前。", "東遊邂逅迎歸旐，淚落城南下馬阡。"]'),
('74e83af5-9b77-4774-833a-23fb17d9215f','東方書生行','蘇轍','宋','宋诗','song-poetry','','[]','東方書生多愚魯，閉門誦書口生土。',160,'全唐诗/poet.song.48000.json','["東方書生多愚魯，閉門誦書口生土。", "窗中白首抱遺編，自信此書傳父祖。", "辟雍新說從上公，冊除僕射酬元功。", "太常弟子不知數，日夜吟諷如寒蟲。", "四方窺覘不能得，一卷百金猶復惜。", "康成穎達棄塵灰，老聃瞿曇更出入。", "舊書句句傳先師，中途欲棄還自疑。", "東鄰小兒識機會，半年外舍無不知。", "乘輕策肥正年少，齒疏脣腐真堪笑。", "是非得失付它年，眼前且買先騰踔。"]'),
('059d9b53-8448-4b7c-ad32-23f951ba6822','送韓宗弼','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','大野將凍河水微，慨然臨流送將歸。',160,'全唐诗/poet.song.48000.json','["大野將凍河水微，慨然臨流送將歸。", "登舟上帆手一揮，脫棄朋友如敝衣。", "我來三見芳草腓，來時同寮今已非。", "念昔相從未嘗違，西湖幽遠人事稀。", "青蓮紫芡傾珠璣，白魚掉尾黄鼈肥。", "客醉將起命闔扉，方橋月出風露霏。", "星河下照摇清輝，喧呼笑語相嘲譏。", "歲月一逝空長欷，交遊去盡將誰依。", "君家漢代平與韋，藹然令德傳餘徽。", "鳴鳩著地鴻高飛，安得久此同縶鞿。"]'),
('991b90c1-2eb8-436b-b38e-c2fd4e137803','送劉長清敏','蘇轍','宋','宋诗','song-poetry','','[]','汝州太守卧病年，亹亹猶復能清言。',128,'全唐诗/poet.song.48000.json','["汝州太守卧病年，亹亹猶復能清言。", "平生雄辯嗟不見，風流尚有曹州存。", "歷下東遊少相識，歡喜聞君在西邑。", "舊知兄弟無凡儔，相逢一笑開顔色。", "三年政令如牛毛，思歸南畝皆蓬蒿。", "羨君飲酒動論斗，引觥向口收狂潮。", "醉後胸中百無有，偃然嘯傲傾朋曹。", "中朝卿士足官府，君歸何處狂歌謠。"]'),
('85c87707-b49c-4be1-b321-faebba4f0a80','題張安道樂全堂','蘇轍','宋','宋诗','song-poetry','','[]','天命無不全，人事每自傷。',120,'全唐诗/poet.song.48000.json','["天命無不全，人事每自傷。", "譬如摩尼珠，宛轉有餘光。", "藻飾不能加，塵垢豈有亡。", "世人未嘗識，姑射手自將。", "我公體自然，率性非勉强。", "馳驅四十年，不入憂患場。", "晚歲事蒙養，斂退就此堂。", "小儒豈知道，宿昔窺門牆。", "申屠師無人，無足亦自忘。", "如逢鄭執政，一笑先生傍。"]'),
('5d43cd5a-b7f2-4aa5-aab1-de8538b175f2','和鮮于子駿益昌官舍八咏 桐軒','蘇轍','宋','宋诗','song-poetry','','[]','桐身青琅玕，桐葉蒲葵扇。',72,'全唐诗/poet.song.48000.json','["桐身青琅玕，桐葉蒲葵扇。", "落落出軒墀，亭亭奉閒燕。", "夜聲疏雨滴，午影微風轉。", "秋飆一凌亂，淅瀝驚葱蒨。", "朝日失繁陰，青苔覆遺片。", "空使坐中人，慨然嗟物變。"]'),
('03587afb-8722-48d6-9061-be1cd380f7e5','和鮮于子駿益昌官舍八咏 竹軒','蘇轍','宋','宋诗','song-poetry','','[]','幽軒離紛華，惟有一叢竹。',72,'全唐诗/poet.song.48000.json','["幽軒離紛華，惟有一叢竹。", "纖梢起餘寒，紫筍散輕馥。", "擢幹春雨餘，挺節秋霜足。", "不知歲時改，守此娟娟綠。", "上有吟風蟬，空腹未嘗食。", "翦伐非所辭，不受塵土辱。"]'),
('0c8621b2-1cfc-4c34-9f61-94c1fa37de91','和鮮于子駿益昌官舍八咏 柏軒','蘇轍','宋','宋诗','song-poetry','','[]','築室城市間，移柏南澗底。',72,'全唐诗/poet.song.48000.json','["築室城市間，移柏南澗底。", "山林夙所尚，封植聊自寄。", "崎嶇脫巖石，擁塞出棼翳。", "上承清露滋，下受寒泉惠。", "秋來采霜葉，咀嚼有餘味。", "苦澀未須嫌，愈久甘如薺。"]'),
('3ce4d8d1-3309-43d0-8e4a-d08f45587593','和鮮于子駿益昌官舍八咏 巽堂','蘇轍','宋','宋诗','song-poetry','','[]','山前三秦道，車馬不遑息。',96,'全唐诗/poet.song.48000.json','["山前三秦道，車馬不遑息。", "日出紅塵生，不見青山色。", "峰巒未嘗改，往意自奔迫。", "誰言幽堂居，近在使者宅。", "俯聽辨江聲，却立睨石壁。", "藤蘿自太古，松竹列新植。", "暑簟卧清風，寒樽對佳客。", "試問東行人，誰能同此適。"]'),
('745619ff-851a-4501-af90-b51329fe34b8','和鮮于子駿益昌官舍八咏 山齋','蘇轍','宋','宋诗','song-poetry','','[]','平地厭喧囂，虛齋上山足。',72,'全唐诗/poet.song.48000.json','["平地厭喧囂，虛齋上山足。", "蕭條遠城市，坡陀富林麓。", "簡書日填委，杖屨每幽獨。", "豈無山中士，高卧白茅屋。", "逢人默無語，長嘯響巖谷。", "此室庶可招，夜月相從宿。"]'),
('b34ac800-c147-4d2f-b82c-fe581d4c66a6','和鮮于子駿益昌官舍八咏 閑燕亭','蘇轍','宋','宋诗','song-poetry','','[]','登山稍已高，曠望良亦遠。',72,'全唐诗/poet.song.48000.json','["登山稍已高，曠望良亦遠。", "危亭在山腹，物景行自變。", "諸峰宿露收，草木朝陽絢。", "盎盎雲出山，溜溜泉垂坂。", "徐行得佳處，永日遂忘返。", "此樂只自知，傍人任嫌懶。"]'),
('118c54c4-81dd-4d9e-85be-f6f952d06324','和鮮于子駿益昌官舍八咏 會景亭','蘇轍','宋','宋诗','song-poetry','','[]','亭高衆山下，勝勢不自收。',72,'全唐诗/poet.song.48000.json','["亭高衆山下，勝勢不自收。", "岡巒向眼盡，風籟與耳謀。", "鳶飛半嶺息，雲起當空遊。", "視身如乘風，超然忘百憂。", "暮歸室中居，唯見窗戶幽。", "視聽隨物變，恍誰識其由。"]'),
('8d507a96-9710-49fb-b431-2ace4cdee68b','和鮮于子駿益昌官舍八咏 寶峰亭','蘇轍','宋','宋诗','song-poetry','','[]','昔過益昌城，莫登君子堂。',144,'全唐诗/poet.song.48000.json','["昔過益昌城，莫登君子堂。", "駕言念長道，未暇升崇岡。", "今聞寶峰上，縹緲陵朝陽。", "三休引蘿蔓，一覽窮蒼茫。", "微雲靄雙劍，落日明故鄉。", "奔馳迹未安，山藪意自長。", "漂摇萬里外，手把新詩章。", "宦遊不忘歸，何異鳥欲翔。", "塵土汙顔面，年華侵鬢霜。", "何時首歸路，所至聊徬徨。", "樽俎逢故人，亭榭凝清光。", "爲我具斗酒，宿恨猶可償。"]'),
('d2887d3c-98ba-4c6b-ac6e-c8a94b0c9f81','次韵分司南京李誠之待制求酒二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','世上升沉都夢裏，春來强健鬥樽前。',32,'全唐诗/poet.song.48000.json','["世上升沉都夢裏，春來强健鬥樽前。", "公田種秫全拋却，坐客無氈誰與錢。"]'),
('89296054-80d5-48b3-a401-509b6c5ce667','次韵分司南京李誠之待制求酒二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','春深風雨半相和，節物令人意緒多。',32,'全唐诗/poet.song.48000.json','["春深風雨半相和，節物令人意緒多。", "中酒何須問賢聖，和詩今尚許羊何。"]'),
('02f5ef52-9ede-41bc-bc46-a6c05f491fa2','送施歷城辯歸常州','蘇轍','宋','宋诗','song-poetry','','[]','高人不受塵土侵，三年浙江藏何深。',160,'全唐诗/poet.song.48000.json','["高人不受塵土侵，三年浙江藏何深。", "久閑物理有相復，歷城官事森成林。", "乘時斂散逐十二，鞭撻逋負徒哀矜。", "一杯相屬未嘗得，百畝歸去將安能。", "潛逃雖出知者後，黽勉尚見仁人心。", "歸期忽告三月尾，强留不顧千黄金。", "河豚雖過鱸鱖在，粳稻正插風雨淫。", "酒肴勞苦罄鄰里，期會迫隘思僚朋。", "山川吳越我所愛，扁舟佗日要追尋。", "滯留未用便相詫，半年歲月行駸駸。"]'),
('8449959d-b396-4b58-ad56-eb5c73951a68','施君既去復以事還戲贈','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','令尹西行去又迴，西湖重把舊樽罍。',32,'全唐诗/poet.song.48000.json','["令尹西行去又迴，西湖重把舊樽罍。", "吏民再見雞棲乘，猶道吾公挽不來。"]'),
('d4311051-c9a4-4a62-830c-44015b9bb05d','和文與可洋州園亭三十咏 湖橋','蘇轍','宋','宋诗','song-poetry','','[]','湖南堂宇深，湖北林亭遠。',24,'全唐诗/poet.song.48000.json','["湖南堂宇深，湖北林亭遠。", "不作過湖橋，兩處那相見。"]'),
('21c97486-b9c2-42e0-9e76-dc44a6c28c9b','和文與可洋州園亭三十咏 橫湖','蘇轍','宋','宋诗','song-poetry','','[]','湖裏種荷花，湖邊種楊柳。',24,'全唐诗/poet.song.48000.json','["湖裏種荷花，湖邊種楊柳。", "何處渡橋人，問是人間否。"]'),
('754bd0d8-3da7-4d04-80fc-d8ed1d53c901','和文與可洋州園亭三十咏 書軒','蘇轍','宋','宋诗','song-poetry','','[]','綠竹覆清渠，塵心日日疏。',24,'全唐诗/poet.song.48000.json','["綠竹覆清渠，塵心日日疏。", "使君遺癖在，苦要讀文書。"]'),
('4a07d0a3-a44b-4536-baba-388c61835db9','和文與可洋州園亭三十咏 冰池','蘇轍','宋','宋诗','song-poetry','','[]','水深冰亦厚，滉蕩鋪寒玉。',24,'全唐诗/poet.song.48000.json','["水深冰亦厚，滉蕩鋪寒玉。", "好在水中魚，何愁池上鶩。"]'),
